"use client";

import { useAdminCatalogRequests } from "@/hooks/useAdminCatalogRequests";
import { type CatalogRequestItem } from "@/lib/api/catalogRequests";
import { ClipboardList, CheckCircle, XCircle, Clock, AlertCircle, ExternalLink, Loader2 } from "lucide-react";
import { CatalogPageTemplate } from "@/components/catalog/CatalogPageTemplate";
import { useState, useEffect } from "react";
import { CatalogModal } from "@/components/catalog/CatalogModal";
import {
    CatalogActionsRow,
    CatalogActionIconButton,
    CatalogEntityCell,
    CatalogSelectFilter,
    CatalogRejectSuggestionForm,
    CatalogSearchInput,
} from "@/components/catalog/CatalogUiPrimitives";
import { useCatalogQueryStateSync } from "@/hooks/useCatalogQueryStateSync";
import { normalizeSearchParamValue, parsePositiveIntParam } from "@/lib/urlSearchParams";
import { useSearchParams } from "next/navigation";
import { getBrands } from "@/lib/api/brands";
import { getModels } from "@/lib/api/models";
import { parseAdminResponse } from "@/lib/api/parseAdminResponse";

const REQUEST_STATUS_VALUES = new Set(["all", "pending", "approved", "rejected", "duplicate", "resolved"]);

const normalizeRequestStatusParam = (value: string | null) =>
    value && REQUEST_STATUS_VALUES.has(value) ? value : "all";

export default function CatalogRequestsTab() {
    const searchParams = useSearchParams();
    const initialSearch = normalizeSearchParamValue(searchParams.get("q") ?? searchParams.get("search"));
    const initialStatus = normalizeRequestStatusParam(searchParams.get("status"));
    const initialPage = parsePositiveIntParam(searchParams.get("page"), 1);

    const [searchInput, setSearchInput] = useState(initialSearch);

    const {
        requests,
        loading,
        error,
        handleApprove,
        handleReject,
        handleBulkReject,
        handleBulkMarkDuplicate,
        pagination,
    } = useAdminCatalogRequests({
        initialFilters: {
            search: initialSearch,
            status: initialStatus,
        },
        initialPagination: {
            page: initialPage,
            limit: 20,
        },
    });

    const { replaceQueryState } = useCatalogQueryStateSync({
        searchInput,
        initialSearch,
        loading,
        initialPage,
        totalPages: pagination.totalPages,
    });

    const [rejectingRequest, setRejectingRequest] = useState<CatalogRequestItem | null>(null);
    const [rejectionReason, setRejectionReason] = useState("");
    const [isRejecting, setIsRejecting] = useState(false);

    // Bulk selection state
    const [selectedIds, setSelectedIds] = useState<string[]>([]);
    
    // Bulk Reject state
    const [bulkRejectOpen, setBulkRejectOpen] = useState(false);
    const [bulkRejectionReason, setBulkRejectionReason] = useState("");
    const [isBulkRejecting, setIsBulkRejecting] = useState(false);
    
    // Bulk Duplicate state
    const [bulkDuplicateOpen, setBulkDuplicateOpen] = useState(false);
    const [searchQuery, setSearchQuery] = useState("");
    const [searchResults, setSearchResults] = useState<Array<{ id: string; name: string }>>([]);
    const [searching, setSearching] = useState(false);
    const [selectedTargetId, setSelectedTargetId] = useState<string | null>(null);
    const [isBulkDuplicating, setIsBulkDuplicating] = useState(false);

    // Determine request type of selection to guide the duplicate catalog search
    const firstSelectedId = selectedIds[0];
    const firstSelectedRequest = requests.find((r) => r.id === firstSelectedId);
    const requestType = firstSelectedRequest?.requestType || "brand";

    useEffect(() => {
        if (searchQuery.length < 2) {
            setSearchResults([]);
            return;
        }
        const performSearch = async () => {
            setSearching(true);
            try {
                if (requestType === "brand") {
                    const res = await getBrands({ search: searchQuery });
                    const parsed = parseAdminResponse<any>(res);
                    setSearchResults(parsed.items.map((item) => ({ id: item.id, name: item.name })));
                } else {
                    const res = await getModels({ search: searchQuery });
                    const parsed = parseAdminResponse<any>(res);
                    setSearchResults(parsed.items.map((item) => ({ id: item.id, name: item.name })));
                }
            } catch (e) {
                console.error(e);
            } finally {
                setSearching(false);
            }
        };
        const timer = setTimeout(performSearch, 300);
        return () => clearTimeout(timer);
    }, [searchQuery, requestType]);

    const allSelected = requests.length > 0 && requests.every((item) => selectedIds.includes(item.id));
    
    const onToggleSelectAll = (checked: boolean) => {
        if (checked) {
            setSelectedIds(requests.map((item) => item.id));
        } else {
            setSelectedIds([]);
        }
    };

    const onToggleSelect = (id: string, checked: boolean) => {
        if (checked) {
            setSelectedIds((prev) => [...prev, id]);
        } else {
            setSelectedIds((prev) => prev.filter((x) => x !== id));
        }
    };

    const openBulkReject = () => {
        setBulkRejectionReason("");
        setBulkRejectOpen(true);
    };

    const openBulkDuplicate = () => {
        setSearchQuery("");
        setSearchResults([]);
        setSelectedTargetId(null);
        setBulkDuplicateOpen(true);
    };

    const confirmReject = async () => {
        if (!rejectingRequest || !rejectionReason.trim()) return;
        setIsRejecting(true);
        await handleReject(rejectingRequest.id, rejectionReason.trim());
        setIsRejecting(false);
        setRejectingRequest(null);
        setRejectionReason("");
    };

    const confirmBulkReject = async () => {
        if (selectedIds.length === 0 || !bulkRejectionReason.trim()) return;
        setIsBulkRejecting(true);
        try {
            await handleBulkReject(selectedIds, bulkRejectionReason.trim());
            setSelectedIds([]);
            setBulkRejectOpen(false);
        } catch (e) {
            console.error(e);
        } finally {
            setIsBulkRejecting(false);
        }
    };

    const confirmBulkDuplicate = async () => {
        if (selectedIds.length === 0 || !selectedTargetId) return;
        setIsBulkDuplicating(true);
        try {
            await handleBulkMarkDuplicate(selectedIds, selectedTargetId);
            setSelectedIds([]);
            setBulkDuplicateOpen(false);
        } catch (e) {
            console.error(e);
        } finally {
            setIsBulkDuplicating(false);
        }
    };

    const bulkActions = (
        <div className="flex items-center gap-2">
            <button
                type="button"
                onClick={openBulkReject}
                className="rounded-lg bg-amber-600 px-3 py-2 text-xs font-semibold text-white hover:bg-amber-700 transition-all shadow-sm"
            >
                Quick Reject
            </button>
            <button
                type="button"
                onClick={openBulkDuplicate}
                className="rounded-lg bg-primary px-3 py-2 text-xs font-semibold text-white hover:bg-primary/95 transition-all shadow-sm"
            >
                Quick Duplicate
            </button>
        </div>
    );

    return (
        <>
            <CatalogPageTemplate<CatalogRequestItem, Record<string, never>>
                isNested={true}
                title="Catalog Requests"
                description="Manage user-submitted requests for new brands, models, or categories. Reviewing and approving these maintains the SSOT integrity."
                createLabel="" // No manual creation of requests in admin
                csvFileName="catalog-requests.csv"
                items={requests}
                loading={loading}
                error={error}
                pagination={pagination}
                selectedCount={selectedIds.length}
                bulkActions={selectedIds.length > 0 ? bulkActions : undefined}
                setPage={(page) => replaceQueryState({ page: page > 1 ? page : null })}
                handleCreate={async () => false}
                handleUpdate={async () => false}
                defaultFormData={{} as Record<string, never>}
                formRenderer={() => null}
                generateColumns={() => [
                    {
                        header: (
                            <input
                                type="checkbox"
                                checked={allSelected}
                                onChange={(e) => onToggleSelectAll(e.target.checked)}
                                className="w-4 h-4 rounded border-slate-300 text-primary focus:ring-primary/20 cursor-pointer"
                            />
                        ),
                        id: "select",
                        className: "w-12",
                        cell: (req) => (
                            <input
                                type="checkbox"
                                checked={selectedIds.includes(req.id)}
                                onChange={(e) => onToggleSelect(req.id, e.target.checked)}
                                className="w-4 h-4 rounded border-slate-300 text-primary focus:ring-primary/20 cursor-pointer"
                            />
                        ),
                    },
                    {
                         header: "Request",
                         cell: (req) => {
                             const userName = typeof req.requestedBy === 'string' ? req.requestedBy : `${req.requestedBy.firstName} ${req.requestedBy.lastName}`;
                             return (
                                 <div className="flex flex-col gap-1">
                                     <CatalogEntityCell
                                         icon={<ClipboardList size={20} />}
                                         iconClassName="bg-amber-50 text-amber-600"
                                         title={req.requestedName}
                                         subtitle={`${req.requestType} • ${userName}`}
                                     />
                                     {req.listingId && (
                                         <a
                                             href={`/listing/${req.listingId}`}
                                             target="_blank"
                                             rel="noopener noreferrer"
                                             className="inline-flex items-center gap-1 ml-10 text-[11px] font-semibold text-blue-600 hover:text-blue-800 hover:underline"
                                         >
                                             <ExternalLink size={10} />
                                             View Listing
                                         </a>
                                     )}
                                 </div>
                             );
                         },
                     },
                    {
                        header: "Status",
                        cell: (req) => (
                            <span className={`inline-flex items-center gap-1.5 px-2 py-1 rounded text-[10px] font-bold uppercase tracking-wider ${
                                req.status === "approved" || req.status === "resolved" ? "bg-emerald-100 text-emerald-700" :
                                req.status === "rejected" ? "bg-red-100 text-red-700" :
                                req.status === "duplicate" ? "bg-blue-100 text-blue-700" :
                                "bg-amber-100 text-amber-700"
                            }`}>
                                {req.status === "pending" ? <Clock size={10} /> : (req.status === "approved" || req.status === "resolved") ? <CheckCircle size={10} /> : <AlertCircle size={10} />}
                                {req.status}
                            </span>
                        ),
                    },
                    {
                        header: "Demand",
                        cell: (req) => {
                            const count = req.requestCount ?? 1;
                            const isHot = count >= 5;
                            return (
                                <span className={`inline-flex items-center gap-1 px-2 py-1 rounded-full text-[10px] font-bold ${
                                    isHot
                                        ? "bg-rose-100 text-rose-700"
                                        : count >= 2
                                        ? "bg-amber-100 text-amber-700"
                                        : "bg-slate-100 text-slate-500"
                                }`}>
                                    ×{count}
                                </span>
                            );
                        },
                    },
                    {
                        header: "Actions",
                        className: "text-right",
                        cell: (req) => (
                            <CatalogActionsRow>
                                {req.status === "pending" && (
                                    <>
                                        <CatalogActionIconButton
                                            onClick={() => void handleApprove(req.id)}
                                            className="p-1.5 text-emerald-600 hover:bg-emerald-50 rounded-lg transition-all"
                                            title="Approve"
                                            icon={<CheckCircle size={18} />}
                                        />
                                        <CatalogActionIconButton
                                            onClick={() => {
                                                setRejectionReason("");
                                                setRejectingRequest(req);
                                            }}
                                            className="p-1.5 text-orange-600 hover:bg-orange-50 rounded-lg transition-all"
                                            title="Reject"
                                            icon={<XCircle size={18} />}
                                        />
                                    </>
                                )}
                            </CatalogActionsRow>
                        ),
                    },
                ]}
                filterLayoutClassName="md:grid-cols-2"
                filtersRenderer={
                    <>
                        <CatalogSearchInput
                            value={searchInput}
                            placeholder="Search requests..."
                            onChange={setSearchInput}
                        />
                        <CatalogSelectFilter
                            value={initialStatus}
                            onChange={(status) =>
                                replaceQueryState({
                                    status: status !== "all" ? status : null,
                                    page: null,
                                })
                            }
                            options={[
                                { value: "all", label: "All Status" },
                                { value: "pending", label: "Pending" },
                                { value: "approved", label: "Approved" },
                                { value: "resolved", label: "Resolved" },
                                { value: "rejected", label: "Rejected" },
                                { value: "duplicate", label: "Duplicate" },
                            ]}
                        />
                    </>
                }
            />

            <CatalogModal
                isOpen={!!rejectingRequest}
                onClose={() => !isRejecting && setRejectingRequest(null)}
                title="Reject Catalog Request"
            >
                <CatalogRejectSuggestionForm
                    itemName={rejectingRequest?.requestedName}
                    rejectionReason={rejectionReason}
                    onRejectionReasonChange={setRejectionReason}
                    onCancel={() => setRejectingRequest(null)}
                    onConfirm={() => void confirmReject()}
                    isSubmitting={isRejecting}
                    placeholder="e.g. Duplicate request, Already in catalog, Spam..."
                />
            </CatalogModal>

            {/* Bulk Reject Modal */}
            <CatalogModal
                isOpen={bulkRejectOpen}
                onClose={() => !isBulkRejecting && setBulkRejectOpen(false)}
                title="Bulk Reject Requests"
            >
                <div className="p-6 space-y-4">
                    <div className="flex items-start gap-3 rounded-xl border border-orange-200 bg-orange-50 p-4">
                        <AlertCircle className="mt-0.5 h-5 w-5 shrink-0 text-orange-600" />
                        <div>
                            <p className="text-sm font-semibold text-orange-700">Bulk Rejection Action</p>
                            <p className="mt-1 text-sm text-orange-600">
                                You are about to reject <strong>{selectedIds.length}</strong> selected requests. Please provide a reason to notify the submitters.
                            </p>
                        </div>
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-wider text-slate-500">Rejection Reason</label>
                        <textarea
                            value={bulkRejectionReason}
                            onChange={(e) => setBulkRejectionReason(e.target.value)}
                            placeholder="Explain why these requests are being rejected"
                            className="w-full min-h-[100px] rounded-lg border border-slate-200 bg-slate-50 p-3 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all"
                        />
                    </div>
                    <div className="flex justify-end gap-3 pt-2">
                        <button
                            type="button"
                            disabled={isBulkRejecting}
                            onClick={() => setBulkRejectOpen(false)}
                            className="rounded-lg border border-slate-200 bg-white px-4 py-2 text-sm font-medium text-slate-700 hover:bg-slate-50 transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            type="button"
                            disabled={isBulkRejecting || !bulkRejectionReason.trim()}
                            onClick={confirmBulkReject}
                            className="flex items-center gap-2 rounded-lg bg-red-600 px-4 py-2 text-sm font-semibold text-white hover:bg-red-700 disabled:opacity-60 transition-colors"
                        >
                            {isBulkRejecting ? <><Loader2 size={14} className="animate-spin" /> Submitting…</> : "Reject Selected"}
                        </button>
                    </div>
                </div>
            </CatalogModal>

            {/* Bulk Duplicate Modal */}
            <CatalogModal
                isOpen={bulkDuplicateOpen}
                onClose={() => !isBulkDuplicating && setBulkDuplicateOpen(false)}
                title="Bulk Mark As Duplicate"
            >
                <div className="p-6 space-y-4">
                    <div className="flex items-start gap-3 rounded-xl border border-blue-200 bg-blue-50 p-4">
                        <AlertCircle className="mt-0.5 h-5 w-5 shrink-0 text-blue-600" />
                        <div>
                            <p className="text-sm font-semibold text-blue-700">Bulk Mark As Duplicate</p>
                            <p className="mt-1 text-sm text-blue-600">
                                Select the canonical {requestType === 'brand' ? 'brand' : 'model'} that these <strong>{selectedIds.length}</strong> requests are duplicates of.
                            </p>
                        </div>
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-wider text-slate-500">
                            Search Canonical {requestType === 'brand' ? 'Brand' : 'Model'}
                        </label>
                        <input
                            type="text"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            placeholder={`Type at least 2 characters to search ${requestType === 'brand' ? 'brands' : 'models'}`}
                            className="w-full rounded-lg border border-slate-200 bg-slate-50 p-3 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all"
                        />
                    </div>
                    {searching && (
                        <div className="flex justify-center py-2">
                            <Loader2 className="h-5 w-5 animate-spin text-primary" />
                        </div>
                    )}
                    <div className="max-h-[200px] overflow-y-auto space-y-2 custom-scrollbar">
                        {searchResults.map((item) => (
                            <button
                                key={item.id}
                                type="button"
                                onClick={() => setSelectedTargetId(item.id)}
                                className={`w-full text-left px-4 py-2 text-sm rounded-lg border transition-all ${
                                    selectedTargetId === item.id 
                                        ? "bg-primary/10 border-primary text-primary font-bold animate-pulse" 
                                        : "bg-slate-50 border-slate-200 text-slate-700 hover:bg-slate-100"
                                }`}
                            >
                                {item.name}
                            </button>
                        ))}
                        {!searching && searchQuery.length >= 2 && searchResults.length === 0 && (
                            <p className="text-center text-xs text-slate-400">No results found</p>
                        )}
                    </div>
                    <div className="flex justify-end gap-3 pt-2">
                        <button
                            type="button"
                            disabled={isBulkDuplicating}
                            onClick={() => setBulkDuplicateOpen(false)}
                            className="rounded-lg border border-slate-200 bg-white px-4 py-2 text-sm font-medium text-slate-700 hover:bg-slate-50 transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            type="button"
                            disabled={isBulkDuplicating || !selectedTargetId}
                            onClick={confirmBulkDuplicate}
                            className="flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-semibold text-white hover:bg-primary/90 disabled:opacity-60 transition-colors"
                        >
                            {isBulkDuplicating ? <><Loader2 size={14} className="animate-spin" /> Submitting…</> : "Mark Selected"}
                        </button>
                    </div>
                </div>
            </CatalogModal>
        </>
    );
}

"use client";

import { useState } from "react";
import { useSearchParams } from "next/navigation";
import { Edit, Trash2, Monitor, AlignJustify, AlertTriangle, Loader2 } from "lucide-react";
import { LISTING_TYPE, type ListingTypeValue } from "@esparex/shared";
import { CatalogPageTemplate } from "@/components/catalog/CatalogPageTemplate";
import {
    CatalogActionsRow,
    CatalogActiveStatusFilter,
    CatalogActionIconButton,
    CatalogActiveToggleButton,
    CatalogCheckboxCard,
    CatalogCheckboxGroupField,
    CatalogCategoryIcon,
    CatalogEntityCell,
    CatalogListingTypeBadges,
    CatalogSearchInput,
    CatalogTextInputField,
} from "@/components/catalog/CatalogUiPrimitives";
import { CatalogModal } from "@/components/catalog/CatalogModal";
import { useAdminCategories } from "@/hooks/useAdminCategories";
import { useCatalogQueryStateSync } from "@/hooks/useCatalogQueryStateSync";
import { normalizeSearchParamValue, parsePositiveIntParam } from "@/lib/urlSearchParams";
import { adminCategorySchema } from "@/schemas/admin.schemas";
import type { Category } from "@esparex/shared";

type CategoryFormData = {
    name: string;
    icon?: string;
    isActive: boolean;
    hasScreenSizes: boolean;
    listingType: ListingTypeValue[];
    _editingSlug?: string;
};

const CATEGORY_STATUS_VALUES = new Set(["all", "active", "inactive", "live"]);

const normalizeCategoryStatusParam = (value: string | null) =>
    value && CATEGORY_STATUS_VALUES.has(value) ? value : "all";

const isListingTypeValue = (value: string): value is ListingTypeValue => 
    ([LISTING_TYPE.AD, LISTING_TYPE.SERVICE, LISTING_TYPE.SPARE_PART] as string[]).includes(value);

const listingTypeOptions: Array<{ value: ListingTypeValue; label: string }> = [
    { value: LISTING_TYPE.AD, label: "Device Listings" },
    { value: LISTING_TYPE.SERVICE, label: "Service Listings" },
    { value: LISTING_TYPE.SPARE_PART, label: "Spare Part Listings" },
];

const deriveSlug = (name: string) =>
    name.toLowerCase().replace(/\s+/g, "-").replace(/[^a-z0-9-]/g, "");

export default function CategoriesTab() {
    const searchParams = useSearchParams();
    const initialSearch = normalizeSearchParamValue(searchParams.get("q") ?? searchParams.get("search"));
    const initialStatus = normalizeCategoryStatusParam(searchParams.get("status"));
    const initialPage = parsePositiveIntParam(searchParams.get("page"), 1);

    const [searchInput, setSearchInput] = useState(initialSearch);
    const [deletingCategory, setDeletingCategory] = useState<Category | null>(null);
    const [isDeleting, setIsDeleting] = useState(false);

    const {
        categories,
        loading,
        error,
        handleToggleStatus,
        handleDelete,
        handleCreate,
        handleUpdate,
        pagination,
        isTogglingId,
    } = useAdminCategories({
        initialFilters: {
            search: initialSearch,
            status: initialStatus,
        },
        initialPagination: {
            page: initialPage,
            limit: 20,
        },
    });

    const { replaceQueryState } = useCatalogQueryStateSync({
        searchInput,
        initialSearch,
        loading,
        initialPage,
        totalPages: pagination.totalPages,
    });

    const confirmDelete = async () => {
        if (!deletingCategory) return;
        setIsDeleting(true);
        await handleDelete(deletingCategory.id);
        setIsDeleting(false);
        setDeletingCategory(null);
    };

    return (
        <>
            <CatalogPageTemplate<Category, CategoryFormData>
                isNested={true}
                title="Categories"
                description="Root device categories — the SSOT for Post Ad step 1, search filters, alert matching, and fraud detection. Every brand, model, and spare part is anchored to a category here."
                createLabel="Add Category"
                csvFileName="categories.csv"
                items={categories}
                loading={loading}
                error={error}
                pagination={pagination}
                setPage={(page) => replaceQueryState({ page: page > 1 ? page : null })}
                handleCreate={(data) => {
                    const payload = { ...data };
                    delete payload._editingSlug;
                    return handleCreate(payload);
                }}
                handleUpdate={(id, data) => {
                    const payload = { ...data };
                    delete payload._editingSlug;
                    return handleUpdate(id, payload);
                }}
                defaultFormData={{
                    name: "",
                    icon: "",
                    isActive: true,
                    hasScreenSizes: false,
                    listingType: [LISTING_TYPE.AD],
                    _editingSlug: "",
                }}
                customSubmitValidation={(formData) => {
                    const slug =
                        formData._editingSlug ||
                        deriveSlug(formData.name);
                    const validation = adminCategorySchema.safeParse({
                        name: formData.name,
                        slug,
                        listingType: formData.listingType,
                        hasScreenSizes: formData.hasScreenSizes,
                    });
                    if (!validation.success) return validation.error.issues[0]?.message || "Invalid form data";
                    if (formData.listingType.length === 0) return "At least one listing type is required";
                    return null;
                }}
                onModalOpen={(item, setFormData) => {
                    if (item) {
                        setFormData({
                            name: item.name,
                            icon: item.icon || "",
                            isActive: item.isActive,
                            hasScreenSizes: item.hasScreenSizes || false,
                            listingType: Array.isArray(item.listingType)
                                ? item.listingType.filter(isListingTypeValue)
                                : [],
                            _editingSlug: item.slug,
                        });
                    }
                }}
                generateColumns={(openEditModal) => [
                    {
                        header: "Category",
                        cell: (category) => (
                            <CatalogEntityCell
                                icon={<CatalogCategoryIcon icon={category.icon} listingType={category.listingType} size={20} />}
                                iconClassName="bg-slate-100 text-slate-600"
                                title={category.name}
                                subtitle={category.slug}
                            />
                        ),
                    },

                    {
                        header: "Listing Types",
                        cell: (category) => <CatalogListingTypeBadges types={category.listingType} />,
                    },
                    {
                        header: "Screen Sizes",
                        cell: (category) =>
                            category.hasScreenSizes ? (
                                <span className="inline-flex items-center gap-1 rounded-full bg-blue-50 px-2.5 py-1 text-[11px] font-semibold text-blue-700">
                                    <Monitor size={11} aria-hidden="true" focusable="false" /> Yes
                                </span>
                            ) : (
                                <span className="text-[11px] text-slate-400">—</span>
                            ),
                    },
                    {
                        header: "Status",
                        cell: (category) => (
                            <CatalogActiveToggleButton
                                isActive={category.isActive}
                                onClick={() => void handleToggleStatus(category.id)}
                                disabled={isTogglingId === category.id}
                                loading={isTogglingId === category.id}
                            />
                        ),
                    },
                    {
                        header: "Actions",
                        className: "text-right",
                        cell: (category) => (
                            <CatalogActionsRow>
                                <CatalogActionIconButton
                                    onClick={() => openEditModal(category)}
                                    className="p-1.5 text-slate-400 hover:text-primary hover:bg-primary/5 rounded-lg transition-all"
                                    title="Edit"
                                    icon={<Edit size={18} aria-hidden="true" focusable="false" />}
                                />
                                <CatalogActionIconButton
                                    onClick={() => setDeletingCategory(category)}
                                    className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                                    title="Delete"
                                    icon={<Trash2 size={18} aria-hidden="true" focusable="false" />}
                                />
                            </CatalogActionsRow>
                        ),
                    },
                ]}
                filterLayoutClassName="md:grid-cols-3"
                filtersRenderer={
                    <>
                        <CatalogSearchInput
                            value={searchInput}
                            placeholder="Search categories..."
                            onChange={setSearchInput}
                        />
                        <CatalogActiveStatusFilter
                            value={initialStatus}
                            onChange={(status) =>
                                replaceQueryState({
                                    status: status !== "all" ? status : null,
                                    page: null,
                                })
                            }
                        />
                    </>
                }
                formRenderer={(formData, setFormData, isEditing) => (
                    <>
                        <CatalogTextInputField
                            label="Category Name"
                            placeholder="e.g. Smartphones"
                            value={formData.name}
                            maxLength={50}
                            onChange={(name) => setFormData((prev) => ({ ...prev, name }))}
                        />

                        <CatalogTextInputField
                            label="Icon Name"
                            placeholder="e.g. smartphone, drone, briefcase..."
                            value={formData.icon || ""}
                            maxLength={30}
                            required={false}
                            onChange={(icon) => setFormData((prev) => ({ ...prev, icon }))}
                        />

                        <div className="rounded-lg border border-slate-200 bg-slate-50 px-3 py-2">
                            <p className="text-[11px] font-medium uppercase tracking-wider text-slate-400">URL Slug</p>
                            <p className="mt-0.5 font-mono text-sm text-slate-700 break-all">
                                {isEditing && formData._editingSlug
                                    ? formData._editingSlug
                                    : deriveSlug(formData.name) || "auto-generated from name"}
                            </p>
                            {isEditing && (
                                <p className="mt-1 text-[11px] text-amber-600">
                                    ⚠ Slug is fixed on create. Changing name will not change the slug.
                                </p>
                            )}
                        </div>

                        <CatalogCheckboxGroupField
                            label="Listing Types"
                            options={listingTypeOptions}
                            selectedValues={formData.listingType}
                            onChange={(listingType) =>
                                setFormData((prev) => ({
                                    ...prev,
                                    listingType: listingType.filter(isListingTypeValue),
                                }))
                            }
                        />

                        <div className="grid grid-cols-2 gap-4">
                            <CatalogCheckboxCard
                                checked={formData.isActive}
                                onChange={(isActive) => setFormData((prev) => ({ ...prev, isActive }))}
                                label="Active"
                            />

                            <CatalogCheckboxCard
                                checked={formData.hasScreenSizes}
                                onChange={(hasScreenSizes) => setFormData((prev) => ({ ...prev, hasScreenSizes }))}
                                label="Screen Sizes"
                            />
                        </div>
                    </>
                )}
            />

            <CatalogModal
                isOpen={!!deletingCategory}
                onClose={() => !isDeleting && setDeletingCategory(null)}
                title="Delete Category"
            >
                <div className="p-6 space-y-4">
                    <div className="flex items-start gap-3 rounded-xl border border-red-200 bg-red-50 p-4">
                        <AlertTriangle className="mt-0.5 h-5 w-5 shrink-0 text-red-600" aria-hidden="true" focusable="false" />
                        <div>
                            <p className="text-sm font-semibold text-red-700">
                                Cascade delete — this cannot be undone
                            </p>
                            <p className="mt-1 text-sm text-red-600">
                                Deleting <strong>&ldquo;{deletingCategory?.name}&rdquo;</strong> will also
                                soft-delete all Brands, Models, Spare Parts, and Screen Sizes linked exclusively
                                to this category.
                            </p>
                        </div>
                    </div>
                    <p className="text-sm text-slate-600">
                        To hide this category temporarily, <strong>deactivate it</strong> instead of deleting.
                    </p>
                    <div className="flex justify-end gap-3 pt-2">
                        <button
                            type="button"
                            disabled={isDeleting}
                            onClick={() => setDeletingCategory(null)}
                            className="rounded-lg border border-slate-200 bg-white px-4 py-2 text-sm font-medium text-slate-700 hover:bg-slate-50 disabled:opacity-50 transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            type="button"
                            disabled={isDeleting}
                            onClick={() => void confirmDelete()}
                            className="flex items-center gap-2 rounded-lg bg-red-600 px-4 py-2 text-sm font-semibold text-white hover:bg-red-700 disabled:opacity-60 transition-colors"
                        >
                            {isDeleting ? (
                                <><Loader2 size={14} className="animate-spin" /> Deleting…</>
                            ) : (
                                "Yes, Delete Category"
                            )}
                        </button>
                    </div>
                </div>
            </CatalogModal>
        </>
    );
}

"use client";

import type { Dispatch, SetStateAction } from "react";
import type { Model, Brand } from "@esparex/shared";
import type { ModelFormData } from "./types";
import { normalizeObjectIdLike } from "@/lib/utils/idUtils";
import { CatalogBoundNameCategoryFields } from "@/components/catalog/CatalogNameCategoryFields";
import { CatalogSelectField } from "@/components/catalog/CatalogUiPrimitives";
import { CatalogArchivedCategoryNotice } from "@/components/catalog/CatalogUiPrimitives";
import { getEntityCategoryIds } from "@/components/catalog/catalogDomainUtils";

export function ModelsFormRenderer({ formData, setFormData, isEditing, editingItem, brands, categoryOptions, parentModelOptions, archivedCategoryCount }: {
    formData: ModelFormData;
    setFormData: Dispatch<SetStateAction<ModelFormData>>;
    isEditing: boolean;
    editingItem?: Model;
    brands: Brand[];
    categoryOptions: { id: string; name: string }[];
    parentModelOptions: Model[];
    archivedCategoryCount: number;
}) {
    const formBrands = formData.categoryIds.length > 0
        ? brands.filter((brand) => getEntityCategoryIds(brand).some((cid) => formData.categoryIds.includes(cid)))
        : brands;
    const hierarchyOptions = parentModelOptions
        .filter((m) => m.id !== editingItem?.id)
        .filter((m) => !formData.brandId || normalizeObjectIdLike(m.brandId) === formData.brandId)
        .map((m) => ({ value: m.id, label: m.name }));

    return (
        <>
            <CatalogBoundNameCategoryFields
                formData={formData}
                setFormData={setFormData}
                nameLabel="Model Name"
                namePlaceholder="e.g. iPhone 15 Pro"
                categoryLabel="Assigned Categories"
                categoryOptions={categoryOptions}
                categoryNotice={<CatalogArchivedCategoryNotice archivedCategoryCount={archivedCategoryCount} />}
            />
            <div className="grid grid-cols-2 gap-4">
                <CatalogSelectField label="Brand" value={formData.brandId}
                    onChange={(brandId) => setFormData((prev) => ({ ...prev, brandId, parentModelId: null, variantOfModelId: null }))}
                    options={formBrands.map((b) => ({ value: b.id, label: b.name }))} placeholder="Select Brand" required />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <CatalogSelectField label="Parent Model" value={formData.parentModelId || ""}
                    onChange={(parentModelId) => setFormData((prev) => ({ ...prev, parentModelId: parentModelId || null, variantOfModelId: null, isParentModel: parentModelId ? false : prev.isParentModel }))}
                    options={hierarchyOptions} placeholder="No parent model" />
                <CatalogSelectField label="Variant Of" value={formData.variantOfModelId || ""}
                    onChange={(variantOfModelId) => setFormData((prev) => ({ ...prev, variantOfModelId: variantOfModelId || null, parentModelId: variantOfModelId || prev.parentModelId || null, isParentModel: variantOfModelId ? false : prev.isParentModel }))}
                    options={hierarchyOptions} placeholder="Not a variant" />
            </div>
            <label className="flex items-center gap-3 rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-sm font-medium text-slate-700">
                <input type="checkbox" className="h-4 w-4 rounded border-slate-300 text-primary focus:ring-primary/20"
                    checked={Boolean(formData.isParentModel)}
                    onChange={(event) => setFormData((prev) => ({ ...prev, isParentModel: event.target.checked }))}
                    disabled={Boolean(formData.parentModelId || formData.variantOfModelId)} />
                Parent model
            </label>
        </>
    );
}

