"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { getListingById } from "@/lib/api/user/listings";
import { usePostAdAction } from "./PostAdContext";
import { Loader2 } from "lucide-react";

export function EditAdWrapper({ children }: { children: React.ReactNode }) {
    const params = useParams();
    const id = params?.id as string | undefined;
    const { initializeFromListing, setLoadError } = usePostAdAction();

    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!id) {
            setError("No listing ID provided in route");
            setIsLoading(false);
            return;
        }

        let isMounted = true;

        async function fetchListing() {
            try {
                setIsLoading(true);
                setError(null);
                const data = await getListingById(id as string);
                if (!data) {
                    throw new Error("Listing not found or you do not have permission to edit it.");
                }
                if (isMounted) {
                    await initializeFromListing(data);
                    // Ensure loading state clears in the component regardless
                    // of what initializeFromListing does to context state.
                    setIsLoading(false);
                }
            } catch (err: unknown) {
                const message = err instanceof Error ? err.message : "Failed to load listing for editing";
                if (isMounted) {
                    setError(message);
                    setLoadError(message);
                    setIsLoading(false);
                }
            }
        }

        fetchListing();

        return () => {
            isMounted = false;
        };
        // Now that initializeFromListing is stable (uses setListingImages, not imagesHook),
        // this effect will only re-run if id changes — no more infinite loop.
    }, [id, initializeFromListing, setLoadError]);

    if (isLoading) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[400px]">
                <Loader2 className="w-8 h-8 animate-spin text-primary" />
                <p className="mt-4 text-muted-foreground">Loading listing data...</p>
            </div>
        );
    }

    if (error) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[400px] text-center px-4">
                <div className="bg-destructive/10 text-destructive p-6 rounded-lg max-w-md w-full">
                    <h3 className="font-semibold text-lg mb-2">Error Loading Listing</h3>
                    <p>{error}</p>
                </div>
            </div>
        );
    }

    return (
        <div className="edit-ad-wrapper relative">
            <div className="bg-amber-50 border-b border-amber-200 p-4 text-amber-800 text-sm text-center">
                <strong>Editing Listing:</strong> Changes to title, description, price, or images may require re-approval.
            </div>
            {children}
        </div>
    );
}

"use client";

import { useCallback } from "react";
import { usePostAdCatalog, usePostAdFlow, usePostAdAction } from "../../context";
import { Field } from "@/components/ui/field";
import { BrandSearchSelect } from "@/components/user/BrandSearchSelect";
import { useCascadeConfirmation } from "@/components/ui/cascade-confirm-dialog";
import { getNestedFieldMeta } from "../common/utils";
import { Button } from "@/components/ui/button";

export function BrandSection() {
    const { availableBrands, brandMap, brandIsPending, brandsError } = usePostAdCatalog();
    const { isEditMode, form, stepValidationAttempts, listingId } = usePostAdFlow();
    const { watch, handleBrandChange, loadBrandsForCategory, refreshBrands, createAndSelectBrand } = usePostAdAction();
    const { withCascadeConfirmation, ConfirmDialog, dialogProps } = useCascadeConfirmation();

    const categoryId = String(watch("categoryId") || watch("category") || "");
    const brandNameValue = String(watch("brand") ?? "");
    const modelId = String(watch("modelId") ?? "");
    const screenSize = String(watch("screenSize") || "");
    const deviceCondition = String(watch("deviceCondition") || "");
    const spareParts = (watch("spareParts") || []) as string[];

    const { touchedFields } = form.formState;
    const { errors } = form.formState;
    const hasAttemptedStepValidation = Boolean(stepValidationAttempts[1]);

    const shouldShowFieldError = useCallback((path: string) => hasAttemptedStepValidation || Boolean(getNestedFieldMeta(touchedFields, path)), [hasAttemptedStepValidation, touchedFields]);
    const brandError = (shouldShowFieldError("brand") || shouldShowFieldError("brandId")) ? (errors.brand?.message ?? errors.brandId?.message) : undefined;

    const onBrandChange = useCallback((name: string, rId?: string) => {
        if (isEditMode) return;
        const affected: string[] = [];
        if (modelId) affected.push("Model");
        if (screenSize) affected.push("Screen Size");
        if (deviceCondition) affected.push("Device Condition");
        if (spareParts.length > 0) affected.push("Selected Spare Parts");
        
        withCascadeConfirmation("Brand", affected, () => handleBrandChange(name, rId));
    }, [isEditMode, modelId, screenSize, deviceCondition, spareParts.length, handleBrandChange, withCascadeConfirmation]);

    return (
        <section className="space-y-3">
            <Field label="Brand" error={brandError as string} required>
                {brandIsPending && availableBrands.length === 0 ? (
                    <div className="h-11 w-full rounded-xl bg-slate-100 animate-pulse border border-slate-200" />
                ) : (
                    <BrandSearchSelect 
                        brands={availableBrands} 
                        brandMap={brandMap as any} 
                        categoryId={categoryId} 
                        value={brandNameValue} 
                        onChange={(_id, name) => onBrandChange(name, _id)} 
                        onRequestSuccess={() => refreshBrands()} 
                        onCreateBrand={createAndSelectBrand}
                        disabled={brandIsPending || isEditMode} 
                        placeholder={brandIsPending ? "Loading brands…" : "Search or select brand"} 
                        listingId={listingId} 
                    />
                )}
                {brandIsPending && availableBrands.length > 0 && (
                    <p className="text-[10px] text-muted-foreground mt-1 px-1 flex items-center gap-1.5">
                        <span className="inline-block h-2 w-2 rounded-full border-2 border-primary border-t-transparent animate-spin" />
                        Updating brands&hellip;
                    </p>
                )}
            </Field>
            {brandsError && (
                <div className="p-3 bg-red-50 border border-red-200 rounded-xl">
                    <p className="text-xs text-red-700 text-center mb-2">{brandsError}</p>
                    <Button 
                        type="button" 
                        variant="outline" 
                        size="sm" 
                        onClick={() => loadBrandsForCategory(categoryId)} 
                        className="w-full text-xs font-semibold text-red-600 border-red-200 hover:bg-red-50"
                    >
                        Try Again
                    </Button>
                </div>
            )}
            <ConfirmDialog {...dialogProps} />
        </section>
    );
}

"use client";

import { useCallback } from "react";
import { usePostAdCatalog, usePostAdFlow, usePostAdAction } from "../../context";
import { Field } from "@/components/ui/field";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Z_INDEX } from "@/lib/zIndexConfig";
import { useCascadeConfirmation } from "@/components/ui/cascade-confirm-dialog";
import { getNestedFieldMeta } from "../common/utils";
import { cn } from "@/components/ui/utils";
import { getVisibleAttributeFilters, renderAttributeField } from "../common/attribute-fields";

export function SpecificationSection() {
    const { categorySchema, requiresScreenSize, availableSizes } = usePostAdCatalog();
    const { isEditMode, form, stepValidationAttempts } = usePostAdFlow();
    const { watch, setValue } = usePostAdAction();
    const { withCascadeConfirmation, ConfirmDialog, dialogProps } = useCascadeConfirmation();

    const attributes = watch("attributes") as Record<string, unknown> | undefined;
    const screenSize = String(watch("screenSize") || "");
    const spareParts = (watch("spareParts") || []) as string[];

    const { touchedFields } = form.formState;
    const { errors } = form.formState;
    const hasAttemptedStepValidation = Boolean(stepValidationAttempts[1]);

    const shouldShowFieldError = useCallback((path: string) => hasAttemptedStepValidation || Boolean(getNestedFieldMeta(touchedFields, path)), [hasAttemptedStepValidation, touchedFields]);
    const screenSizeError = shouldShowFieldError("screenSize") ? errors.screenSize?.message : undefined;

    const onScreenSizeChange = useCallback((val: string) => {
        const affected: string[] = [];
        if (spareParts.length > 0) affected.push("Selected Spare Parts");

        withCascadeConfirmation("Screen Size", affected, () => {
            setValue("screenSize", val, { shouldValidate: true, shouldDirty: true, shouldTouch: true }); 
            setValue("spareParts", [], { shouldValidate: true, shouldDirty: true });
        });
    }, [spareParts.length, setValue, withCascadeConfirmation]);

    const updateAttribute = useCallback((id: string, value: unknown) => {
        const current = form.getValues("attributes") as Record<string, unknown> | undefined;
        setValue("attributes", { ...(current ?? {}), [id]: value } as any, { shouldValidate: true, shouldDirty: true, shouldTouch: true });
    }, [form, setValue]);

    const dynamicAttributeFilters = getVisibleAttributeFilters(categorySchema, attributes);
    
    if (dynamicAttributeFilters.length === 0 && !requiresScreenSize) {
        return null;
    }

    return (
        <div className="flex flex-col gap-3">
            {dynamicAttributeFilters.length > 0 ? (
                <section className={cn("space-y-3 rounded-2xl border border-slate-100 bg-slate-50/40 p-3", isEditMode && "opacity-60 pointer-events-none")}>
                    <div>
                        <p className="text-xs font-bold uppercase tracking-wider text-foreground-tertiary">Category Details</p>
                    </div>
                    <div className="space-y-3">
                        {dynamicAttributeFilters.map((f) => renderAttributeField(
                            f, 
                            getAttributeValue(attributes, f.id) ?? f.defaultValue, 
                            shouldShowFieldError(`attributes.${f.id}`) ? (getNestedFieldMeta(errors, `attributes.${f.id}.message`) as string | undefined) : undefined, 
                            updateAttribute
                        ))}
                    </div>
                </section>
            ) : null}

            {requiresScreenSize && (
                <Field label="Screen Size" error={screenSizeError as string} className={cn(isEditMode && "opacity-60 pointer-events-none")}>
                    <Select value={screenSize || undefined} onValueChange={onScreenSizeChange}>
                        <SelectTrigger className="h-11 rounded-xl border-2 border-slate-200 bg-white font-bold text-foreground focus:border-primary transition-colors px-3 text-sm">
                            <SelectValue placeholder="Select size" />
                        </SelectTrigger>
                        <SelectContent style={{ zIndex: Z_INDEX.selectContent }} className="rounded-xl border-2 border-slate-100 shadow-xl">
                            {availableSizes.map((size) => (
                                <SelectItem key={size} value={size} className="font-medium py-2.5 px-3 text-sm">{size}</SelectItem>
                            ))}
                        </SelectContent>
                    </Select>
                </Field>
            )}
            
            <ConfirmDialog {...dialogProps} />
        </div>
    );
}

const getAttributeValue = (attributes: unknown, id: string): unknown => {
    if (!attributes || typeof attributes !== "object") return undefined;
    return (attributes as Record<string, unknown>)[id];
};

