import { apiClient } from "@/lib/api/client";
import { API_ROUTES } from "../routes";
import { unwrapApiPayload } from "@/lib/api/result";
import logger from "@/lib/logger";

export interface CreateCatalogRequestPayload {
    requestType: 'brand' | 'model';
    categoryId: string;
    parentBrandId?: string;
    requestedName: string;
    /** Optional soft reference to the related listing (edit-ad flow only). */
    listingId?: string;
}

export interface CatalogRequest {
    id: string;
    requestType: 'brand' | 'model';
    categoryId: string;
    parentBrandId?: string;
    requestedName: string;
    status: 'pending' | 'approved' | 'rejected' | 'duplicate' | 'resolved';
    createdAt: string;
}

interface PaginationMeta {
    page: number;
    limit: number;
    total: number;
    pages: number;
}

export interface CatalogRequestResult {
    approvedEntityId?: string;
    requestId?: string;
    name: string;
    decision: 'AUTO_APPROVE' | 'MANUAL_REVIEW' | 'REJECT';
    created?: boolean;
    request: any;
}

/**
 * Submit a request for a missing brand or model.
 * This will be resolved based on resolution policies.
 */
export async function createCatalogRequest(payload: CreateCatalogRequestPayload): Promise<CatalogRequestResult> {
    try {
        const response = await apiClient.post(API_ROUTES.USER.CATALOG_REQUESTS, payload);
        return unwrapApiPayload<CatalogRequestResult>(response) as CatalogRequestResult;
    } catch (error) {
        logger.error("[CatalogRequest] createCatalogRequest failed:", error);
        throw error instanceof Error ? error : new Error("Failed to submit request");
    }
}

/**
 * Get the current user's submitted catalog requests.
 */
export async function getMyCatalogRequests(params?: {
    status?: string;
    requestType?: string;
    page?: number;
    limit?: number;
}): Promise<{ items: CatalogRequest[]; total: number; pagination: PaginationMeta }> {
    try {
        const response = await apiClient.get(API_ROUTES.USER.CATALOG_REQUESTS_MY, { params });
        const envelope = (response as { data?: unknown })?.data ?? response;
        const data = unwrapApiPayload<unknown>(response);
        const meta: Partial<PaginationMeta> = (
            envelope &&
            typeof envelope === 'object' &&
            !Array.isArray(envelope) &&
            (envelope as { meta?: { pagination?: Partial<PaginationMeta> } }).meta?.pagination
        ) || {};
        const items = (
            data &&
            typeof data === 'object' &&
            !Array.isArray(data) &&
            Array.isArray((data as { items?: CatalogRequest[] }).items)
        )
            ? ((data as { items: CatalogRequest[] }).items)
            : (Array.isArray(data) ? (data as CatalogRequest[]) : []);
        const page = Number(meta.page ?? params?.page ?? 1);
        const limit = Number(meta.limit ?? params?.limit ?? 20);
        const total = Number(meta.total ?? items.length);
        const pages = Number(meta.pages ?? Math.max(1, Math.ceil(total / Math.max(1, limit))));

        return {
            items,
            total,
            pagination: {
                page,
                limit,
                total,
                pages,
            },
        };
    } catch (error) {
        logger.error("[CatalogRequest] getMyCatalogRequests failed:", error);
        throw error instanceof Error ? error : new Error("Failed to load requests");
    }
}

import { Request, Response } from 'express';
import logger from '@esparex/core/utils/logger';
import { sendSuccessResponse } from '../../../utils/respond';
import { handlePaginatedContent } from '../../../utils/contentHandler';
import mongoose from 'mongoose';
import { CATALOG_APPROVAL_STATUS } from '@esparex/shared';
import { BrandModel, findBrandByFilter, findCategoryBySlugForCatalog } from '@esparex/core/services/catalog/CatalogBrandModelService';
import CatalogOrchestrator from '@esparex/core/services/catalog/CatalogOrchestrator';
import { sendCatalogError, QueryRecord, ACTIVE_CATEGORY_QUERY, validateActiveCategories, handleCatalogCreate, handleCatalogUpdate, handleCatalogToggleStatus, handleCatalogReview, sendEmptyPublicList, applyCatalogStatusFilter, hasAdminAccess, CATALOG_PUBLIC_VISIBILITY_QUERY, deriveApprovalStatus } from './shared';
import { logAdminAction } from '../../../utils/adminLogger';
import { brandCreateSchema, brandUpdateSchema, rejectionSchema } from '@esparex/core/validators/catalog.validator';
import CategoryQueryBuilder from '@esparex/core/utils/CategoryQueryBuilder';
import { getCache } from '@esparex/core/utils/redisCache';
import { catalogCacheKey, applyCacheWriteThrough } from './adminCatalogShared';
import { AppError } from '@esparex/core/utils/AppError';

export const getBrands = async (req: Request, res: Response) => {
    const isAdminView = req.originalUrl.includes('/admin');
    const categoryId = req.query.categoryId as string;
    let categoryObjectId: string | undefined = (categoryId && categoryId !== 'all') ? categoryId : undefined;
    if (!isAdminView && categoryId && categoryId !== 'all') {
        if (!mongoose.Types.ObjectId.isValid(categoryId)) {
            const cat = await findCategoryBySlugForCatalog(categoryId, ACTIVE_CATEGORY_QUERY);
            if (cat) categoryObjectId = cat._id.toString();
            else logger.debug('[Catalog] Category not found by slug (getBrands)', { categorySlug: categoryId });
        }
    }
    if (!isAdminView && !categoryObjectId) return sendCatalogError(req, res, 'categoryId is required', 400);
    if (!isAdminView) {
        const cacheKey = catalogCacheKey.brands(categoryObjectId ?? 'all');
        const cached = await getCache<unknown>(cacheKey);
        if (cached) return res.json(cached);
        applyCacheWriteThrough(res, cacheKey);
    }
    if (!isAdminView && categoryObjectId) {
        const v = await validateActiveCategories([categoryObjectId]);
        if (!v.ok) { logger.debug('[Catalog] Category not active (getBrands)', { categoryId: categoryObjectId }); return sendEmptyPublicList(res); }
    }
    const queryParams: QueryRecord = { ...(req.query as QueryRecord) };
    delete queryParams.categoryId; delete queryParams.categoryIds; delete queryParams.status;
    const categoryFilter = CategoryQueryBuilder.forPlural().withFilters({ categoryIds: categoryObjectId ? [categoryObjectId] : [] }).build();
    const adminCategoryFilter = CategoryQueryBuilder.forPlural().withFilters({ categoryIds: categoryObjectId ? [categoryObjectId] : [] }).build();
    const rawStatus = Array.isArray(req.query.status) ? req.query.status[0] : req.query.status;
    applyCatalogStatusFilter(adminCategoryFilter, rawStatus);
    return handlePaginatedContent(req, res, BrandModel, {
        searchFields: ['name', 'canonicalName', 'aliases'],
        publicQuery: { ...CATALOG_PUBLIC_VISIBILITY_QUERY, ...categoryFilter },
        adminQuery: adminCategoryFilter, queryParams,
    });
};

export const getBrandById = async (req: Request, res: Response) => {
    try {
        const isAdminView = req.originalUrl.includes('/admin');
        const brand = await findBrandByFilter({ _id: req.params.id, ...(isAdminView ? {} : { ...CATALOG_PUBLIC_VISIBILITY_QUERY }) });
        if (!brand) return sendCatalogError(req, res, 'Brand not found', 404);
        sendSuccessResponse(res, brand);
    } catch (error) { sendCatalogError(req, res, error); }
};

export const getBrandBySlug = async (req: Request, res: Response) => {
    try {
        const slug = String(req.params.slug || '').trim().toLowerCase();
        if (!slug) return sendCatalogError(req, res, 'Brand slug is required', 400);
        const brand = await findBrandByFilter({ ...CATALOG_PUBLIC_VISIBILITY_QUERY, $or: [{ slug }, { canonicalName: slug.replace(/-/g, ' ') }, { aliases: { $in: [slug.replace(/-/g, ' '), slug] } }] });
        if (!brand) return sendCatalogError(req, res, 'Brand not found', 404);
        sendSuccessResponse(res, brand);
    } catch (error) { sendCatalogError(req, res, error); }
};

export const createBrand = async (req: Request, res: Response) => {
    return handleCatalogCreate(req, res, BrandModel, brandCreateSchema, {
        auditAction: 'BRAND_CREATE', slugifyName: true,
        preOp: async (payload) => {
            const categoryIds = Array.isArray(payload.categoryIds) ? (payload.categoryIds as string[]).map(String) : [];
            payload.categoryIds = categoryIds;
            if (categoryIds.length === 0) payload.isActive = false;
            payload.approvalStatus = deriveApprovalStatus({ approvalStatus: payload.approvalStatus, isActive: payload.isActive as boolean | undefined, fallback: CATALOG_APPROVAL_STATUS.APPROVED });
            const catVal = await validateActiveCategories(categoryIds);
            if (!catVal.ok) throw new Error(`Invalid or inactive categories: ${catVal.invalidCategoryIds.join(', ')}`);
            return payload;
        },
        postOp: (item: any) => void CatalogOrchestrator.invalidateCatalogCache({ categoryIds: item.categoryIds || (item.categoryId ? [item.categoryId] : []), brandIds: item.brandId ? [item.brandId] : [] }),
    });
};

export const updateBrand = async (req: Request, res: Response) => {
    return handleCatalogUpdate(req, res, BrandModel, brandUpdateSchema, {
        auditAction: 'BRAND_RENAME',
        preUpdate: async (_id, payload, oldBrand) => {
            const typedOld = oldBrand as { categoryIds?: unknown[]; approvalStatus?: unknown; isActive?: boolean };
            const nextCategoryIds = payload.categoryIds ? (payload.categoryIds as string[]).map(String) : (typedOld.categoryIds || []).map(String);
            payload.categoryIds = nextCategoryIds;
            if (nextCategoryIds.length === 0) payload.isActive = false;
            payload.approvalStatus = deriveApprovalStatus({ approvalStatus: payload.approvalStatus ?? typedOld.approvalStatus, isActive: (payload.isActive ?? typedOld.isActive) as boolean | undefined, fallback: CATALOG_APPROVAL_STATUS.APPROVED });
            const catVal = await validateActiveCategories(nextCategoryIds);
            if (!catVal.ok) throw new Error(`Invalid or inactive categories: ${catVal.invalidCategoryIds.join(', ')}`);
            return payload;
        },
        postOp: (item: any) => void CatalogOrchestrator.invalidateCatalogCache({ categoryIds: item.categoryIds || (item.categoryId ? [item.categoryId] : []), brandIds: item.brandId ? [item.brandId] : [] }),
    });
};

export const toggleBrandStatus = async (req: Request, res: Response) => {
    return handleCatalogToggleStatus(req, res, BrandModel, {
        auditAction: 'TOGGLE_BRAND_STATUS',
        postOp: (item: any) => void CatalogOrchestrator.invalidateCatalogCache({ categoryIds: item.categoryIds || (item.categoryId ? [item.categoryId] : []), brandIds: item.brandId ? [item.brandId] : [] }),
    });
};

export const deleteBrand = async (req: Request, res: Response) => {
    try {
        if (!hasAdminAccess(req)) return res.status(403).json({ success: false, error: 'Admin access required', path: req.originalUrl || req.path, status: 403 });
        const id = String(req.params.id);
        if (!mongoose.Types.ObjectId.isValid(id)) return res.status(400).json({ success: false, error: 'Invalid Brand ID format', path: req.originalUrl || req.path, status: 400 });

        const result = await CatalogOrchestrator.deleteBrandOrchestrated(id);

        if (!result.alreadyDeleted) {
            void logAdminAction(req, 'BRAND_DELETE', 'Brand', new mongoose.Types.ObjectId(id));
        }

        return res.status(200).json({
            success: true,
            message: 'Brand and dependent models and spare parts soft-deleted successfully',
            data: result
        });
    } catch (error) {
        if (error instanceof AppError && error.code === 'DEPENDENCIES_EXIST') {
            return res.status(409).json({
                success: false,
                error: error.message,
                status: 409,
                details: error.details
            });
        }
        return res.status(500).json({
            success: false,
            error: error instanceof Error ? error.message : 'An unexpected error occurred',
            path: req.originalUrl || req.path,
            status: 500
        });
    }
};

export const approveBrand = (req: Request, res: Response) => handleCatalogReview(req, res, BrandModel, 'APPROVE', undefined, { auditAction: 'APPROVE_BRAND', postOp: (item: any) => void CatalogOrchestrator.invalidateCatalogCache({ categoryIds: item.categoryIds || (item.categoryId ? [item.categoryId] : []), brandIds: item.brandId ? [item.brandId] : [] }) });

export const rejectBrand = (req: Request, res: Response) => handleCatalogReview(req, res, BrandModel, 'REJECT', rejectionSchema, { auditAction: 'REJECT_BRAND', postOp: (item: any) => void CatalogOrchestrator.invalidateCatalogCache({ categoryIds: item.categoryIds || (item.categoryId ? [item.categoryId] : []), brandIds: item.brandId ? [item.brandId] : [] }) });

import mongoose from 'mongoose';
import { Request, Response } from 'express';
import logger from '@esparex/core/utils/logger';
import { toOptionalString } from './inputCoercion';
import { setCache } from '@esparex/core/utils/redisCache';
import { getVariantsAndModelsForParentModels, getBrandModelsForDuplicateCheck } from '@esparex/core/services/catalog/CatalogBrandModelService';
import { validateModelHierarchyMutation } from '@esparex/core/services/catalog/CatalogHierarchyService';
import { detectDuplicateCandidates } from '@esparex/core/services/catalog/CatalogSearchGovernanceService';

export const CATALOG_CACHE_TTL = 300;

export const normalizeCacheValue = (value: unknown): string => {
    if (Array.isArray(value)) return value.map(normalizeCacheValue).join(',');
    if (value === undefined || value === null || value === '') return 'all';
    return encodeURIComponent(String(value));
};

export const catalogCacheKey = {
    brands: (categoryId: string) => `catalog:brands:${normalizeCacheValue(categoryId)}`,
    models: (params: {
        categoryId?: unknown; brandId?: unknown; parentModelId?: unknown; variantModelId?: unknown;
        includeVariants?: unknown; treeView?: unknown; search?: unknown; q?: unknown;
        page?: unknown; limit?: unknown; sort?: unknown;
    }) => ['catalog:models', `category=${normalizeCacheValue(params.categoryId)}`, `brand=${normalizeCacheValue(params.brandId)}`,
        `parent=${normalizeCacheValue(params.parentModelId)}`, `variant=${normalizeCacheValue(params.variantModelId)}`,
        `includeVariants=${normalizeCacheValue(params.includeVariants)}`, `treeView=${normalizeCacheValue(params.treeView)}`,
        `search=${normalizeCacheValue(params.search ?? params.q)}`, `page=${normalizeCacheValue(params.page ?? 1)}`,
        `limit=${normalizeCacheValue(params.limit ?? 100)}`, `sort=${normalizeCacheValue(params.sort ?? 'name')}`,
    ].join(':'),
};

export const normalizeOptionalObjectIdQuery = (value: unknown): string | undefined => {
    const raw = Array.isArray(value) ? value[0] : value;
    if (typeof raw !== 'string') return undefined;
    const normalized = raw.trim();
    if (!normalized || normalized === 'all') return undefined;
    return mongoose.Types.ObjectId.isValid(normalized) ? normalized : undefined;
};

export const normalizeBooleanQuery = (value: unknown): boolean => {
    const raw = Array.isArray(value) ? value[0] : value;
    return raw === true || raw === 'true' || raw === '1';
};

export const populateModelVariants = async (items: unknown[]) => {
    const modelIds = items.map((item) => { const m = item as { _id?: unknown; id?: unknown }; return m._id ?? m.id; }).filter(Boolean).map(String);
    if (modelIds.length === 0) return items;
    const [variantDocs, variantModelDocs] = await getVariantsAndModelsForParentModels(modelIds);
    const variantsByModelId = new Map<string, unknown[]>();
    for (const v of variantDocs) { const mid = String((v as { modelId?: unknown }).modelId ?? ''); if (!mid) continue; const ex = variantsByModelId.get(mid) ?? []; ex.push(v); variantsByModelId.set(mid, ex); }
    const variantModelsByParentId = new Map<string, unknown[]>();
    for (const vm of variantModelDocs) { const pid = String((vm as { variantOfModelId?: unknown }).variantOfModelId ?? ''); if (!pid) continue; const ex = variantModelsByParentId.get(pid) ?? []; ex.push(vm); variantModelsByParentId.set(pid, ex); }
    return items.map((item) => {
        const plain = typeof (item as { toObject?: () => unknown }).toObject === 'function' ? (item as { toObject: () => Record<string, unknown> }).toObject() : { ...(item as Record<string, unknown>) };
        const id = String(plain._id ?? plain.id ?? '');
        return { ...plain, variants: variantsByModelId.get(id) ?? [], variantModels: variantModelsByParentId.get(id) ?? [] };
    });
};

export const applyModelHierarchyPayload = async (payload: Record<string, unknown>, options: { existingModel?: unknown } = {}) => {
    const normalizedPayload = {
        ...payload,
        brandId: toOptionalString(payload.brandId) ?? payload.brandId,
        parentModelId: payload.parentModelId === null ? null : toOptionalString(payload.parentModelId) ?? payload.parentModelId,
        variantOfModelId: payload.variantOfModelId === null ? null : toOptionalString(payload.variantOfModelId) ?? payload.variantOfModelId,
    };
    return validateModelHierarchyMutation(normalizedPayload, { existingModel: options.existingModel as any });
};

export const logModelDuplicateCandidates = async (req: Request, payload: Record<string, unknown>, options: { excludeId?: string } = {}) => {
    const name = String(payload.displayName ?? payload.name ?? payload.canonicalName ?? '').trim();
    const brandId = toOptionalString(payload.brandId);
    if (!name || !brandId) return;
    const candidates = await getBrandModelsForDuplicateCheck(brandId, options.excludeId);
    const dupes = detectDuplicateCandidates(name, candidates as unknown as Record<string, unknown>[]);
    if (dupes.length > 0) logger.warn('[CatalogSearch] Potential model duplicate candidates detected', { requestPath: req.originalUrl || req.path, candidateCount: dupes.length, input: name, candidates: dupes });
};

export const applyCacheWriteThrough = (res: Response, cacheKey: string) => {
    const originalJson = res.json.bind(res);
    res.json = (body: unknown) => {
        if (res.statusCode >= 200 && res.statusCode < 300) setCache(cacheKey, body, CATALOG_CACHE_TTL).catch(() => {});
        return originalJson(body);
    };
};

import { Request, Response } from 'express';
import logger from '@esparex/core/utils/logger';
import { sendSuccessResponse } from '../../../utils/respond';
import { handlePaginatedContent } from '../../../utils/contentHandler';
import mongoose from 'mongoose';
import { CATALOG_APPROVAL_STATUS } from '@esparex/shared';
import { CatalogModel, findCategoryBySlugForCatalog, getActiveBrandIds, checkBrandInCategories, checkModelDependencies, findModelByFilter, findModelBySlug } from '@esparex/core/services/catalog/CatalogBrandModelService';
import { validateBrandIsActive } from '@esparex/core/services/catalog/CatalogValidationService';
import CatalogOrchestrator from '@esparex/core/services/catalog/CatalogOrchestrator';
import { sendCatalogError, QueryRecord, ACTIVE_CATEGORY_QUERY, validateActiveCategories, getActiveCategoryIds, handleCatalogCreate, handleCatalogUpdate, handleCatalogToggleStatus, handleCatalogDelete, handleCatalogReview, sendEmptyPublicList, applyCatalogStatusFilter, CATALOG_PUBLIC_VISIBILITY_QUERY, deriveApprovalStatus } from './shared';
import { toOptionalString, toStringArray } from './inputCoercion';
import { modelCreateSchema, modelUpdateSchema, rejectionSchema } from '@esparex/core/validators/catalog.validator';
import CategoryQueryBuilder from '@esparex/core/utils/CategoryQueryBuilder';
import { MAX_MODEL_TREE_DEPTH } from '@esparex/core/services/catalog/CatalogHierarchyService';
import { updateModelHierarchyTransactionally } from '@esparex/core/services/catalog/CatalogHierarchyService';
import { getCache } from '@esparex/core/utils/redisCache';
import { catalogCacheKey, applyCacheWriteThrough, normalizeOptionalObjectIdQuery, normalizeBooleanQuery, populateModelVariants, applyModelHierarchyPayload, logModelDuplicateCandidates } from './adminCatalogShared';

export const getModels = async (req: Request, res: Response) => {
    const isAdminView = req.originalUrl.includes('/admin');
    const { brandId } = req.query;
    const brandObjectId = (typeof brandId === 'string' && brandId !== 'all') ? brandId : undefined;
    const parentModelId = normalizeOptionalObjectIdQuery(req.query.parentModelId);
    const variantModelId = normalizeOptionalObjectIdQuery(req.query.variantModelId);
    const includeVariants = normalizeBooleanQuery(req.query.includeVariants);
    const treeView = normalizeBooleanQuery(req.query.treeView);
    const categoryId = req.query.categoryId as string;
    const rawStatus = Array.isArray(req.query.status) ? req.query.status[0] : req.query.status;
    let categoryObjectId: string | undefined = (categoryId && categoryId !== 'all') ? categoryId : undefined;
    if (!isAdminView && categoryId && categoryId !== 'all' && !mongoose.Types.ObjectId.isValid(categoryId)) {
        const cat = await findCategoryBySlugForCatalog(categoryId, ACTIVE_CATEGORY_QUERY);
        if (cat) categoryObjectId = cat._id.toString();
    }
    if (!isAdminView) {
        const cacheKey = catalogCacheKey.models({ categoryId: categoryObjectId, brandId: brandObjectId, parentModelId, variantModelId, includeVariants: req.query.includeVariants, treeView: req.query.treeView, search: req.query.search, q: req.query.q, page: req.query.page, limit: req.query.limit, sort: req.query.sort });
        const cached = await getCache<unknown>(cacheKey);
        if (cached) return res.json(cached);
        applyCacheWriteThrough(res, cacheKey);
    }
    if (!isAdminView && categoryObjectId) {
        const v = await validateActiveCategories([categoryObjectId]);
        if (!v.ok) return sendEmptyPublicList(res);
    }
    let activeCategoryIds: string[] = [];
    if (!isAdminView) { activeCategoryIds = categoryObjectId ? [categoryObjectId] : await getActiveCategoryIds(); if (activeCategoryIds.length === 0) return sendEmptyPublicList(res); }
    const activeBrandIds = !isAdminView ? await getActiveBrandIds(activeCategoryIds) : [];
    if (!isAdminView && activeBrandIds.length === 0) return sendEmptyPublicList(res);
    const adminQuery: QueryRecord = {};
    if (brandObjectId) adminQuery.brandId = brandObjectId;
    if (parentModelId) adminQuery.parentModelId = parentModelId;
    if (variantModelId) adminQuery.variantOfModelId = variantModelId;
    if (treeView && !parentModelId && !variantModelId) { adminQuery.variantOfModelId = { $in: [null] }; adminQuery.treeDepth = { $lte: MAX_MODEL_TREE_DEPTH }; }
    if (categoryId) Object.assign(adminQuery, CategoryQueryBuilder.forPlural().withFilters({ categoryIds: [categoryId] }).build());
    applyCatalogStatusFilter(adminQuery, rawStatus);
    const publicQuery: QueryRecord = { ...CATALOG_PUBLIC_VISIBILITY_QUERY };
    if (!isAdminView) { Object.assign(publicQuery, CategoryQueryBuilder.forPlural().withFilters({ categoryIds: activeCategoryIds }).build()); publicQuery.brandId = { $in: activeBrandIds }; }
    if (brandObjectId) publicQuery.brandId = brandObjectId;
    if (parentModelId) publicQuery.parentModelId = parentModelId;
    if (variantModelId) publicQuery.variantOfModelId = variantModelId;
    if (treeView && !parentModelId && !variantModelId) { publicQuery.variantOfModelId = { $in: [null] }; publicQuery.treeDepth = { $lte: MAX_MODEL_TREE_DEPTH }; }
