import type { Document, Model } from 'mongoose';
import { Request } from 'express';
import logger from '@esparex/core/utils/logger';
import { getAdminConnection, getUserConnection } from '@esparex/core/config/db';
import { castCatalogQueryIds, summarizeCatalogReadDiff, recordCatalogReadDiff } from '@esparex/core/utils/catalogShadowRead';

export const CATALOG_MODELS = ['Category', 'Brand', 'Model', 'ServiceType', 'ScreenSize', 'SparePart'];

export const ensureAdminCatalogModel = <T extends Document>(model: Model<T>): Model<T> => {
    const adminConn = getAdminConnection();
    const userConn = getUserConnection();
    for (const modelName of CATALOG_MODELS) {
        const userModel = userConn.models[modelName] as Model<Document> | undefined;
        if (userModel && !adminConn.models[modelName]) adminConn.model(modelName, userModel.schema, userModel.collection.name);
    }
    return (adminConn.models[model.modelName] as Model<T> | undefined) || adminConn.model<T>(model.modelName, model.schema, model.collection.name);
};

export const readAdminCatalogPage = async (params: {
    model: Model<Document>; query: Record<string, unknown>; sort: Record<string, 1 | -1>; skip: number; limit: number; populate?: unknown; select?: string; includeDeleted?: boolean;
}) => {
    const adminModel = ensureAdminCatalogModel(params.model);
    const adminQuery = castCatalogQueryIds(params.query) as Record<string, unknown>;
    const findQuery = adminModel.find(adminQuery).skip(params.skip).limit(params.limit).sort(params.sort);
    if (params.includeDeleted) findQuery.setOptions({ withDeleted: true });
    if (params.populate) (findQuery as any).populate(params.populate);
    if (params.select) findQuery.select(params.select);
    const countQuery = adminModel.countDocuments(adminQuery);
    if (params.includeDeleted) countQuery.setOptions({ withDeleted: true });
    return Promise.all([findQuery, countQuery]);
};

export const tryAdminCatalogReadSwitch = async <T extends Document>(params: {
    req: Request; model: Model<T>; query: Record<string, unknown>; sort: Record<string, 1 | -1>; skip: number; limit: number; populate?: unknown; select?: string; includeDeleted?: boolean; transformResponse?: (items: unknown[]) => unknown | Promise<unknown>; userItems: unknown[]; userTotal: number;
}): Promise<{ items: unknown[]; total: number } | null> => {
    try {
        const [adminItems, adminTotal] = await readAdminCatalogPage({ model: params.model as any, query: params.query, sort: params.sort, skip: params.skip, limit: params.limit, populate: params.populate, select: params.select, includeDeleted: params.includeDeleted });
        const rai = params.transformResponse ? await params.transformResponse(adminItems as unknown[]) : adminItems as unknown[];
        if (!Array.isArray(rai)) return null;
        const diff = summarizeCatalogReadDiff(params.userItems as Record<string, unknown>[], rai as Record<string, unknown>[]);
        if (!diff.mismatch && params.userTotal === adminTotal) return { items: rai, total: adminTotal };
        await recordCatalogReadDiff({ modelName: params.model.modelName, query: params.query, userRows: params.userItems as Record<string, unknown>[], adminRows: rai as Record<string, unknown>[], requestPath: params.req.originalUrl || params.req.path, requestMethod: params.req.method });
        logger.warn('[CatalogReadSwitch] Falling back', { requestPath: params.req.originalUrl || params.req.path, modelName: params.model.modelName, userTotal: params.userTotal, adminTotal, summary: diff.summary });
        return null;
    } catch (error) {
        logger.warn('[CatalogReadSwitch] Admin read failed', { requestPath: params.req.originalUrl || params.req.path, modelName: params.model.modelName, error: error instanceof Error ? error.message : String(error) });
        return null;
    }
};

export const parseSortQuery = (rawSort: unknown, defaultSort: Record<string, 1 | -1>): Record<string, 1 | -1> => {
    if (typeof rawSort !== 'string' || rawSort.trim().length === 0) return defaultSort;
    const sort: Record<string, 1 | -1> = {};
    for (const segment of rawSort.split(',').map((s) => s.trim()).filter(Boolean)) {
        const dir: 1 | -1 = segment.startsWith('-') ? -1 : 1;
        const field = segment.replace(/^-/, '');
        if (!/^[a-zA-Z0-9_.]+$/.test(field)) continue;
        sort[field] = dir;
    }
    return Object.keys(sort).length > 0 ? sort : defaultSort;
};

import { Request, Response } from 'express';
import type { Document, Model } from 'mongoose';
import { LISTING_TYPE_VALUES, type ListingTypeValue } from '@esparex/shared';
import { getPaginationParams, sendPaginatedResponse, sendSuccessResponse, sendAdminError } from '../adminBaseController';
import { getCache, setCache, CACHE_TTLS } from '@esparex/core/utils/redisCache';
import { FeatureFlag, isEnabled } from '@esparex/core/config/featureFlags';
import { buildRegexSearchClauses, rankCatalogSearchResults, recordCatalogSearchTelemetry, shouldSuppressAutocomplete, tryAtlasCatalogSearch } from '@esparex/core/services/catalog/CatalogSearchGovernanceService';
import { runCatalogShadowRead } from '@esparex/core/utils/catalogShadowRead';
import type { ContentOptions } from './types';
import { CATALOG_MODELS, parseSortQuery, tryAdminCatalogReadSwitch } from './helpers';

const AF = new Set(['status','isActive','categoryId','categoryIds','brandId','modelId','parentModelId','variantOfModelId','variantModelId','type','needsReview','suggestedBy','createdBy','listingType']);
const IG = new Set(['page','limit','q','search','includeDeleted','sort','order','tab','view']);

export async function handlePaginatedContent<T extends Document>(req: Request, res: Response, model: Model<T>, options: ContentOptions = {}) {
    try {
        const user = (req as any).user;
        const isAdmin = Boolean((req as any).admin) || user?.role === 'admin' || user?.role === 'super_admin';
        const isUrlAdmin = req.originalUrl.includes('/admin');
        const { searchFields = ['name'], defaultSort = { name: 1 }, publicQuery = { isActive: true }, adminQuery = {}, populate, select, transformResponse, queryParams } = options;
        const eq = (queryParams || req.query) as Record<string, unknown>;
        const isCM = CATALOG_MODELS.includes(model.modelName);
        const uACR = isCM ? await isEnabled(FeatureFlag.USE_ADMIN_CATALOG_READS) : false;
        const uACS = isCM ? await isEnabled(FeatureFlag.ENABLE_ATLAS_CATALOG_SEARCH) : false;
        let ck: string | null = null;

        if (isCM) {
            const sq = Object.keys(eq).sort().map(k => `${k}=${encodeURIComponent(String(eq[k]))}`).join('&');
            ck = `catalog:list:${model.modelName.toLowerCase()}:${isUrlAdmin ? 'admin' : 'public'}:${uACR ? 'admin-read' : 'user-read'}:${req.path}?${sq}`;
            const cp = await getCache<any>(ck);
            if (cp) {
                const etag = `W/"${Buffer.from(JSON.stringify(cp)).toString('base64').substring(0, 24)}"`;
                res.setHeader('ETag', etag);
                if (req.headers['if-none-match'] === etag) return res.status(304).end();
                if (isUrlAdmin && Array.isArray(cp.items) && typeof cp.total === 'number' && typeof cp.page === 'number' && typeof cp.limit === 'number') return sendPaginatedResponse(res, cp.items, cp.total, cp.page, cp.limit);
                return sendSuccessResponse(res, cp);
            }
        }

        if (isAdmin && isUrlAdmin) {
            const { page, limit, skip } = getPaginationParams(req);
            const rs = eq.q || eq.search; const sv = Array.isArray(rs) ? rs[0] : rs;
            const st = Date.now(); const search = typeof sv === 'string' ? (sv as string).trim().slice(0, 120) : '';
            const incDel = eq.includeDeleted === 'true';
            if (search && limit <= 50 && shouldSuppressAutocomplete({ key: req.ip || 'admin', search, limit })) return sendPaginatedResponse(res, [], 0, page, limit);
            const q: Record<string, unknown> = { ...adminQuery };
            if (!incDel && !('isDeleted' in q)) q.isDeleted = { $ne: true };
            if (search && searchFields.length > 0) q.$or = buildRegexSearchClauses(search, searchFields);
            Object.entries(eq).forEach(([k, v]) => {
                if (IG.has(k) || !AF.has(k) || v === 'all' || v === '' || v === undefined) return;
                let tk = k;
                if (k === 'categoryId' && (model.schema as any)?.paths && 'categoryIds' in (model.schema as any).paths) tk = 'categoryIds';
                if (k === 'variantModelId' && (model.schema as any)?.paths && 'variantOfModelId' in (model.schema as any).paths) tk = 'variantOfModelId';
                if (q[tk] !== undefined) return;
                if (tk === 'status' && v === 'deleted' && q.isDeleted === true) return;
                let tv = v;
                if (tk === 'isActive') { if (v === 'true') tv = true; if (v === 'false') tv = false; }
                q[tk] = tv;
            });
            const asrt = Array.isArray(eq.sort) ? eq.sort[0] : eq.sort;
            const aSort = parseSortQuery(asrt, { createdAt: -1 });
            const ats = search && uACS ? await tryAtlasCatalogSearch({ model: model as any, query: q, search, searchFields, skip, limit }) : null;
            const efq = ats?.ids.length ? { ...q, _id: { $in: ats.ids } } : q;
            const fq = model.find(efq).skip(ats ? 0 : skip).limit(limit).sort(ats ? {} : aSort);
            if (incDel) fq.setOptions({ withDeleted: true });
            if (populate) (fq as any).populate(populate);
            if (select) fq.select(select);
            const cq = model.countDocuments(q);
            if (incDel) cq.setOptions({ withDeleted: true });
            const [items, total] = await Promise.all([fq, cq]);
            const ri = transformResponse ? await transformResponse(items as unknown[]) : items;
            const rk = search && Array.isArray(ri) ? rankCatalogSearchResults(ri, search, searchFields, ats?.scores, { autocomplete: limit <= 50, collapseVariants: limit <= 50 }) : ri;
            if (search) recordCatalogSearchTelemetry({ search, latencyMs: Date.now() - st, resultCount: Array.isArray(rk) ? rk.length : 0, autocomplete: limit <= 50 });
            if (uACR && Array.isArray(rk)) {
                const ar = await tryAdminCatalogReadSwitch({ req, model: model as any, query: q, sort: aSort, skip, limit, populate, select, includeDeleted: incDel, transformResponse, userItems: rk, userTotal: total });
                if (ar) { const p = { items: ar.items, total: ar.total, page, limit }; if (ck) await setCache(ck, p, CACHE_TTLS.CATEGORIES); return sendPaginatedResponse(res, ar.items, ar.total, page, limit); }
            }
            if (!uACR && Array.isArray(rk)) void runCatalogShadowRead({ modelName: model.modelName, query: q, sort: aSort, skip, limit, userRows: rk as Record<string, unknown>[], requestPath: req.originalUrl || req.path, requestMethod: req.method });
            if (!Array.isArray(rk)) { if (ck) await setCache(ck, rk, CACHE_TTLS.CATEGORIES); return sendSuccessResponse(res, rk); }
            const p = { items: rk, total, page, limit };
            if (ck) await setCache(ck, p, CACHE_TTLS.CATEGORIES);
            return sendPaginatedResponse(res, rk, total, page, limit);
        }

        // Public view
        const rp = eq.page; const rl = eq.limit;
        const rsv = eq.q || eq.search; const rs2 = Array.isArray(rsv) ? rsv[0] : rsv;
        const rso = Array.isArray(eq.sort) ? eq.sort[0] : eq.sort;
        const pp = parseInt(String(rp || '1')); const pl2 = parseInt(String(rl || '100'));
        const page = Number.isFinite(pp) && pp > 0 ? pp : 1;
        const limit = Math.min(Math.max(Number.isFinite(pl2) && pl2 > 0 ? pl2 : 100, 1), 100);
        const st2 = Date.now(); const search = typeof rs2 === 'string' ? rs2.trim().slice(0, 120) : '';
        const sort = parseSortQuery(rso, defaultSort);
        if (search && limit <= 50 && shouldSuppressAutocomplete({ key: req.ip || 'public', search, limit })) return sendSuccessResponse(res, { items: [], total: 0 });
        const q: Record<string, unknown> = { ...publicQuery };
        if (search && searchFields.length > 0) q.$or = buildRegexSearchClauses(search, searchFields);
        if (typeof eq.listingType === 'string' && LISTING_TYPE_VALUES.includes(eq.listingType as ListingTypeValue)) q.listingType = eq.listingType;
        const ats = search && uACS ? await tryAtlasCatalogSearch({ model: model as any, query: q, search, searchFields, skip: (page - 1) * limit, limit }) : null;
        const efq = ats?.ids.length ? { ...q, _id: { $in: ats.ids } } : q;
        const fq = model.find(efq).skip(ats ? 0 : (page - 1) * limit).limit(limit).sort(ats ? {} : sort);
        if (populate) (fq as any).populate(populate);
        if (select) fq.select(select);
        const [items, total] = await Promise.all([fq, model.countDocuments(q)]);
        const ri = transformResponse ? await transformResponse(items as unknown[]) : items;
        const rk = search && Array.isArray(ri) ? rankCatalogSearchResults(ri, search, searchFields, ats?.scores, { autocomplete: limit <= 50, collapseVariants: limit <= 50 }) : ri;
        if (search) recordCatalogSearchTelemetry({ search, latencyMs: Date.now() - st2, resultCount: Array.isArray(rk) ? rk.length : 0, autocomplete: limit <= 50 });
        if (uACR && Array.isArray(rk)) {
            const ar = await tryAdminCatalogReadSwitch({ req, model: model as any, query: q, sort, skip: (page - 1) * limit, limit, populate, select, transformResponse, userItems: rk, userTotal: total });
            if (ar) { const p = { items: ar.items, total: ar.total }; if (ck) await setCache(ck, p, CACHE_TTLS.CATEGORIES); return sendSuccessResponse(res, p); }
        }
        if (!uACR && Array.isArray(rk)) void runCatalogShadowRead({ modelName: model.modelName, query: q, sort, skip: (page - 1) * limit, limit, userRows: rk as Record<string, unknown>[], requestPath: req.originalUrl || req.path, requestMethod: req.method });
        if (!Array.isArray(rk)) { if (ck) await setCache(ck, rk, CACHE_TTLS.CATEGORIES); return sendSuccessResponse(res, rk); }
        const p = { items: rk, total };
        if (ck) await setCache(ck, p, CACHE_TTLS.CATEGORIES);
        return sendSuccessResponse(res, p);
    } catch (error) { sendAdminError(req, res, error); }
}

import { Request, Response } from 'express';
import { IAuthUser } from '@esparex/core/types/auth';
import { sendErrorResponse } from './errorResponse';
import { getSingleParam } from './requestParams';
import { getListingRepository } from '@esparex/core/composition/listings';
import { ListingFilter } from '@esparex/core/domains/listings';

/**
 * Shared Controller Helpers
 * Used to reduce duplication in ownership and existence checks.
 */

export const getAndVerifyOwnedListing = async (
    req: Request,
    res: Response,
    options: {
        listingType?: string;
        errorMessage?: string;
        select?: string;
    } = {}
) => {
    const id = getSingleParam(req, res, 'id', { error: 'Invalid Listing ID' });
    if (!id) return null;

    const user = req.user as IAuthUser;
    if (!user) {
        sendErrorResponse(req, res, 401, 'Unauthorized');
        return null;
    }

    const filter: ListingFilter = {
        ids: [id],
        sellerId: user._id.toString(),
        isDeleted: false,
    };

    if (options.listingType) {
        filter.listingType = options.listingType as any;
    }

    const listing = await getListingRepository().findOne(filter);

    if (!listing) {
        sendErrorResponse(req, res, 404, options.errorMessage || 'Listing not found or access denied');
        return null;
    }

    return listing;
};

import mongoose from 'mongoose';
import User from '../../../../models/User';
import Ad from '../../../../models/Ad';
import CatalogRequest, { CatalogRequestStatusValue } from '../../../../models/CatalogRequest';
import CatalogModel from '../../../../models/Model';
import Report from '../../../../models/Report';
import Business from '../../../../models/Business';
import RevenueAnalytics from '../../../../models/RevenueAnalytics';
import ContactSubmission from '../../../../models/ContactSubmission';
import Location from '../../../../models/Location';
import LocationAnalytics from '../../../../models/LocationAnalytics';
import AdminLog from '../../../../models/AdminLog';
import { LISTING_STATUS, LISTING_TYPE, BUSINESS_STATUS, CATALOG_STATUS, REPORT_STATUS, USER_STATUS } from '@esparex/shared';
import { AdminDashboardRepositoryPort } from '../../../../domains/admin';

const CATALOG_REQUEST_PENDING_STATUS = 'pending' as CatalogRequestStatusValue;
const CATALOG_REQUEST_RESOLVED_STATUSES: CatalogRequestStatusValue[] = ['approved', 'rejected', 'merged', 'resolved'];
const CATALOG_REQUEST_MERGED_STATUS = 'merged' as CatalogRequestStatusValue;

export class MongoAdminDashboardRepositoryAdapter implements AdminDashboardRepositoryPort {
    public async getCatalogHealthMetrics(): Promise<any> {
        const [counts, resolutionAgg] = await Promise.all([
            CatalogRequest.aggregate([{ $match: { status: { $in: [CATALOG_REQUEST_PENDING_STATUS] } } }, { $group: { _id: '$status', count: { $sum: 1 } } }]),
            CatalogRequest.aggregate([
                { $match: { status: { $in: CATALOG_REQUEST_RESOLVED_STATUSES }, $or: [{ approvedAt: { $ne: null } }, { rejectedAt: { $ne: null } }] } },
                { $project: { resolutionTimeMs: { $subtract: [{ $ifNull: ['$approvedAt', '$rejectedAt'] }, '$createdAt'] } } },
                { $group: { _id: null, avgTimeMs: { $avg: '$resolutionTimeMs' } } }
            ]),
        ]);

        const findCount = (status: string) => counts.find((c: any) => c._id === status)?.count || 0;
        const pendingRequests = findCount(CATALOG_REQUEST_PENDING_STATUS);
        const mergedRequests = findCount(CATALOG_REQUEST_MERGED_STATUS);
        const avgTimeMs = resolutionAgg[0]?.avgTimeMs || 0;
        const averageResolutionHours = Number((avgTimeMs / (1000 * 60 * 60)).toFixed(1));

        return { pendingRequests, averageResolutionHours, mergedRequests };
    }

    public async getDashboardOverviewStats(publicAdFilter: any): Promise<any> {
        const [totalUsers, unifiedStats, pendingModels, openReports, pendingBusinesses, totalRevenueAgg, catalogHealth] = await Promise.all([
            User.countDocuments(),
            Ad.aggregate([
                {
                    $facet: {
                        totalAds: [{ $match: { listingType: LISTING_TYPE.AD, isDeleted: { $ne: true } } }, { $count: 'count' }],
                        activeAds: [{ $match: { listingType: LISTING_TYPE.AD, ...publicAdFilter } }, { $count: 'count' }],
                        pendingAds: [{ $match: { listingType: LISTING_TYPE.AD, status: LISTING_STATUS.PENDING, isDeleted: { $ne: true } } }, { $count: 'count' }],
                        totalServices: [{ $match: { listingType: LISTING_TYPE.SERVICE, isDeleted: { $ne: true } } }, { $count: 'count' }],
                        activeServices: [{ $match: { listingType: LISTING_TYPE.SERVICE, ...publicAdFilter } }, { $count: 'count' }],
                        pendingServices: [{ $match: { listingType: LISTING_TYPE.SERVICE, status: LISTING_STATUS.PENDING, isDeleted: { $ne: true } } }, { $count: 'count' }],
                        rejectedServices:[{ $match: { listingType: LISTING_TYPE.SERVICE, status: LISTING_STATUS.REJECTED, isDeleted: { $ne: true } } }, { $count: 'count' }],
                        totalSpareParts: [{ $match: { listingType: LISTING_TYPE.SPARE_PART, isDeleted: { $ne: true } } }, { $count: 'count' }],
                        activeSpareParts:[{ $match: { listingType: LISTING_TYPE.SPARE_PART, ...publicAdFilter } }, { $count: 'count' }],
                        pendingSpareParts:[{ $match: { listingType: LISTING_TYPE.SPARE_PART, status: LISTING_STATUS.PENDING, isDeleted: { $ne: true } } }, { $count: 'count' }]
                    }
                }
            ]),
            CatalogModel.countDocuments({ status: CATALOG_STATUS.PENDING }),
            Report.countDocuments({ status: REPORT_STATUS.OPEN }),
            Business.countDocuments({ status: BUSINESS_STATUS.PENDING }),
            RevenueAnalytics.aggregate([{ $group: { _id: null, total: { $sum: '$totalRevenue' } } }]),
            this.getCatalogHealthMetrics()
        ]);
        return { totalUsers, unifiedStats, pendingModels, openReports, pendingBusinesses, totalRevenueAgg, catalogHealth };
    }

    public async getDashboardCardStats(publicAdFilter: any): Promise<any> {
        const [totalUsers, adStats, totalReports, totalBusinesses, totalRevenueAgg, catalogHealth] = await Promise.all([
            User.countDocuments(),
            Ad.aggregate([
                {
                    $facet: {
                        live: [{ $match: { listingType: LISTING_TYPE.AD, ...publicAdFilter } }, { $count: 'count' }],
                        pending: [{ $match: { listingType: LISTING_TYPE.AD, status: LISTING_STATUS.PENDING } }, { $count: 'count' }]
                    }
                }
            ]),
            Report.countDocuments({ status: { $in: [REPORT_STATUS.OPEN, REPORT_STATUS.PENDING] } }),
            Business.countDocuments({ isDeleted: { $ne: true } }),
            RevenueAnalytics.aggregate([{ $group: { _id: null, total: { $sum: '$totalRevenue' } } }]),
            this.getCatalogHealthMetrics()
        ]);
        return { totalUsers, adStats, totalReports, totalBusinesses, totalRevenueAgg, catalogHealth };
    }

    public async getRecentAdminLogs(limit: number): Promise<any[]> {
        return AdminLog.find().sort({ createdAt: -1 }).limit(limit).populate('adminId', 'firstName lastName email').lean();
    }

    public async getContactSubmissionsPaginated(query: any, skip: number, limit: number): Promise<[any[], number]> {
        return Promise.all([
            ContactSubmission.find(query).skip(skip).limit(limit).sort({ createdAt: -1 }),
            ContactSubmission.countDocuments(query),
        ]);
    }

    public async updateContactSubmissionById(id: string, status: string): Promise<any> {
        const safeId = typeof id === 'string' ? id : String(id);
        // eslint-disable-next-line esparex/no-status-mutation-outside-status-mutation-service
        return ContactSubmission.findByIdAndUpdate(safeId, { $set: { status: typeof status === 'string' ? status : String(status) } }, { new: true });
    }

    public async getLocationAnalyticsRawData(params: any): Promise<any> {
        const { sixMonthsAgo, buildScopedLocationQuery, buildScopedAdQuery, buildScopedUserQuery, hotZoneQuery } = params;
        const [totalLocations, totalAds, totalUsers, adsByLocationAgg, monthlyAds, monthlyUsers, monthlyLocs, topHotZonesRaw] = await Promise.all([
            Location.countDocuments(buildScopedLocationQuery()),
            Ad.countDocuments(buildScopedAdQuery({ status: LISTING_STATUS.LIVE })),
            User.countDocuments(buildScopedUserQuery({ status: USER_STATUS.LIVE })),
            Ad.aggregate([
                { $match: { ...buildScopedAdQuery({ status: LISTING_STATUS.LIVE }), 'location.locationId': { $exists: true, $ne: null } } },
                { $group: { _id: '$location.locationId', adsCount: { $sum: 1 } } },
                { $sort: { adsCount: -1 } },
                { $limit: 250 }
            ]),
            Ad.aggregate([
                { $match: buildScopedAdQuery({ createdAt: { $gte: sixMonthsAgo } }) },
                { $group: { _id: { month: { $month: '$createdAt' }, year: { $year: '$createdAt' } }, count: { $sum: 1 } } }
            ]),
            User.aggregate([
                { $match: buildScopedUserQuery({ createdAt: { $gte: sixMonthsAgo } }) },
                { $group: { _id: { month: { $month: '$createdAt' }, year: { $year: '$createdAt' } }, count: { $sum: 1 } } }
            ]),
            Location.aggregate([
                { $match: buildScopedLocationQuery({ createdAt: { $gte: sixMonthsAgo } }) },
                { $group: { _id: { month: { $month: '$createdAt' }, year: { $year: '$createdAt' } }, count: { $sum: 1 } } }
            ]),
            LocationAnalytics.find(hotZoneQuery).select('locationId popularityScore searchCount adsCount').sort({ popularityScore: -1, searchCount: -1 }).limit(10).lean()
        ]);
        return { totalLocations, totalAds, totalUsers, adsByLocationAgg, monthlyAds, monthlyUsers, monthlyLocs, topHotZonesRaw };
    }

    public async getHotZoneLocations(locationIds: string[]): Promise<any[]> {
        if (locationIds.length === 0) return [];
        return Location.find({ _id: { $in: locationIds } }).select('_id name country level parentId path').lean();
    }

    public async getAnalyticsLocations(locationIds: string[]): Promise<any[]> {
        if (locationIds.length === 0) return [];
        return Location.find({ _id: { $in: locationIds } }).select('_id name country level parentId path').lean();
    }
}

