    async exists(id: string, tx?: unknown): Promise<boolean> {
        const query = SparePartMongoose.findById(id).select('_id').lean();
        if (tx) query.session(tx as any);
        const doc = await query.exec();
        return doc !== null;
    }

    async findByCategoryOrBrands(categoryId: string, brandIds: string[], tx?: unknown): Promise<SparePart[]> {
        const sparePartOrFilters: Array<Record<string, unknown>> = [{ categoryIds: categoryId }];
        if (brandIds.length > 0) {
            sparePartOrFilters.push({ brandId: { $in: brandIds } });
        }
        const query = SparePartMongoose.find({ $or: sparePartOrFilters }).lean<DbSparePart[]>();
        if (tx) query.session(tx as any);
        const docs = await query.exec();
        return docs.map(doc => this.toDomain(doc));
    }

    async create(data: Partial<SparePart> | any, tx?: unknown): Promise<SparePart> {
        const docs = await SparePartMongoose.create([data], { session: tx as any });
        return this.toDomain(docs[0] as unknown as DbSparePart);
    }

    async update(id: string, data: Partial<SparePart> | any, tx?: unknown): Promise<SparePart | null> {
        const query = SparePartMongoose.findByIdAndUpdate(id, data, { new: true }).lean<DbSparePart | null>();
        if (tx) query.session(tx as any);
        const doc = await query.exec();
        return doc ? this.toDomain(doc) : null;
    }

    async softDelete(id: string, tx?: unknown): Promise<boolean> {
        const update = { isDeleted: true, isActive: false, deletedAt: new Date() };
        const query = SparePartMongoose.findByIdAndUpdate(id, update, { new: true });
        if (tx) query.session(tx as any);
        const res = await query.exec();
        return !!res;
    }

    async softDeleteMany(sparePartIds: string[], tx?: unknown): Promise<number> {
        const update = { isDeleted: true, isActive: false, deletedAt: new Date() };
        const query = SparePartMongoose.updateMany({ _id: { $in: sparePartIds } }, { $set: update });
        if (tx) query.session(tx as any);
        const res = await query.exec();
        return res.modifiedCount;
    }

    async softDeleteByBrandId(brandId: string, tx?: unknown): Promise<number> {
        const update = { isDeleted: true, isActive: false, deletedAt: new Date() };
        const query = SparePartMongoose.updateMany({ brandId }, { $set: update });
        if (tx) query.session(tx as any);
        const res = await query.exec();
        return res.modifiedCount;
    }

    async softDeleteByModelIds(modelIds: string[], tx?: unknown): Promise<number> {
        const update = { isDeleted: true, isActive: false, deletedAt: new Date() };
        const query = SparePartMongoose.updateMany({ modelId: { $in: modelIds } }, { $set: update });
        if (tx) query.session(tx as any);
        const res = await query.exec();
        return res.modifiedCount;
    }

    async updateCategoryIds(sparePartId: string, categoryIds: string[], tx?: unknown): Promise<boolean> {
        const query = SparePartMongoose.updateOne(
            { _id: sparePartId },
            { $set: { categoryIds } }
        );
        if (tx) query.session(tx as any);
        const res = await query.exec();
        return res.modifiedCount > 0;
    }

    async clearModelReferences(modelId: string, tx?: unknown): Promise<number> {
        const query = SparePartMongoose.updateMany(
            { modelId },
            { $set: { modelId: null, isActive: false } }
        );
        if (tx) query.session(tx as any);
        const res = await query.exec();
        return res.modifiedCount;
    }
}

import { Types } from 'mongoose';
import { Conversation } from '../../../../models/Conversation';
import { ChatReport } from '../../../../models/ChatReport';
import { ChatMessage } from '../../../../models/ChatMessage';
import Ad from '../../../../models/Ad';
import BlockedUser from '../../../../models/BlockedUser';
import { ChatRepositoryPort } from '../../../../domains/chat';
import { PAGE_SIZE_INBOX } from '../../../../services/chat/ChatUtils';
import { PAGE_SIZE_MESSAGES } from '../../../../services/chat/ChatUtils';

export class MongoChatRepositoryAdapter implements ChatRepositoryPort {
    public async findConversationById(conversationId: string): Promise<any> {
        return await Conversation.findById(conversationId).lean();
    }
    public async createReport(data: any): Promise<any> {
        return await ChatReport.create({
            conversationId: new Types.ObjectId(data.conversationId),
            reporterId: new Types.ObjectId(data.reporterId),
            reportedUserId: new Types.ObjectId(data.reportedUserId),
            messageId: data.messageId ? new Types.ObjectId(data.messageId) : undefined,
            reason: data.reason,
            description: data.description,
        });
    }
    public async getAdChatInfo(adId: string): Promise<any> {
        return await Ad.findById(adId).select('sellerId status isDeleted isChatLocked').lean();
    }
    public async checkBlockRelationship(buyerId: string, sellerId: string): Promise<boolean> {
        const exists = await BlockedUser.exists({
            $or: [
                { blockerId: new Types.ObjectId(buyerId), blockedId: new Types.ObjectId(sellerId) },
                { blockerId: new Types.ObjectId(sellerId), blockedId: new Types.ObjectId(buyerId) },
            ],
        });
        return !!exists;
    }
    public async findExistingConversation(adId: string, buyerId: string): Promise<any> {
        return await Conversation.findOne({ adId, buyerId }).lean();
    }
    public async removeUserFromDeleted(conversationId: string, userId: string): Promise<void> {
        await Conversation.updateOne({ _id: conversationId }, { $pull: { deletedFor: new Types.ObjectId(userId) } });
    }
    public async createConversation(data: any): Promise<any> {
        return await Conversation.create({
            adId: new Types.ObjectId(data.adId),
            buyerId: new Types.ObjectId(data.buyerId),
            sellerId: new Types.ObjectId(data.sellerId),
            isAdClosed: data.isAdClosed,
        });
    }
    public async listConversations(userId: string, before?: string, view: 'active' | 'archived' = 'active'): Promise<any[]> {
        const query: Record<string, unknown> = { $or: [{ buyerId: userId }, { sellerId: userId }] };
        query.deletedFor = view === 'archived' ? userId : { $ne: userId };
        if (before) query.lastMessageAt = { $lt: new Date(before) };
        return await Conversation.find(query).sort({ lastMessageAt: -1 }).limit(PAGE_SIZE_INBOX).populate('adId', 'title images price status listingType seoSlug isDeleted isChatLocked').populate('buyerId', 'name avatar').populate('sellerId', 'name avatar').lean();
    }
    public async getPopulatedConversation(conversationId: string, userId: string): Promise<any> {
        return await Conversation.findOne({ _id: conversationId, $or: [{ buyerId: userId }, { sellerId: userId }] }).populate('adId', 'title images price status listingType seoSlug isDeleted isChatLocked').populate('buyerId', 'name avatar').populate('sellerId', 'name avatar').lean();
    }
    public async blockConversation(conversationId: string, userId: string): Promise<void> {
        await Conversation.updateOne({ _id: conversationId }, { $set: { isBlocked: true, blockedBy: new Types.ObjectId(userId) } });
    }
    public async addUserToDeleted(conversationId: string, userId: string): Promise<void> {
        await Conversation.updateOne({ _id: conversationId }, { $addToSet: { deletedFor: new Types.ObjectId(userId) } });
    }
    public async findMessages(conversationId: string, userId: string, before?: string, after?: string): Promise<{ msgs: any[], nextCursor?: string }> {
        const baseFilter: Record<string, unknown> = { conversationId, deletedFor: { $ne: new Types.ObjectId(userId) } };
        if (after) {
            const msgs = await ChatMessage.find({ ...baseFilter, createdAt: { $gt: new Date(after) } }).sort({ createdAt: 1 }).lean();
            return { msgs, nextCursor: undefined };
        }
        if (before) baseFilter.createdAt = { $lt: new Date(before) };
        const msgs = await ChatMessage.find(baseFilter).sort({ createdAt: -1 }).limit(PAGE_SIZE_MESSAGES).lean();
        const lastMsg = msgs[msgs.length - 1];
        const nextCursor = msgs.length === PAGE_SIZE_MESSAGES && lastMsg?.createdAt ? lastMsg.createdAt.toISOString() : undefined;
        return { msgs: msgs.reverse(), nextCursor };
    }
    public async updateConversationAdClosedStatus(conversationId: string, isAdClosed: boolean): Promise<void> {
        await Conversation.updateOne({ _id: conversationId }, { $set: { isAdClosed } });
    }
    public async createMessage(data: any): Promise<any> {
        return await ChatMessage.create({
            conversationId: new Types.ObjectId(data.conversationId),
            senderId: new Types.ObjectId(data.senderId),
            receiverId: new Types.ObjectId(data.receiverId),
            text: data.text,
            attachments: data.attachments,
            riskScore: data.riskScore,
            badWordDetected: data.badWordDetected,
        });
    }
    public async updateConversationPreview(conversationId: string, unreadField: string, senderId: string, preview: string, messageDate: Date): Promise<void> {
        await Conversation.updateOne({ _id: conversationId }, { $set: { lastMessage: preview, lastMessageAt: messageDate }, $inc: { [unreadField]: 1 }, $pull: { deletedFor: new Types.ObjectId(senderId) } });
    }
    public async createSystemMessage(data: any): Promise<void> {
        await ChatMessage.create({
            conversationId: new Types.ObjectId(data.conversationId),
            senderId: new Types.ObjectId(data.senderId),
            receiverId: new Types.ObjectId(data.receiverId),
            text: data.text,
            isSystemMessage: true,
            riskScore: 0,
        });
    }
    public async markMessagesRead(conversationId: string, userId: string): Promise<void> {
        await ChatMessage.updateMany({ conversationId, receiverId: new Types.ObjectId(userId), readAt: null }, { $set: { readAt: new Date() } });
    }
    public async resetUnreadCount(conversationId: string, unreadField: string): Promise<void> {
        await Conversation.updateOne({ _id: conversationId }, { $set: { [unreadField]: 0 } });
    }
}

import mongoose from 'mongoose';
import User from '../../../../models/User';
import Business from '../../../../models/Business';
import BlockedUser from '../../../../models/BlockedUser';
import { UserRepositoryPort, UserProfileData } from '../../../../domains/identity';
import { normalizeRole } from '../../../../utils/roleNormalization';

export class MongoUserRepositoryAdapter implements UserRepositoryPort {
    public async findActiveProfileById(id: string): Promise<UserProfileData | null> {
        if (!mongoose.Types.ObjectId.isValid(id)) return null;
        return await User.findOne({ _id: new mongoose.Types.ObjectId(id), status: { $ne: 'deleted' } })
            .select('name avatar createdAt isVerified location.city location.state location.country')
            .lean<UserProfileData | null>();
    }
    public async updateUser(id: string, updates: any): Promise<any> {
        const safeId = typeof id === 'string' ? id : String(id);
        const rawUpdates = (updates && typeof updates === 'object' && !Array.isArray(updates)) ? updates : {};
        const sanitizedUpdates = Object.fromEntries(
            Object.entries(rawUpdates).filter(([key]) => !key.startsWith('$') && !key.includes('.'))
        );
        return await User.findByIdAndUpdate(
            safeId,
            { $set: sanitizedUpdates },
            { new: true, runValidators: true }
        ).select('-password');
    }
    public async removeUserFcmToken(userId: any, token: string): Promise<void> {
        const safeId = typeof userId === 'string' ? userId : String(userId ?? '');
        await User.findByIdAndUpdate(safeId, { $pull: { fcmTokens: { token: String(token ?? '') } } });
    }
    public async getUserById(userId: string): Promise<any> {
        const safeId = typeof userId === 'string' ? userId : String(userId);
        const user = await User.findById(safeId).lean() as any;
        if (user && user.role) user.role = normalizeRole(user.role);
        return user;
    }
    public async getUserWithBusiness(userId: string): Promise<{ user: any; business: any }> {
        const safeId = typeof userId === 'string' ? userId : String(userId);
        const [user, business] = await Promise.all([
            User.findById(safeId).select('-password -salt').lean() as any,
            Business.findOne({ userId: String(userId) }).lean(),
        ]);
        if (user && user.role) user.role = normalizeRole(user.role);
        return { user, business };
    }
    public async getUserPhoneVerification(userId: string): Promise<any> {
        const safeId = typeof userId === 'string' ? userId : String(userId);
        return User.findById(safeId).select('isPhoneVerified mobile').lean();
    }
    public async findUserByEmail(email: string): Promise<any> {
        const safeEmail = typeof email === 'string' ? email : String(email ?? '');
        return User.findOne({ email: safeEmail });
    }
    public async getUserAvatarById(userId: string): Promise<any> {
        const safeId = typeof userId === 'string' ? userId : String(userId);
        return User.findById(safeId).select('avatar').lean();
    }
    public async checkUserExistsById(userId: string): Promise<boolean> {
        const exists = await User.exists({ _id: new mongoose.Types.ObjectId(userId), isDeleted: { $ne: true } });
        return !!exists;
    }
    public async blockUserById(blockerId: string, blockedUserId: string): Promise<any> {
        return BlockedUser.updateOne(
            { blockerId: new mongoose.Types.ObjectId(blockerId), blockedId: new mongoose.Types.ObjectId(blockedUserId) },
            { $setOnInsert: { blockerId: new mongoose.Types.ObjectId(blockerId), blockedId: new mongoose.Types.ObjectId(blockedUserId) } },
            { upsert: true }
        );
    }
    public async unblockUserById(blockerId: string, blockedUserId: string): Promise<any> {
        return BlockedUser.deleteOne({ blockerId: new mongoose.Types.ObjectId(blockerId), blockedId: new mongoose.Types.ObjectId(blockedUserId) });
    }
}

import mongoose from 'mongoose';
import AdModel from '../../../../models/Ad';
import { LISTING_STATUS, LISTING_TYPE, SERVICE_STATUS, INVENTORY_STATUS } from '@esparex/shared';

import {
    type ActiveListingCountFilter,
    type Listing,
    type ListingFilter,
    type ListingUpdate,
    ListingRepositoryPort,
} from '../../../../domains/listings';

// ─── Domain mapper ──────────────────────────────────────────────────────────

type DbListing = {
    _id: unknown;
    title: string;
    description: string;
    price: number;
    listingType: string;
    sellerId: unknown;
    status: string;
    categoryId: unknown;
    brandId?: unknown;
    modelId?: unknown;
    locationPath?: unknown[];
    images?: string[];
    seoSlug?: string;
    location?: {
        city?: string;
        state?: string;
        country?: string;
        display?: string;
        coordinates?: { coordinates?: [number, number] };
        locationId?: unknown;
    };
    isDeleted?: boolean;
    isSold?: boolean;
    moderationStatus?: string;
    fraudScore?: number;
    sellerTrustSnapshot?: number;
    isSpotlight?: boolean;
    spotlightExpiresAt?: Date;
    expiresAt?: Date;
    views?: {
        total?: number;
        unique?: number;
        favorites?: number;
        lastViewedAt?: Date;
    };
    createdAt: Date;
    updatedAt: Date;
};

function toDomain(doc: DbListing): Listing {
    return {
        id: String(doc._id),
        title: doc.title,
        description: doc.description,
        price: doc.price,
        listingType: doc.listingType as Listing['listingType'],
        sellerId: String(doc.sellerId),
        status: doc.status as Listing['status'],
        categoryId: String(doc.categoryId),
        brandId: doc.brandId ? String(doc.brandId) : undefined,
        modelId: doc.modelId ? String(doc.modelId) : undefined,
        locationPath: Array.isArray(doc.locationPath) ? doc.locationPath.map((id) => String(id)) : undefined,
        images: doc.images ?? [],
        seoSlug: doc.seoSlug,
        location: {
            coordinates: doc.location?.coordinates?.coordinates ?? [0, 0],
            city: doc.location?.city,
            state: doc.location?.state,
            country: doc.location?.country,
            display: doc.location?.display,
            locationId: doc.location?.locationId ? String(doc.location.locationId) : undefined,
        },
        isDeleted: doc.isDeleted ?? false,
        isSold: doc.isSold ?? false,
        moderationStatus: doc.moderationStatus,
        fraudScore: doc.fraudScore,
        sellerTrustSnapshot: doc.sellerTrustSnapshot,
        isSpotlight: doc.isSpotlight,
        spotlightExpiresAt: doc.spotlightExpiresAt,
        expiresAt: doc.expiresAt,
        views: doc.views ? {
            total: doc.views.total,
            unique: doc.views.unique,
            favorites: doc.views.favorites,
            lastViewedAt: doc.views.lastViewedAt,
        } : undefined,
        createdAt: doc.createdAt,
        updatedAt: doc.updatedAt,
    };
}

// ─── Filter builder ─────────────────────────────────────────────────────────

function toMongoId(id: unknown): unknown {
    if (typeof id === 'string' && mongoose.Types.ObjectId.isValid(id)) {
        return new mongoose.Types.ObjectId(id);
    }
    if (typeof id === 'string' || typeof id === 'number') {
        return id;
    }
    return String(id ?? '');
}

function buildMongoFilter(filter: ListingFilter): Record<string, unknown> {
    const mongoFilter: Record<string, unknown> = {};

    if (filter.status) {
        mongoFilter.status = Array.isArray(filter.status) ? { $in: filter.status } : filter.status;
    }
    if (filter.listingType) mongoFilter.listingType = filter.listingType;
    if (filter.sellerId) mongoFilter.sellerId = typeof filter.sellerId === 'object' ? filter.sellerId : toMongoId(filter.sellerId);
    if (filter.categoryId) mongoFilter.categoryId = typeof filter.categoryId === 'object' ? filter.categoryId : toMongoId(filter.categoryId);
    if (filter.brandId) mongoFilter.brandId = typeof filter.brandId === 'object' ? filter.brandId : toMongoId(filter.brandId);
    if (filter.modelId) mongoFilter.modelId = typeof filter.modelId === 'object' ? filter.modelId : toMongoId(filter.modelId);
    if (filter.isDeleted !== undefined) {
        if (typeof filter.isDeleted === 'object' && filter.isDeleted !== null) {
            mongoFilter.isDeleted = filter.isDeleted;
        } else {
            mongoFilter.isDeleted = filter.isDeleted;
        }
    }
    if (filter.isSold !== undefined) mongoFilter.isSold = filter.isSold;
    if (filter.ids && filter.ids.length > 0) {
        mongoFilter._id = { $in: filter.ids.map(id => toMongoId(id)) };
    }
    if (filter.idsNotIn && filter.idsNotIn.length > 0) {
        mongoFilter._id = { ...(mongoFilter._id as Record<string, unknown> || {}), $nin: filter.idsNotIn.map(id => toMongoId(id)) };
    }
    if (filter.excludeStatus && filter.excludeStatus.length > 0) {
        mongoFilter.status = { ...(mongoFilter.status as Record<string, unknown> || {}), $nin: filter.excludeStatus };
    }
    if (filter.locationId) {
        mongoFilter['location.locationId'] = toMongoId(filter.locationId);
    }
    if (filter.locationCity) {
        mongoFilter['location.city'] = filter.locationCity;
    }
    if (filter.locationState) {
        mongoFilter['location.state'] = filter.locationState;
    }
    if (filter.locationPath) {
        mongoFilter.locationPath = toMongoId(filter.locationPath);
    }
    if (filter.isSpotlight !== undefined) mongoFilter.isSpotlight = filter.isSpotlight;
    if (filter.spotlightExpiresAt) {
        mongoFilter.spotlightExpiresAt = filter.spotlightExpiresAt;
    }
    if (filter.expiresAt) mongoFilter.expiresAt = filter.expiresAt;
    if (filter.sparePartIds) {
        mongoFilter.sparePartIds = toMongoId(filter.sparePartIds);
    }
    if (filter.favoritesGreaterThan !== undefined) {
        mongoFilter['views.favorites'] = { $gt: filter.favoritesGreaterThan };
    }
    if (filter.moderationStatus) {
        mongoFilter.moderationStatus = filter.moderationStatus;
    }
    
    // Cursor pagination mapping
    if (filter.cursorCreatedAt) {
        if (filter.cursorId) {
            mongoFilter.$or = [
                ...(mongoFilter.$or as Record<string, unknown>[] || []),
                { createdAt: { $lt: filter.cursorCreatedAt } },
                {
                    createdAt: filter.cursorCreatedAt,
                    _id: { $lt: toMongoId(filter.cursorId) }
                }
            ];
        } else {
            mongoFilter.createdAt = { $lt: filter.cursorCreatedAt };
        }
    }

    if (filter.$or && !filter.cursorCreatedAt) {
        mongoFilter.$or = filter.$or;
    } else if (filter.$or && filter.cursorCreatedAt) {
        // If we already set $or from cursor, merge any existing $or using $and
        const existingOr = mongoFilter.$or as Record<string, unknown>[];
        delete mongoFilter.$or;
        mongoFilter.$and = [
            { $or: filter.$or },
            { $or: existingOr }
        ];
    }

    return mongoFilter;
}

async function resolveMongoQuery<T>(q: unknown): Promise<T> {
    let curr = q as any;
    if (curr && typeof curr.select === 'function') curr = curr.select();
    if (curr && typeof curr.lean === 'function') curr = curr.lean();
    if (curr && typeof curr.exec === 'function') curr = await curr.exec();
    else curr = await curr;
    return curr as T;
}

// ─── Adapter implementation ─────────────────────────────────────────────────

export class MongoListingRepositoryAdapter implements ListingRepositoryPort {
    async countActiveBySeller(filter: ActiveListingCountFilter): Promise<number> {
        const { sellerId, listingType, session } = filter;

        if (listingType === LISTING_TYPE.SERVICE) {
            let query = AdModel.countDocuments({
                sellerId,
                listingType: LISTING_TYPE.SERVICE,
                status: { $in: [SERVICE_STATUS.LIVE, SERVICE_STATUS.PENDING] },
                isDeleted: { $ne: true },
            });
            if (session) query = query.session(session as Parameters<typeof query.session>[0]);
            return query;
        }

        if (listingType === LISTING_TYPE.SPARE_PART) {
            let query = AdModel.countDocuments({
                sellerId,
                listingType: LISTING_TYPE.SPARE_PART,
                status: { $in: [INVENTORY_STATUS.LIVE, INVENTORY_STATUS.PENDING] },
                isDeleted: { $ne: true },
            });
            if (session) query = query.session(session as Parameters<typeof query.session>[0]);
            return query;
        }

        let query = AdModel.countDocuments({
            sellerId,
            listingType: LISTING_TYPE.AD,
            status: { $in: [LISTING_STATUS.LIVE, LISTING_STATUS.PENDING] },
            isDeleted: { $ne: true },
        });
        if (session) query = query.session(session as Parameters<typeof query.session>[0]);
        return query;
    }

    async count(filter: ListingFilter): Promise<number> {
        return AdModel.countDocuments(buildMongoFilter(filter));
    }

    async findWithinRadius(
        lng: number,
        lat: number,
        radiusKm: number,
        filter: ListingFilter,
        sort?: Record<string, 1 | -1>,
        limit?: number,
        skip?: number
    ): Promise<Listing[]> {
        const mongoFilter = buildMongoFilter(filter);
        
        mongoFilter['location.coordinates'] = {
            $near: {
                $geometry: {
                    type: 'Point',
                    coordinates: [lng, lat]
                },
                $maxDistance: radiusKm * 1000
            }
        };

        let q = AdModel.find(mongoFilter);
        if (sort) {
            q = q.sort(sort);
        }
        if (skip !== undefined) q = q.skip(skip);
        if (limit !== undefined) q = q.limit(limit);
        if (filter.session) q = q.session(filter.session as any);

        const docs = await q.lean<DbListing[]>();
        return (docs || []).map(toDomain);
    }

    async findById(id: string): Promise<Listing | null> {
        const safeId = typeof id === 'string' && mongoose.Types.ObjectId.isValid(id) ? new mongoose.Types.ObjectId(id) : String(id);
        const doc = await resolveMongoQuery<DbListing | null>(AdModel.findById(safeId));
        return doc ? toDomain(doc) : null;
    }

    async find(filter: ListingFilter): Promise<readonly Listing[]> {
        const rawDocs = await resolveMongoQuery<DbListing[]>(AdModel.find(buildMongoFilter(filter)));
        const docs = Array.isArray(rawDocs) ? rawDocs : [];
        return docs.map(toDomain);
    }

    async findWithLimit(filter: ListingFilter, sort?: Record<string, 1 | -1>, limit?: number, skip?: number): Promise<readonly Listing[]> {
        const q = AdModel.find(buildMongoFilter(filter));
        if (sort && typeof (q as any)?.sort === 'function') (q as any).sort(sort);
        if (skip !== undefined && typeof (q as any)?.skip === 'function') (q as any).skip(skip);
        if (limit !== undefined && typeof (q as any)?.limit === 'function') (q as any).limit(limit);
        const rawDocs = await resolveMongoQuery<DbListing[]>(q);
        const docs = Array.isArray(rawDocs) ? rawDocs : [];
        return docs.map(toDomain);
    }

    async findOne(filter: ListingFilter): Promise<Listing | null> {
        const doc = await resolveMongoQuery<DbListing | null>(AdModel.findOne(buildMongoFilter(filter)));
        return doc ? toDomain(doc) : null;
    }

    async insert(listing: ListingUpdate, session?: unknown): Promise<Listing> {
        const docs = await AdModel.create([listing as Record<string, unknown>], { session: session as any });
        return toDomain(docs[0] as unknown as DbListing);
    }

    async updateOne(id: string, update: ListingUpdate, session?: unknown): Promise<Listing | null> {
        const safeId = typeof id === 'string' && mongoose.Types.ObjectId.isValid(id) ? new mongoose.Types.ObjectId(id) : String(id);
        const updateDoc = Object.keys(update).some(k => k.startsWith('$')) ? update : { $set: update };
        const query = AdModel.findByIdAndUpdate(safeId, updateDoc, { new: true, runValidators: true, session: session as any });
        const doc = await resolveMongoQuery<DbListing | null>(query);
        return doc ? toDomain(doc) : null;
    }

    async updateOneByFilter(filter: ListingFilter, update: ListingUpdate, session?: unknown): Promise<Listing | null> {
        const updateDoc = Object.keys(update).some(k => k.startsWith('$')) ? update : { $set: update };
        const filterDoc = buildMongoFilter(filter);
        const query = AdModel.findOneAndUpdate(
            filterDoc._id ? { ...filterDoc, _id: (filterDoc._id as any).$in?.[0] ?? filterDoc._id } : filterDoc,
            updateDoc,
            { new: true, runValidators: true, session: session as any }
        );
        const doc = await resolveMongoQuery<DbListing | null>(query);
        return doc ? toDomain(doc) : null;
    }

    async updateMany(filter: ListingFilter, update: ListingUpdate, session?: unknown): Promise<number> {
        const updateDoc = Object.keys(update).some(k => k.startsWith('$')) ? update : { $set: update };
        const filterDoc = buildMongoFilter(filter);
        if (typeof AdModel.updateMany === 'function') {
            const result = await resolveMongoQuery<{ modifiedCount?: number } | null>(
                AdModel.updateMany(filterDoc, updateDoc).session(session as any)
            );
            return result?.modifiedCount ?? 0;
        }
        if (typeof AdModel.findOneAndUpdate === 'function') {
            await resolveMongoQuery(
                AdModel.findOneAndUpdate(
                    filterDoc._id ? { ...filterDoc, _id: (filterDoc._id as any).$in?.[0] ?? filterDoc._id } : filterDoc,
                    updateDoc,
                    { runValidators: true, session: session as any }
                )
            );
            return 1;
        }
        return 0;
    }
}

