type ScopedQueryBuilder = (extra?: Record<string, unknown>) => Record<string, unknown>;

export const getLocationAnalyticsRawData = async (params: {
    sixMonthsAgo: Date;
    buildScopedLocationQuery: ScopedQueryBuilder;
    buildScopedAdQuery: ScopedQueryBuilder;
    buildScopedUserQuery: ScopedQueryBuilder;
    hotZoneQuery: Record<string, unknown>;
}) => {
    return adminDashboardRepository.getLocationAnalyticsRawData(params);
};

export const getHotZoneLocations = async (locationIds: string[]) => {
    return adminDashboardRepository.getHotZoneLocations(locationIds);
};

export const getAnalyticsLocations = async (locationIds: string[]) => {
    return adminDashboardRepository.getAnalyticsLocations(locationIds);
};

export const adminGetLocationAnalyticsData = async (reqQuery: Record<string, unknown>) => {
    const sixMonthsAgo = new Date();
    sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);

    const cityFilter = typeof reqQuery.city === 'string' ? reqQuery.city.trim() : '';
    const districtFilter = typeof reqQuery.district === 'string' ? reqQuery.district.trim() : '';
    const stateFilter = typeof reqQuery.state === 'string' ? reqQuery.state.trim() : '';
    const countryFilter = typeof reqQuery.country === 'string' ? reqQuery.country.trim() : '';

    const scope = await resolveLocationScope({
        city: cityFilter || undefined,
        district: districtFilter || undefined,
        state: stateFilter && stateFilter !== 'all' ? stateFilter : undefined,
        country: countryFilter && countryFilter !== 'all' ? countryFilter : undefined,
    });
    const locationScopeIds = scope.locationIds;

    const buildScopedLocationQuery = (extra: Record<string, unknown> = {}) => {
        if (locationScopeIds === undefined || locationScopeIds === null) {
            return { isActive: true, ...extra };
        }
        if (locationScopeIds.length === 0) {
            return { _id: { $in: [] }, ...extra };
        }
        return {
            isActive: true,
            ...extra,
            $or: [
                { _id: { $in: locationScopeIds } },
                { path: { $in: locationScopeIds } },
            ],
        };
    };

    const buildScopedAdQuery = (extra: Record<string, unknown> = {}) => {
        if (locationScopeIds === undefined || locationScopeIds === null) {
            return extra;
        }
        if (locationScopeIds.length === 0) {
            return { _id: { $in: [] }, ...extra };
        }
        return {
            ...extra,
            $or: [
                { 'location.locationId': { $in: locationScopeIds } },
                { locationPath: { $in: locationScopeIds } },
            ],
        };
    };

    const buildScopedUserQuery = (extra: Record<string, unknown> = {}) => {
        if (locationScopeIds === undefined || locationScopeIds === null) {
            return extra;
        }
        if (locationScopeIds.length === 0) {
            return { _id: { $in: [] }, ...extra };
        }

        const orQuery: Array<Record<string, unknown>> = [
            { locationId: { $in: locationScopeIds } },
            { 'location.locationId': { $in: locationScopeIds } },
        ];

        if (cityFilter) {
            orQuery.push({ 'location.city': new RegExp(`^${escapeRegExp(cityFilter)}$`, 'i') });
        }
        if (stateFilter && stateFilter !== 'all') {
            orQuery.push({ 'location.state': new RegExp(`^${escapeRegExp(stateFilter)}$`, 'i') });
        }

        return {
            ...extra,
            $or: orQuery,
        };
    };

    if (Array.isArray(locationScopeIds) && locationScopeIds.length === 0) {
        return {
            totalLocations: 0,
            totalAds: 0,
            totalUsers: 0,
            topCities: [],
            adsByState: [],
            hotZones: [],
            monthlyTrends: [],
        };
    }

    const hotZoneQuery: Record<string, unknown> = {
        isHotZone: true,
        ...(Array.isArray(locationScopeIds) ? { locationId: { $in: locationScopeIds } } : {}),
    };

    const {
        totalLocations,
        totalAds,
        totalUsers,
        adsByLocationAgg,
        monthlyAds,
        monthlyUsers,
        monthlyLocs,
        topHotZonesRaw,
    } = await getLocationAnalyticsRawData({
        sixMonthsAgo,
        buildScopedLocationQuery,
        buildScopedAdQuery,
        buildScopedUserQuery,
        hotZoneQuery,
    });

    const hotZoneLocationIds = topHotZonesRaw.map((zone: any) => zone.locationId);
    const hotZoneLocations = await getHotZoneLocations(hotZoneLocationIds.map(String));
    const hotZoneHierarchyMap = await loadHierarchyMapForLocations(hotZoneLocations);
    const hotZoneLocationMap = new Map(
        hotZoneLocations.map((location: any) => [String(location._id), location])
    );
    const hotZones = topHotZonesRaw.map((zone: any) => {
        const location = hotZoneLocationMap.get(String(zone.locationId));
        const summary = location ? buildLocationSummary(location, hotZoneHierarchyMap) : undefined;
        return {
            _id: String(zone._id),
            city: summary?.city ?? '',
            state: summary?.state ?? '',
            popularityScore: zone.popularityScore ?? 0,
            isHotZone: true,
        };
    });

    // Format Monthly Trends
    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    const trends = [];
    for (let i = 0; i < 6; i++) {
        const d = new Date();
        d.setMonth(d.getMonth() - (5 - i));
        const m = d.getMonth() + 1;
        const y = d.getFullYear();

        const ads = monthlyAds.find((a: any) => a._id.month === m && a._id.year === y)?.count || 0;
        const users = monthlyUsers.find((u: any) => u._id.month === m && u._id.year === y)?.count || 0;
        const locs = monthlyLocs.find((l: any) => l._id.month === m && l._id.year === y)?.count || 0;

        trends.push({
            month: monthNames[m - 1],
            adsPosted: ads,
            activeUsers: users,
            newLocations: locs
        });
    }

    const adsByLocationIds = adsByLocationAgg
        .map((entry: any) => entry?._id as string | undefined)
        .filter((value: string | undefined): value is string => Boolean(value))
        .map((value: string) => String(value));
    const analyticsLocations = await getAnalyticsLocations(adsByLocationIds);
    const analyticsHierarchyMap = await loadHierarchyMapForLocations(analyticsLocations);
    const analyticsLocationMap = new Map(
        analyticsLocations.map((location: any) => [String(location._id), location])
    );

    const topCityMap = new Map<string, { _id: string; city: string; state: string; adsCount: number }>();
    const adsByStateMap = new Map<string, { _id: string; count: number }>();

    for (const entry of adsByLocationAgg as any[]) {
        const location = analyticsLocationMap.get(String(entry._id));
        if (!location) continue;

        const summary = buildLocationSummary(location, analyticsHierarchyMap);
        const count = typeof entry?.adsCount === 'number' ? entry.adsCount : Number(entry?.adsCount || 0);

        if (summary.city && summary.state && summary.level !== 'state' && summary.level !== 'country') {
            const cityKey = `${summary.city.toLowerCase()}::${summary.state.toLowerCase()}`;
            const existingCity = topCityMap.get(cityKey);
            if (existingCity) {
                existingCity.adsCount += count;
            } else {
                topCityMap.set(cityKey, {
                    _id: cityKey,
                    city: summary.city,
                    state: summary.state,
                    adsCount: count,
                });
            }
        }

        const stateLabel = normalizeStateLabel(summary.state);
        const stateKey = stateLabel.toLowerCase();
        const existing = adsByStateMap.get(stateKey);
        if (existing) {
            existing.count += count;
            continue;
        }
        adsByStateMap.set(stateKey, { _id: stateLabel, count });
    }
    const topCities = Array.from(topCityMap.values())
        .sort((a, b) => b.adsCount - a.adsCount)
        .slice(0, 10);
    const adsByState = Array.from(adsByStateMap.values()).sort((a, b) => b.count - a.count);

    return {
        totalLocations,
        totalAds,
        totalUsers,
        topCities,
        adsByState,
        hotZones,
        monthlyTrends: trends.map(t => ({
            month: t.month,
            ads: t.adsPosted,
            users: t.activeUsers,
        })),
    };
};

import mongoose from 'mongoose';
import SavedAd from '../models/SavedAd';
import { getListingRepository } from '../composition/listings';
import { hydrateAdMetadata, type HydratedAd } from './ad/AdAggregationService';
import { sanitizePersistedImageUrls } from '../utils/s3';
import { serializeDoc } from '../utils/serialize';
import { recordAdAnalyticsEvent } from './TrendingService';

export const getSavedAds = async (userId: string, page: number, limit: number) => {
    const skip = (page - 1) * limit;

    // Single $facet aggregation: replaces two separate queries (find + countDocuments)
    // that previously ran in parallel, each costing 1500ms+ on cold start.
    const [result] = await SavedAd.aggregate<{
        data: { adId: mongoose.Types.ObjectId; createdAt: Date }[];
        total: { count: number }[];
    }>([
        { $match: { userId: new mongoose.Types.ObjectId(userId) } },
        {
            $facet: {
                data: [
                    { $sort: { createdAt: -1 } },
                    { $skip: skip },
                    { $limit: limit },
                    { $project: { adId: 1, createdAt: 1 } },
                ],
                total: [{ $count: 'count' }],
            },
        },
    ]);

    const saved = result?.data ?? [];
    const total = result?.total?.[0]?.count ?? 0;

    if (saved.length === 0) {
        return { data: [], total };
    }

    const adIds = saved.filter((s) => s.adId).map((s) => s.adId);
    const listings = await getListingRepository().find({ ids: adIds.map((id) => id.toString()) });
    const rawAds: HydratedAd[] = listings.map((l) => ({
        ...l,
        _id: new mongoose.Types.ObjectId(l.id),
    } as unknown as HydratedAd));

    await hydrateAdMetadata(rawAds);

    const adMap = new Map(
        rawAds
            .map((ad) => {
                const adKey = ad._id ? ad._id.toString() : ad.id;
                return adKey ? [adKey, ad] as const : null;
            })
            .filter((entry): entry is readonly [string, HydratedAd] => Boolean(entry))
    );

    const data = saved
        .map((s) => {
            const adIdStr = s.adId?.toString();
            const ad = adIdStr ? adMap.get(adIdStr) : null;
            if (!ad) return null;

            const serialized = serializeDoc(ad) as Record<string, unknown>;
            const rawImages = Array.isArray(serialized.images) ? serialized.images : [];

            return {
                ...serialized,
                images: sanitizePersistedImageUrls(
                    rawImages.filter((img: unknown): img is string => typeof img === 'string'),
                    { fallbackToPlaceholder: false, allowPlaceholder: false }
                ),
                _savedAt: s.createdAt,
            };
        })
        .filter(Boolean);

    return { data, total };
};

export const saveAd = async (userId: string, adId: string) => {
    const ad = await getListingRepository().findById(adId);
    if (!ad) return null;

    await SavedAd.create({ userId, adId });
    void recordAdAnalyticsEvent(adId, 'favorite');
    void getListingRepository().updateOne(adId, { $inc: { 'views.favorites': 1 } } as any);
    return true;
};

export const unsaveAd = async (userId: string, adId: string) => {
    const deleted = await SavedAd.findOneAndDelete({ userId, adId });
    if (deleted) {
        void getListingRepository().updateMany(
            { ids: [adId], favoritesGreaterThan: 0 },
            { $inc: { 'views.favorites': -1 } } as any
        );
    }
};

import mongoose, { type PipelineStage } from 'mongoose';
import { getListingRepository } from '../composition/listings';
import type { ListingFilter } from '../domains/listings/ports/ListingRepositoryPort';
import AdAnalytics from '../models/AdAnalytics';
import Category from '../models/Category';
import { getCache, setCache } from '../utils/redisCache';
import { LISTING_STATUS } from '@esparex/shared';
import logger from '../utils/logger';
import { normalizeAdImagesForResponse } from './adQuery/AdQueryHelpers';
import { toObjectId } from '../utils/idUtils';
import { LISTING_TYPE } from '@esparex/shared';

type AnalyticsEventType = 'view' | 'favorite';

type TrendingInput = {
    location?: string;
    locationId?: string;
    category?: string;
    categoryId?: string;
    limit?: number;
};

type TrendingCounterState = {
    views: number;
    favorites: number;
};

type AnalyticsSnapshot = TrendingCounterState & {
    _id?: unknown;
    adId: mongoose.Types.ObjectId;
    score?: number;
    updatedAt?: Date;
};

const TRENDING_LIMIT_DEFAULT = 20;
const TRENDING_LIMIT_MAX = 20;
const TRENDING_CACHE_TTL_SECONDS = 120;

const SCORE_WEIGHTS = {
    views: 2,
    favorites: 3,
} as const;

const RECENCY_WINDOW_HOURS = 48;
const RECENCY_MAX_BONUS = 12;

const normalizeSegment = (value: unknown, fallback: string): string => {
    if (typeof value !== 'string') return fallback;
    const normalized = value.trim().toLowerCase().replace(/[^a-z0-9._:-]+/g, '-');
    return normalized.length > 0 ? normalized : fallback;
};

const resolveTrendingCacheKey = (input: TrendingInput): string => {
    const locationSegment = normalizeSegment(input.locationId || input.location, 'global');
    const categorySegment = normalizeSegment(input.categoryId || input.category, 'all');
    return `trending:${locationSegment}:${categorySegment}`;
};



const toFiniteNumber = (value: unknown): number => {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : 0;
};

const getRecencyBonus = (createdAt: Date | null): number => {
    if (!createdAt) return 0;
    const ageMs = Date.now() - createdAt.getTime();
    if (!Number.isFinite(ageMs) || ageMs <= 0) return RECENCY_MAX_BONUS;
    const ageHours = ageMs / (1000 * 60 * 60);
    if (ageHours >= RECENCY_WINDOW_HOURS) return 0;
    const ratio = Math.max(0, (RECENCY_WINDOW_HOURS - ageHours) / RECENCY_WINDOW_HOURS);
    return Number((RECENCY_MAX_BONUS * ratio).toFixed(4));
};

export const calculateTrendingScore = (
    counters: TrendingCounterState,
    createdAt: Date | null
): number => {
    const baseScore = (
        counters.views * SCORE_WEIGHTS.views +
        counters.favorites * SCORE_WEIGHTS.favorites
    );
    return Number((baseScore + getRecencyBonus(createdAt)).toFixed(4));
};

const resolveCategoryId = async (category?: string, categoryId?: string): Promise<mongoose.Types.ObjectId | null> => {
    const directCategoryId = toObjectId(categoryId || category);
    if (directCategoryId) return directCategoryId;
    if (!category || category.trim().length === 0) return null;

    const lookup = category.trim();
    const found = await Category.findOne({
        $or: [
            { slug: lookup.toLowerCase() },
            { name: { $regex: `^${lookup.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}$`, $options: 'i' } }
        ]
    })
        .select('_id')
        .lean<{ _id: mongoose.Types.ObjectId } | null>();

    return found?._id || null;
};


const buildDirectAdFilter = async (input: TrendingInput): Promise<ListingFilter> => {
    const filter: ListingFilter = {
        status: LISTING_STATUS.LIVE,
        isDeleted: { $ne: true },
        listingType: LISTING_TYPE.AD,
    };

    const locationObjectId = toObjectId(input.locationId);
    if (locationObjectId) {
        filter.locationId = locationObjectId.toString();
    } else if (typeof input.location === 'string' && input.location.trim().length > 0) {
        const safeLocation = input.location.trim().replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        filter.locationCity = { $regex: `^${safeLocation}$`, $options: 'i' };
    }

    const resolvedCategoryId = await resolveCategoryId(input.category, input.categoryId);
    if (resolvedCategoryId) {
        filter.categoryId = resolvedCategoryId.toString();
    }

    return filter;
};

export const recordAdAnalyticsEvent = async (
    adId: string | mongoose.Types.ObjectId,
    eventType: AnalyticsEventType
): Promise<void> => {
    const objectId = toObjectId(adId);
    if (!objectId) return;

    const incrementPath =
        eventType === 'view'
            ? 'views'
            : 'favorites';

    try {
        const ad = await getListingRepository().findById(objectId.toString());
        if (!ad || ad.isDeleted || ad.status !== LISTING_STATUS.LIVE) return;

        const snapshot = await AdAnalytics.findOneAndUpdate(
            { adId: objectId },
            {
                $inc: { [incrementPath]: 1 },
                $setOnInsert: {
                    adId: objectId,
                    views: 0,
                    favorites: 0,
                    score: 0,
                }
            },
            {
                upsert: true,
                new: true,
                setDefaultsOnInsert: true,
            }
        ).lean<AnalyticsSnapshot | null>();

        if (!snapshot) return;

        const score = calculateTrendingScore(
            {
                views: toFiniteNumber(snapshot.views),
                favorites: toFiniteNumber(snapshot.favorites),
            },
            ad.createdAt || null
        );

        await AdAnalytics.updateOne(
            { adId: objectId },
            { $set: { score } }
        );
    } catch (error) {
        logger.warn('Failed to record ad analytics event', {
            adId: String(objectId),
            eventType,
            error: error instanceof Error ? error.message : String(error)
        });
    }
};

export const getTrendingAds = async (input: TrendingInput): Promise<{ ads: Record<string, unknown>[] }> => {
    const limit = Math.max(1, Math.min(TRENDING_LIMIT_MAX, Math.floor(Number(input.limit) || TRENDING_LIMIT_DEFAULT)));
    const cacheKey = resolveTrendingCacheKey(input);

    try {
        const cached = await getCache<{ ads: Record<string, unknown>[] }>(cacheKey);
        if (cached && Array.isArray(cached.ads)) {
            return cached;
        }

        let mergedAds: Record<string, unknown>[] = [];
        let skip = 0;
        const batchSize = Math.max(limit * 2, 20);

        while (mergedAds.length < limit && skip < 1000) {
            const analyticsBatch = await AdAnalytics.find()
                .sort({ score: -1, updatedAt: -1 })
                .skip(skip)
                .limit(batchSize)
                .lean<AnalyticsSnapshot[]>();

            if (analyticsBatch.length === 0) break;

            const adIds = analyticsBatch.map((a) => String(a.adId));
            const filter = await buildDirectAdFilter(input);
            filter.ids = adIds;

            const listings = await getListingRepository().findWithLimit(
                filter,
                { createdAt: -1 },
                batchSize
            );

            const listingMap = new Map(listings.map((l) => [l.id, l]));

            for (const analytics of analyticsBatch) {
                const l = listingMap.get(String(analytics.adId));
                if (l) {
                    mergedAds.push({ ...l, _id: l.id, rankScore: analytics.score });
                    if (mergedAds.length >= limit) break;
                }
            }

            skip += batchSize;
        }

        if (mergedAds.length < limit) {
            const fallbackFilter = await buildDirectAdFilter(input);
            const existingIds = mergedAds.map((ad) => String(ad._id || ad.id)).filter(Boolean);

            if (existingIds.length > 0) {
                fallbackFilter.idsNotIn = existingIds;
            }

            const fallbackListings = await getListingRepository().findWithLimit(
                fallbackFilter,
                { createdAt: -1 },
                limit - mergedAds.length
            );

            const fallbackAds = fallbackListings.map((l) => ({
                ...l,
                _id: l.id,
            }));

            mergedAds = [...mergedAds, ...fallbackAds];
        }

        const payload = {
            ads: mergedAds.map((ad) => normalizeAdImagesForResponse(ad))
        };

        await setCache(cacheKey, payload, TRENDING_CACHE_TTL_SECONDS);
        return payload;
    } catch (error) {
        logger.error('Failed to fetch trending ads', {
            error: error instanceof Error ? error.message : String(error),
            input
        });
        return { ads: [] };
    }
};

import mongoose from 'mongoose';
import { CACHE_KEYS, getMultiCache, setMultiCache } from '../ad/_shared/adServiceBase';

type MetadataRef = mongoose.Types.ObjectId | string;
type MetadataEntity = Record<string, unknown> & {
    _id: MetadataRef;
    id?: MetadataRef;
    name?: string;
    slug?: string;
};
import Category from '../../models/Category';
import Brand from '../../models/Brand';
import Model from '../../models/Model';
import SparePart from '../../models/SparePart';
import ServiceType from '../../models/ServiceType';
import Ad from '../../models/Ad';
import type { HydratedAd } from './types';

async function fetchMetadataWithCache<T>(
    ids: Set<string>,
    type: string,
    query: (missingIds: string[]) => Promise<T[]>,
    idField: string = '_id'
): Promise<T[]> {
    if (ids.size === 0) return [];
    const idArray = Array.from(ids);
    const cacheKeys = idArray.map(id => CACHE_KEYS.metadata(type, id));
    const cachedResults = await getMultiCache<T>(cacheKeys);
    const results: T[] = [];
    const missingIds: string[] = [];
    cachedResults.forEach((val, index) => {
        if (val) results.push(val);
        else { const id = idArray[index]; if (id) missingIds.push(id); }
    });
    if (missingIds.length > 0) {
        const fresh = await query(missingIds);
        results.push(...fresh);
        const cacheEntries = fresh.map(item => ({ key: CACHE_KEYS.metadata(type, String((item as MetadataEntity)[idField])), value: item }));
        if (cacheEntries.length > 0) await setMultiCache(cacheEntries);
    }
    return results;
}

export async function hydrateAdMetadata(ads: HydratedAd[]): Promise<HydratedAd[]> {
    if (!ads || ads.length === 0) return ads;
    const categoryIds = new Set<string>();
    const brandIds = new Set<string>();
    const modelIds = new Set<string>();
    const sparePartIds = new Set<string>();
    const serviceTypeIds = new Set<string>();
    const extractId = (val: unknown): string | null => {
        if (!val) return null;
        if (typeof val === 'string') return val;
        if (typeof val === 'object') {
            const record = val as Record<string, unknown>;
            const objectId = record._id;
            if (typeof objectId === 'string' || objectId instanceof mongoose.Types.ObjectId) return objectId.toString();
            const id = record.id;
            if (typeof id === 'string' || id instanceof mongoose.Types.ObjectId) return id.toString();
        }
        if (val instanceof mongoose.Types.ObjectId) return val.toString();
        return null;
    };
    ads.forEach(ad => {
        const catId = extractId(ad.categoryId || ad.category); if (catId) categoryIds.add(catId);
        const bId = extractId(ad.brandId || ad.brand); if (bId) brandIds.add(bId);
        const mId = extractId(ad.modelId || ad.model); if (mId) modelIds.add(mId);
        const spId = extractId(ad.sparePartId || ad.sparePart); if (spId) sparePartIds.add(spId);
        if (Array.isArray(ad.sparePartIds)) ad.sparePartIds.forEach((id) => { const sid = extractId(id); if (sid) sparePartIds.add(sid); });
        if (Array.isArray(ad.serviceTypeIds)) ad.serviceTypeIds.forEach((id) => { const sid = extractId(id); if (sid) serviceTypeIds.add(sid); });
    });
    const [categories, brands, models, spareParts, serviceTypes] = await Promise.all([
        fetchMetadataWithCache<MetadataEntity>(categoryIds, 'category', (missing) => Category.find({ _id: { $in: missing } }).select('name slug').lean<MetadataEntity[]>()),
        fetchMetadataWithCache<MetadataEntity>(brandIds, 'brand', (missing) => Brand.find({ _id: { $in: missing } }).select('name slug').lean<MetadataEntity[]>()),
        fetchMetadataWithCache<MetadataEntity>(modelIds, 'model', (missing) => Model.find({ _id: { $in: missing } }).select('name slug').lean<MetadataEntity[]>()),
        fetchMetadataWithCache<MetadataEntity>(sparePartIds, 'sparepart', (missing) => SparePart.find({ _id: { $in: missing } }).lean<MetadataEntity[]>()),
        fetchMetadataWithCache<MetadataEntity>(serviceTypeIds, 'servicetype', (missing) => ServiceType.find({ _id: { $in: missing } }).select('name').lean<MetadataEntity[]>()),
    ]);
    const categoryMap = new Map(categories.map((c) => [String(c._id), c]));
    const brandMap = new Map(brands.map((b) => [String(b._id), b]));
    const modelMap = new Map(models.map((m) => [String(m._id), m]));
    const sparePartMap = new Map(spareParts.map((s) => [String(s._id), s]));
    const serviceTypeMap = new Map(serviceTypes.map((st) => [String(st._id), st]));
    ads.forEach(ad => {
        const catId = extractId(ad.categoryId || ad.category); if (catId) { ad.categoryId = catId; const cat = categoryMap.get(catId); if (cat?.name) ad.categoryName = cat.name; } delete ad.category;
        const bId = extractId(ad.brandId || ad.brand); if (bId) { ad.brandId = bId; const brand = brandMap.get(bId); if (brand?.name) ad.brandName = brand.name; }
        if (typeof ad.brand === 'object' && ad.brand !== null && !ad.brandName) { const b = ad.brand as any; if (b.name) ad.brandName = b.name; }
        const mId = extractId(ad.modelId || ad.model); if (mId) { ad.modelId = mId; const model = modelMap.get(mId); if (model?.name) ad.modelName = model.name; }
        if (typeof ad.model === 'object' && ad.model !== null && !ad.modelName) { const m = ad.model as any; if (m.name) ad.modelName = m.name; }
        const spId = extractId(ad.sparePartId || ad.sparePart); if (spId) ad.sparePart = sparePartMap.get(spId);
        if (Array.isArray(ad.sparePartIds)) ad.spareParts = ad.sparePartIds.map((id) => { const sid = extractId(id); return sid ? sparePartMap.get(sid) : null; }).filter(Boolean) as MetadataEntity[];
        if (Array.isArray(ad.serviceTypeIds)) ad.serviceTypes = ad.serviceTypeIds.map((id) => { const sid = extractId(id); return sid ? serviceTypeMap.get(sid) : null; }).filter(Boolean) as MetadataEntity[];
    });
    return ads;
}

export const getOwnerListings = async (query: Record<string, unknown>, page: number, limit: number) => {
    const populateSpecs = [
        { path: 'categoryId', model: Category, select: 'name slug icon' },
        { path: 'brandId', model: Brand, select: 'name slug' },
        { path: 'modelId', model: Model, select: 'name slug' },
        { path: 'sparePartId', model: SparePart, select: 'name slug' },
        { path: 'serviceTypeIds', model: ServiceType, select: 'name slug' },
    ] as const;
    const itemsQuery = populateSpecs.reduce((builder, spec) => builder.populate(spec), Ad.find(query));
    const [items, total] = await Promise.all([
        itemsQuery.sort({ createdAt: -1 }).skip((page - 1) * limit).limit(limit),
        Ad.countDocuments(query),
    ]);
    return { items, total };
};

import {
    mongoose,
    Business,
    Report,
    LISTING_STATUS,
    isBusinessPublishedStatus
} from './_shared/adServiceBase';
import type { PaginationOptions } from './_shared/adServiceBase';
import { getListingRepository } from '../../composition/listings';

import { hydrateAdMetadata } from './AdAggregationService';
import type { IAd } from '../../models/Ad';
import logger from '../../utils/logger';

const extractRefId = (value: unknown): string | undefined => {
    if (typeof value === 'string' && value.trim().length > 0) {
        return value.trim();
    }

    if (value && typeof value === 'object') {
        const record = value as Record<string, unknown>;
        const candidate = record._id ?? record.id;
        if (typeof candidate === 'string' && candidate.trim().length > 0) {
            return candidate.trim();
        }
        if (candidate instanceof mongoose.Types.ObjectId) {
            return candidate.toString();
        }
    }

    if (value instanceof mongoose.Types.ObjectId) {
        return value.toString();
    }

    return undefined;
};

const canonicalizeListingContract = (detail: Record<string, unknown>) => {
    const categoryId = extractRefId(detail.categoryId);
    const brandId = extractRefId(detail.brandId);
    const modelId = extractRefId(detail.modelId);
    const businessId = extractRefId(detail.businessId);
    const sellerRecord =
        detail.sellerId && typeof detail.sellerId === 'object'
            ? detail.sellerId as Record<string, unknown>
            : null;
    const sellerId = extractRefId(detail.sellerId);

    if (categoryId) detail.categoryId = categoryId;
    if (brandId) detail.brandId = brandId;
    if (modelId) detail.modelId = modelId;
    if (businessId) detail.businessId = businessId;
    if (sellerId) detail.sellerId = sellerId;

    if (sellerRecord && typeof sellerRecord.name === 'string' && sellerRecord.name.trim().length > 0) {
        detail.sellerName = sellerRecord.name.trim();
    }

    if (sellerRecord && typeof sellerRecord.isVerified === 'boolean') {
        detail.verified = sellerRecord.isVerified;
    }

    return detail;
};

/**
 * Returns a specific ad by its ID with full seller details and flattened DTO shape.
 * Used for admin lookups and specialized public detail views.
 */
export const getAnyAdById = async (
    adId: string,
    _requesterId?: string
): Promise<Record<string, unknown> | null> => {
    void _requesterId;
    if (!mongoose.Types.ObjectId.isValid(adId)) return null;

    const id = new mongoose.Types.ObjectId(adId);

    try {
        const ad = await getListingRepository().findOne({ ids: [adId], isDeleted: { $in: [true, false] } as any });
        if (!ad) return null;

        const User = (await import('../../models/User')).default;
        const seller = await User.findById(ad.sellerId).select('name avatar isVerified role trustScore').lean();
        const adRecord = { ...ad, sellerId: seller ? seller : ad.sellerId };

        if (!adRecord) return null;

        // Perform Split-DB hydration for catalog references
        await hydrateAdMetadata([adRecord as any]);

        // Use DTO/interface for ad
        const result = { ...adRecord } as unknown as Partial<IAd> & Record<string, unknown>;
        delete result.password;
        delete result.otp;
        delete result.otpExpiry;

        return canonicalizeListingContract(result);
    } catch (error) {
        logger.error('Failed to get ad by ID', {
            error: error instanceof Error ? error.message : String(error),
            adId
        });
        throw error;
    }
};

/**
 * Lightweight lookup for moderation checks.
 */
export const getAdForModerationById = async (id: string) => {
    if (!mongoose.Types.ObjectId.isValid(id)) return null;
    const ad = await getListingRepository().findById(id);
    if (!ad) return null;
    return { status: String(ad.status), reviewVersion: ad.reviewVersion as number, listingType: String(ad.listingType), isDeleted: Boolean(ad.isDeleted) };
};

export const getListingDetailById = async (adId: string) => {
    if (!mongoose.Types.ObjectId.isValid(adId)) {
        return null;
    }

    const ad = await getListingRepository().findById(adId);
    if (!ad) return null;

    const User = (await import('../../models/User')).default;
    const seller = await User.findById(ad.sellerId).select('name avatar trustScore isVerified status mobileVisibility role').lean();
    const adRecord = { ...ad, sellerId: seller ? seller : ad.sellerId };

    await hydrateAdMetadata([adRecord as any]);

    const detail = adRecord as unknown as Record<string, unknown> & {
        categoryId?: unknown;
        brandId?: unknown;
        modelId?: unknown;
        businessId?: unknown;
        sellerId?: unknown;
        sellerType?: unknown;
    };

    canonicalizeListingContract(detail);
    detail.isBusiness = detail.sellerType === 'business' || Boolean(detail.businessId);

    if (detail.businessId && mongoose.Types.ObjectId.isValid(String(detail.businessId))) {
        const business = await Business.findById(detail.businessId)
            .select('name businessTypes location expiresAt isVerified status slug')
            .lean();

        if (business) {
            const businessRecord = business as unknown as Record<string, unknown> & {
                name?: string;
                businessTypes?: string[];
                location?: { city?: string; state?: string } | null;
                expiresAt?: Date | string | null;
                isVerified?: boolean;
                status?: unknown;
            };

            if (typeof businessRecord.name === 'string' && businessRecord.name.trim().length > 0) {
                detail.businessName = businessRecord.name.trim();
            }
            if (Array.isArray(businessRecord.businessTypes) && businessRecord.businessTypes.length > 0) {
                const primaryType = businessRecord.businessTypes.find(
                    (type): type is string => typeof type === 'string' && type.trim().length > 0
                );
                if (primaryType) {
                    detail.businessType = primaryType;
                    detail.businessCategory = primaryType;
                }
            }
            if (businessRecord.location && typeof businessRecord.location === 'object') {
                const location = businessRecord.location;
                if (typeof location.city === 'string') {
                    detail.businessCity = location.city;
                }
                if (typeof location.state === 'string') {
                    detail.businessState = location.state;
                }
            }
            if (businessRecord.expiresAt) {
                detail.businessExpiresAt = businessRecord.expiresAt;
            }
            detail.verified =
                businessRecord.isVerified === true || isBusinessPublishedStatus(businessRecord.status);
        }
    }

    return detail;
};

export const getReportedAdsAggregation = async (filters: { status?: string, reason?: string, search?: string }, pagination: { skip: number, limit: number }) => {
    const { status, reason, search } = filters;
    const { skip, limit } = pagination;

    const matchQuery: Record<string, unknown> = {};
    if (status && status !== 'all') matchQuery.status = status;
    if (reason && reason !== 'all') matchQuery.reason = reason;

    const pipeline: mongoose.PipelineStage[] = [
        { $match: matchQuery },
        {
            $group: {
                _id: '$adId',
                reportCount: { $sum: 1 },
                reports: { $push: '$$ROOT' },
                latestReportAt: { $max: '$createdAt' }
            }
        },
        {
            $lookup: {
                from: 'ads',
                localField: '_id',
                foreignField: '_id',
                as: 'adDetails'
            }
        },
        { $unwind: '$adDetails' },
        {
            $lookup: {
                from: 'users',
                localField: 'adDetails.sellerId',
                foreignField: '_id',
                as: 'sellerDetails'
            }
        },
        { $unwind: { path: '$sellerDetails', preserveNullAndEmptyArrays: true } },
        ...(search ? [{
            $match: {
                $or: [
                    { 'adDetails.title': { $regex: String(search), $options: 'i' } },
                    { 'reports.description': { $regex: String(search), $options: 'i' } }
                ]
            }
        }] : []),
        {
            $addFields: {
                isAutoHidden: { $eq: ['$adDetails.moderationStatus', LISTING_STATUS.REJECTED] }
            }
        },
        {
            $sort: {
                isAutoHidden: -1,
                reportCount: -1,
                latestReportAt: -1
            }
        }
    ];

    interface ReportDoc {
        _id: unknown;
        reason: string;
        status: string;
        createdAt: Date;
        reportedBy?: unknown;
    }
    interface ReportGroupDoc {
        _id: unknown;
        reportCount: number;
        reports: ReportDoc[];
        adDetails: unknown;
        isAutoHidden: boolean;
    }

    const [results, totalResults] = await Promise.all([
        Report.aggregate<ReportGroupDoc>([...pipeline, { $skip: skip }, { $limit: limit }]),
        Report.aggregate<{ count: number }>([...pipeline, { $count: 'count' }])
    ]);

    const total = totalResults[0]?.count ?? 0;

    const transformedData = results.map(group => {
        const latestReport = group.reports[group.reports.length - 1];
        return {
            id: String(group._id),
            reportId: String(latestReport._id),
            reason: latestReport.reason,
            status: latestReport.status,
            ad: group.adDetails,
            reportedAt: latestReport.createdAt,
            reporter: group.reports.map((r) => r.reportedBy),
            reportCount: group.reportCount,
            isAutoHidden: group.isAutoHidden
        };
    });

    return { data: transformedData, total };
};

