import mongoose from 'mongoose';
import { AppError } from '../../utils/AppError';
import { getListingRepository } from '../../composition/listings';
import User from '../../models/User';
import { LISTING_STATUS } from '@esparex/shared';
import { LISTING_TYPE, type ListingTypeValue } from '@esparex/shared';
import { Role } from '@esparex/shared';
import { getSystemConfigForRead } from '../SystemConfigService';
import logger from '../../utils/logger';


export const assertOwnership = async (adId: string, userId: string): Promise<{ sellerId: mongoose.Types.ObjectId; status: string }> => {
    const ad = await getListingRepository().findById(adId);
    if (!ad) {
        throw new AppError('Ad not found', 404, 'NOT_FOUND');
    }
    if (ad.sellerId !== userId) {
        throw new AppError('Unauthorized', 403, 'UNAUTHORIZED');
    }
    return { sellerId: new mongoose.Types.ObjectId(ad.sellerId), status: ad.status as string };
};

/**
 * Validates if a seller is within their allowed listing threshold for a specific type.
 * Specifically used to enforce Business Account requirement for high-volume Spare Part sellers.
 */
export const validateSellerTypeThreshold = async (
    sellerId: string,
    listingType: ListingTypeValue
): Promise<{ ok: boolean; reason?: string; code?: string }> => {
    // Currently policy only applies to Spare Parts
    if (listingType !== LISTING_TYPE.SPARE_PART) {
        return { ok: true };
    }

    try {
        const user = await User.findById(sellerId).select('role').lean();
        if (!user) return { ok: false, reason: 'Seller not found', code: 'SELLER_NOT_FOUND' };

        // Business accounts have no threshold limits on spare parts
        if (
            user.role === Role.BUSINESS || 
            user.role === Role.ADMIN || 
            user.role === Role.SUPER_ADMIN ||
            user.role === Role.MODERATOR
        ) {
            return { ok: true };
        }

        const config = await getSystemConfigForRead();
        const threshold = config?.listing?.thresholds?.proSparePartLimit ?? 5; // Default 5

        const activeCount = await getListingRepository().count({
            sellerId,
            listingType: LISTING_TYPE.SPARE_PART,
            status: { $in: [LISTING_STATUS.LIVE, 'pending'] } as any,
            isDeleted: false
        });

        if (activeCount >= threshold) {
            return {
                ok: false,
                reason: `You have reached the limit of ${threshold} spare part listings for individual accounts. Please upgrade to a Business Account to post more.`,
                code: 'BUSINESS_REQUIRED_THRESHOLD'
            };
        }

        return { ok: true };
    } catch (error) {
        logger.error('validateSellerTypeThreshold: Error during validation', { error, sellerId });
        return { ok: true }; // Fail open for safety
    }
};

import { AppError } from '../../utils/AppError';
import logger from '../../utils/logger';
import { getListingRepository, getListingsCache, getListingUnitOfWork } from '../../composition/listings';
import { LISTING_TYPE } from '@esparex/shared';
import { LISTING_STATUS } from '@esparex/shared';
import { LIFECYCLE_STATUS } from '@esparex/shared';
import { consumeCredit } from '../wallet/WalletService';
import { isValidObjectId } from '../../utils/idUtils';

export const promoteAdLogic = async (
    id: string,
    days: number = 7,
    type: 'spotlight_hp' | 'spotlight_cat' = 'spotlight_hp',
    userId: string,
    isAdmin: boolean = false
) => {
    const Boost = (await import('@esparex/core/models/Boost')).default;
    const User = (await import('@esparex/core/models/User')).default;

    if (!isValidObjectId(id)) throw new AppError('Invalid Ad ID', 400);

    const ad = await getListingRepository().findById(id);
    if (!ad) return null;

    if (ad.listingType === LISTING_TYPE.SPARE_PART) {
        throw new AppError('Spare parts are not eligible for Spotlight promotion.', 403);
    }

    if (!isAdmin && ad.sellerId.toString() !== userId.toString()) {
        throw new AppError('Unauthorized', 403);
    }

    if (!isAdmin) {
        const user = await User.findById(userId).select('trustScore strikeCount');
        if (!user || user.trustScore < 30 || user.strikeCount >= 2) {
            throw new AppError('Account ineligible for promotion due to trust or moderation standing.', 403);
        }

        if ((ad.moderationStatus as string) === 'auto_hidden' || ad.moderationStatus === LIFECYCLE_STATUS.REJECTED || ad.moderationStatus === 'held_for_review') {
            throw new AppError('Ad must be in normal standing to be promoted.', 403);
        }

        if (!ad.isSpotlight) {
            const activePromotions = await getListingRepository().count({
                sellerId: userId,
                isSpotlight: true,
                status: LISTING_STATUS.LIVE
            });
            if (activePromotions >= 3) {
                throw new AppError('Maximum 3 active spotlight promotions allowed concurrently.', 403);
            }
        }
    }

    const startsAt = new Date();
    let endsAt = new Date();

    if (ad.isSpotlight && ad.spotlightExpiresAt && ad.spotlightExpiresAt > new Date()) {
        endsAt = new Date(ad.spotlightExpiresAt.getTime());
    }
    endsAt.setDate(endsAt.getDate() + days);

    if (ad.expiresAt && ad.expiresAt < endsAt) {
        throw new AppError('Ad expires before boost duration. Extend ad expiry first.', 400);
    }

    await getListingUnitOfWork().executeTransaction(async (session) => {
        if (!isAdmin) {
            const promotionCost = Math.abs(Math.floor(days));
            if (promotionCost === 0) throw new AppError('Promotion cost cannot be zero', 400, 'INVALID_PROMOTION_COST');

            try {
                await consumeCredit({
                    userId,
                    creditType: 'spotlightCredits',
                    amount: promotionCost,
                    reason: `Ad promotion - ${days} days`,
                    metadata: { adId: id, type, days },
                    session: session as any
                });
            } catch (error) {
                throw new AppError(
                    error instanceof Error ? error.message : 'Insufficient spotlight credits',
                    402
                );
            }
        }

        if (ad.isSpotlight) {
            await Boost.updateOne(
                { entityId: ad.id, isActive: true },
                { $set: { endsAt } },
                { session: session as any }
            );
        } else {
            await Boost.create([{
                entityId: ad.id,
                entityType: 'ad',
                boostType: type,
                startsAt,
                endsAt,
                isActive: true
            }], { session: session as any });
        }

        await getListingRepository().updateOne(id, {
            $set: {
                isSpotlight: true,
                spotlightExpiresAt: endsAt,
                spotlightWarningCount: 0
            },
            $unset: {
                spotlightWarningSentAt: 1
            }
        } as any, session as any);
    });

    setImmediate(() => {
        getListingsCache().invalidateAdFeedCaches().catch((err: unknown) => {
            logger.error('Failed to clear homepage cache after promotion', { error: String(err) });
        });
    });

    return ad;
};

import { AppError } from '../../utils/AppError';
import logger from '../../utils/logger';
import { getListingRepository, getListingsCache, getListingUnitOfWork } from '../../composition/listings';
import { LISTING_STATUS } from '@esparex/shared';
import { ListingSubmissionPolicy } from '../ListingSubmissionPolicy';
import { mutateStatus } from '../lifecycle/StatusMutationService';
import { normalizeAdStatus } from "../lifecycle/AdStatusService";
import { isValidObjectId } from '../../utils/idUtils';

import { type ListingTypeValue } from '@esparex/shared';

export const repostAdLogic = async (
    id: string,
    userId: string
): Promise<Record<string, unknown> | null> => {
    if (!isValidObjectId(id) || !isValidObjectId(userId)) {
        return null;
    }

    logger.info('[RepostLifecycle] Repost requested', { adId: id, userId });

    let updatedAd: Record<string, unknown> | null = null;

    try {
        await getListingUnitOfWork().executeTransaction(async (session) => {
            const ad = await getListingRepository().findOne({
                ids: [id],
                sellerId: userId,
                isDeleted: false as any
            });

            if (!ad) {
                throw new AppError('Ad not found', 404);
            }

            const currentStatus = normalizeAdStatus(String(ad.status));
            const isExpired = currentStatus === LISTING_STATUS.EXPIRED;
            const isRejected = currentStatus === LISTING_STATUS.REJECTED;

            if (!isExpired && !isRejected) {
                throw new AppError('Only expired or rejected ads can be reposted', 400);
            }

            // 🛡️ GOVERNANCE: Unified Slot Reservation via SubmissionPolicy
            await ListingSubmissionPolicy.reserveSlot({
                userId,
                listingType: (ad.listingType as ListingTypeValue),
                listingId: id,
                session: session as any,
                actor: 'user'
            });

            const nextStatus = LISTING_STATUS.PENDING;
            const now = new Date();
            const patchDoc: Record<string, unknown> = {
                $unset: {
                    expiresAt: 1,
                    approvedAt: 1,
                    expiryWarningSentAt: 1,
                    lastExpiryWarningChannel: 1,
                    spotlightWarningSentAt: 1,
                    duplicateFingerprint: 1,
                    duplicateOf: 1,
                    rejectionReason: 1
                },
                $set: {
                    publishedAt: now,
                    expiryWarningCount: 0,
                    spotlightWarningCount: 0,
                    duplicateScore: 0,
                    isDuplicateFlag: false,
                    moderationStatus: 'held_for_review',
                    moderationReason: 'Reposted by seller for moderation review'
                }
            };
            await getListingRepository().updateOne(id, patchDoc as any, session);

            const transitioned = await mutateStatus({
                domain: 'ad',
                entityId: ad.id,
                toStatus: nextStatus,
                actor: { type: 'user', id: userId },
                reason: 'Reposted by seller',
                metadata: {
                    action: 'repost',
                    sourceRoute: '/api/v1/ads/:id/repost',
                },
                patch: {
                    moderationStatus: 'held_for_review',
                    moderationReason: 'Reposted by seller for moderation review',
                    $push: {
                        timeline: {
                            status: nextStatus,
                            timestamp: now,
                            reason: 'Reposted by seller',
                        },
                    },
                },
                session: session as any,
            });
            updatedAd = transitioned;

            logger.info('[RepostLifecycle] Repost mutation applied', {
                adId: id,
                userId,
                nextStatus,
                expiresAt: ad.expiresAt
            });
        });

        setImmediate(() => {
            getListingsCache().invalidateAdFeedCaches().catch((err: unknown) => {
                logger.error('Failed to clear feed cache after repost', { error: String(err), adId: id });
            });
            getListingsCache().invalidatePublicAdCache(id).catch((err: unknown) => {
                logger.error('Failed to clear public ad cache after repost', { error: String(err), adId: id });
            });
        });

        return updatedAd;
    } catch (error) {
        logger.error('[RepostLifecycle] Repost failed', {
            adId: id,
            userId,
            error: error instanceof Error ? error.message : String(error)
        });
        throw error;
    }
};

import { AppError } from '../../utils/AppError';
