import { AdContext } from '../../types/ad.types';
import { generateUniqueSlugWithChecker } from '../../utils/slugGenerator';
import { AdCreationService } from '../AdCreationService';
import { mutateStatus } from '../lifecycle/StatusMutationService';
import { enqueueImageOptimization } from '../../queues/imageQueue';

export const updateAdLogic = async (
    adId: string,
    data: unknown,
    context: AdContext,
    externalSession?: unknown
): Promise<Record<string, unknown> | null> => {
    if (!isValidObjectId(adId)) return null;

    try {
        let updatedAd: Listing | null = null;
        let oldPriceValue: number | undefined;
        let removedImagesCache: string[] = [];
        
        const executeUpdate = async (session: unknown) => {
            const ad = await getListingRepository().findOne({ ids: [adId], session });
            if (!ad) return;

            oldPriceValue = ad.price;

            if (context.actor === 'USER' && ad.sellerId !== context.sellerId)
                throw new AppError('Unauthorized: You can only edit your own ads', 403);
            if (ad.status === LIFECYCLE_STATUS.SOLD || ad.status === LIFECYCLE_STATUS.EXPIRED || ad.status === LIFECYCLE_STATUS.REJECTED || ad.status === LIFECYCLE_STATUS.DEACTIVATED)
                throw new AppError('This ad can no longer be edited in its current status.', 400);

            if (context.actor === 'USER' && ad.status === LISTING_STATUS.PENDING)
                throw new AppError('Pending listings are view-only and cannot be edited', 400);

            if (context.actor === 'USER' && !context.allowSuspendedUser) {
                const User = (await import('@esparex/core/models/User')).default;
                const user = await User.findById(context.authUserId).select('isSuspended').lean();
                if ((user as { isSuspended?: boolean } | null)?.isSuspended)
                    throw Object.assign(new Error('Account suspended'), { statusCode: 403, code: 'ACCOUNT_SUSPENDED' });
            }

            const payload = await AdCreationService.preparePayload(
                {
                    listingType: ad.listingType,
                    categoryId: ad.categoryId?.toString(),
                    ...(data as Record<string, unknown>),
                },
                context,
                true,
                ad.categoryId?.toString(),
                adId
            );

            const untypedPayload = payload as Record<string, unknown>;
            const untypedAd = ad as unknown as Record<string, unknown>;

            let sensitiveChange = false;
            if (context.actor === 'USER') {
                if (untypedPayload.title && untypedPayload.title !== untypedAd.title) sensitiveChange = true;
                if (untypedPayload.description && untypedPayload.description !== untypedAd.description) sensitiveChange = true;
                if (untypedPayload.price !== undefined && untypedPayload.price !== untypedAd.price) sensitiveChange = true;
                if (Array.isArray(untypedPayload.images)) {
                    const newImages = untypedPayload.images.join(',');
                    const oldImages = (Array.isArray(untypedAd.images) ? untypedAd.images : []).join(',');
                    if (newImages !== oldImages) sensitiveChange = true;
                }
            }

            const requiresReviewTransition = context.actor === 'USER' && 
                ((ad.status === LISTING_STATUS.LIVE && sensitiveChange) || (ad.status as string) === 'rejected');

            const oldImagesList = Array.isArray(untypedAd.images) ? untypedAd.images as string[] : [];
            const newImagesList = Array.isArray(untypedPayload.images) ? untypedPayload.images as string[] : oldImagesList;
            removedImagesCache = oldImagesList.filter(img => !newImagesList.includes(img));

            if (context.actor === 'USER') {
                untypedPayload.$inc = { ...(untypedPayload.$inc as Record<string, number>), reviewVersion: 1 };
            }

            // Status transitions must not be embedded in direct update queries.
            delete untypedPayload.status;

            let slugRetries = 0;
            while (slugRetries < 3) {
                try {
                    const updated = await getListingRepository().updateOne(adId, payload as any, session);
                    updatedAd = updated;
                    break;
                } catch (error: unknown) {
                    const mongoError = error as { code?: number; keyPattern?: { seoSlug?: string } };
                    if (mongoError.code === 11000 && mongoError.keyPattern?.seoSlug) {
                        slugRetries++;
                        const baseTitle = (payload as Record<string, unknown>).title as string || ad.title;
                        (payload as Record<string, unknown>).seoSlug = await generateUniqueSlugWithChecker(
                            baseTitle,
                            async (candidate) => {
                                const count = await getListingRepository().count({ seoSlug: candidate, idsNotIn: [adId], session });
                                return count > 0;
                            },
                            ad.seoSlug
                        );
                    } else {
                        throw error;
                    }
                }
            }

            if (updatedAd && requiresReviewTransition) {
                updatedAd = (await mutateStatus({
                    domain: ad.listingType === 'service' ? 'service' : 'ad',
                    entityId: adId,
                    toStatus: LISTING_STATUS.PENDING,
                    actor: {
                        type: context.actor === 'ADMIN' ? 'admin' : 'user',
                        id: context.authUserId,
                    },
                    reason: 'Re-submitted for review after edit',
                    metadata: {
                        action: 'listing_edit',
                        sourceRoute: '/api/v1/ads/:id',
                    },
                    patch: {
                        moderationStatus: 'held_for_review',
                        $push: {
                            timeline: {
                                status: LISTING_STATUS.PENDING,
                                timestamp: new Date(),
                                reason: 'Re-submitted for review after edit',
                            },
                        },
                    },
                    session,
                })) as unknown as Listing | null;
            }
        };

        if (externalSession) {
            await executeUpdate(externalSession);
        } else {
            await getListingUnitOfWork().executeTransaction(async (session) => {
                await executeUpdate(session);
            });
        }

        if (!updatedAd) return null;
        
        const updatedAdTyped = updatedAd as Listing;
        if (Array.isArray(updatedAdTyped.images) && updatedAdTyped.images.length > 0) {
            enqueueImageOptimization(adId, 'ad', updatedAdTyped.images).catch(err => {
                logger.error('Failed to enqueue image optimization after Ad edit', err);
            });
        }

        // 💰 PRICE DROP ENGINE
        if (oldPriceValue && updatedAdTyped.price < oldPriceValue) {
            void (async () => {
                try {
                    const SavedAd = (await import('@esparex/core/models/SavedAd')).default;
                    const keepers = await SavedAd.find({ adId }).select('userId').lean();
                    if (keepers.length > 0) {
                        const { dispatchTemplatedNotification } = await import('../NotificationService');
                        for (const keeper of keepers) {
                            await dispatchTemplatedNotification(
                                String(keeper.userId),
                                NOTIFICATION_TYPE.PRICE_DROP,
                                'PRICE_DROP',
                                { 
                                    adTitle: updatedAdTyped.title, 
                                    price: String(updatedAdTyped.price) 
                                },
                                { adId, type: 'price_drop' }
                             );
                        }
                    }
                } catch (err) {
                    logger.error('Failed to dispatch price drop notifications', { error: err, adId });
                }
            })();
        }

        if (removedImagesCache.length > 0) {
            void (async () => {
                try {
                    const { deleteFromS3Url } = await import('../../utils/s3');
                    for (const url of removedImagesCache) {
                        await deleteFromS3Url(url).catch(e => logger.error(`Failed to delete orphaned image: ${url}`, e));
                    }
                } catch (err) {
                    logger.error('Failed to execute orphan image cleanup task', err);
                }
            })();
        }

        if (typeof (updatedAd as any).toObject === 'function') {
            return (updatedAd as any).toObject();
        }
        return updatedAd as unknown as Record<string, unknown>;
    } catch (error) {
        logger.error('Failed to update ad', {
            error: error instanceof Error ? error.message : String(error),
            adId
        });
        throw error;
    }
};

import Business from '../../models/Business';
import Ad from '../../models/Ad';
import { GOVERNANCE, MS_IN_DAY } from '../../config/constants';
import { publishedBusinessStatusQuery } from '../../utils/businessStatus';
import { BUSINESS_STATUS, LISTING_STATUS, LISTING_TYPE, ACTOR_TYPE } from '@esparex/shared';
import type { ActorMetadata } from '@esparex/shared';
import { mutateStatuses, mutateStatus } from '../lifecycle/StatusMutationService';
import { AppError } from '../../utils/AppError';
import * as businessLifecycleService from '../business/BusinessLifecycleService';

import { getAdminBusinessAccountsData, transformBusinessDocs } from './helpers';

export const getBusinessOverview = async () => {
    const thirty = new Date(Date.now() + GOVERNANCE.BUSINESS.AUTO_EXPIRE_CHECK_DAYS * MS_IN_DAY);
    const seven = new Date(); seven.setDate(seven.getDate() - 7);
    const [live, pending, suspended, rejected, deleted, total, expiringSoon, expiringIn3Days, timeline, topCities] = await Promise.all([
        Business.countDocuments({ status: BUSINESS_STATUS.LIVE }),
        Business.countDocuments({ status: BUSINESS_STATUS.PENDING }),
        Business.countDocuments({ status: BUSINESS_STATUS.SUSPENDED }),
        Business.countDocuments({ status: BUSINESS_STATUS.REJECTED }),
        Business.countDocuments({ isDeleted: true }).setOptions({ withDeleted: true }),
        Business.countDocuments({}).setOptions({ withDeleted: true }),
        Business.countDocuments({ status: publishedBusinessStatusQuery, expiresAt: { $lte: thirty, $gte: new Date() }, isDeleted: false }),
        Business.countDocuments({ status: publishedBusinessStatusQuery, expiresAt: { $lte: new Date(Date.now() + 3 * MS_IN_DAY), $gte: new Date() }, isDeleted: false }),
        Business.aggregate([{ $match: { createdAt: { $gte: seven }, isDeleted: { $ne: true } } }, { $group: { _id: { $dateToString: { format: "%Y-%m-%d", date: "$createdAt" } }, count: { $sum: 1 } } }, { $sort: { _id: 1 } }]),
        Business.aggregate([{ $match: { isDeleted: { $ne: true }, 'location.city': { $exists: true, $ne: '' } } }, { $group: { _id: '$location.city', count: { $sum: 1 } } }, { $sort: { count: -1, _id: 1 } }, { $limit: 5 }, { $project: { _id: 0, city: '$_id', count: 1 } }]),
    ]);
    return { total, pending, live, suspended, rejected, deleted, expiringSoon, expiringIn3Days, analytics: { timeline, topCities } };
};

export const getAdminBusinessAccounts = async (params: {
    status?: string;
    locationId?: string;
    search?: string;
    expiringIn3Days?: string;
    warningSent?: string;
    warningNotSent?: string;
    skip: number;
    limit: number;
}) => {
    const { adminQuery } = await getAdminBusinessAccountsData(params);

    if (params.search) {
        const { escapeRegExp } = require('../../utils/stringUtils');
        const safeSearch = escapeRegExp(params.search);
        adminQuery.$or = [
            { name: { $regex: safeSearch, $options: 'i' } },
            { email: { $regex: safeSearch, $options: 'i' } },
            { mobile: { $regex: safeSearch, $options: 'i' } },
            { 'location.city': { $regex: safeSearch, $options: 'i' } },
        ];
    }

    const [rawItems, total] = await Promise.all([
        Business.find(adminQuery)
            .skip(params.skip)
            .limit(params.limit)
            .sort({ createdAt: -1 })
            .populate('userId')
            .setOptions({ withDeleted: true }),
        Business.countDocuments(adminQuery)
            .setOptions({ withDeleted: true }),
    ]);

    const items = transformBusinessDocs(rawItems);
    return { items, total };
};

export const getAdminBusinessById = async (id: string) => Business.findOne({ _id: id }).setOptions({ withDeleted: true }).populate('userId');
export const findBusinessForAdmin = async (id: string) => Business.findById(id);

export const cascadeExpireBusinessListings = async (businessId: unknown, actor: { type?: string; id?: string }, reason: string) => {
    const nid = typeof businessId === 'string' && businessId.trim() ? businessId.trim() : businessId?.toString?.();
    if (!nid) return 0;
    const na: ActorMetadata = { type: (actor.type === ACTOR_TYPE.ADMIN || actor.type === ACTOR_TYPE.SYSTEM) ? actor.type : ACTOR_TYPE.USER, id: actor.id };
    const listings = await Ad.find({ businessId: nid, status: { $ne: LISTING_STATUS.EXPIRED } }).select('_id listingType');
    if (listings.length > 0) await mutateStatuses(listings.map((l) => ({ domain: l.listingType === LISTING_TYPE.SERVICE ? LISTING_TYPE.SERVICE : l.listingType === LISTING_TYPE.SPARE_PART ? 'spare_part_listing' : LISTING_TYPE.AD, entityId: l._id.toString(), toStatus: LISTING_STATUS.EXPIRED, actor: na, reason })));
    return listings.length;
};

export const approveAdminBusiness = async (id: string, actorId: string, logFn: any) => {
    const business = await businessLifecycleService.approveBusiness(id, actorId) as any;
    if (!business) throw new AppError('Business not found', 404);
    await logFn('APPROVE_BUSINESS', 'Business', id, { expiresAt: business.expiresAt });
    const { dispatchTemplatedNotification } = await import('../NotificationService');
    const { recalculateTrustScore } = await import('../TrustService');
    await dispatchTemplatedNotification(business.userId.toString(), 'BUSINESS_STATUS', 'BUSINESS_APPROVED', { name: business.name }, { businessId: business._id.toString(), status: BUSINESS_STATUS.LIVE });
    setImmediate(() => void recalculateTrustScore(business.userId).catch(() => {}));
    return business;
};

export const rejectAdminBusiness = async (id: string, reason: string, actorId: string, logFn: any) => {
    if (!reason) throw new AppError('Rejection reason is required', 400);
    const business = await businessLifecycleService.rejectBusiness(id, reason, actorId) as any;
    if (!business) throw new AppError('Business not found', 404);
    await logFn('REJECT_BUSINESS', 'Business', id, { reason });
    const { dispatchTemplatedNotification } = await import('../NotificationService');
    await dispatchTemplatedNotification(business.userId.toString(), 'BUSINESS_STATUS', 'BUSINESS_REJECTED', { name: business.name, reason }, { businessId: business._id.toString(), status: BUSINESS_STATUS.REJECTED });
    await cascadeExpireBusinessListings(business._id, { type: ACTOR_TYPE.ADMIN, id: actorId }, `Cascaded from business rejection: ${reason}`);
    return business;
};

export const expireAdminBusiness = async (id: string, actorId: string, logFn: any) => {
    const business = await Business.findById(id);
    if (!business) throw new AppError('Business not found', 404);
    const actor: ActorMetadata = { type: ACTOR_TYPE.ADMIN, id: actorId };
    await mutateStatus({ domain: 'business', entityId: id, toStatus: BUSINESS_STATUS.EXPIRED, actor, reason: 'Manual expiry by admin' });
    const count = await cascadeExpireBusinessListings(business._id, actor, 'Cascaded from admin manual expiry');
    await logFn('EXPIRE_BUSINESS', 'Business', id, { cascadedListings: count });
    const { dispatchTemplatedNotification } = await import('../NotificationService');
    await dispatchTemplatedNotification(business.userId.toString(), 'BUSINESS_STATUS', 'BUSINESS_EXPIRED', { name: business.name }, { businessId: id, status: BUSINESS_STATUS.EXPIRED });
    return Business.findById(id).lean();
};

import Business from '../../models/Business';
import { ACTOR_TYPE } from '@esparex/shared';
import { AppError } from '../../utils/AppError';
import type { AdminLogFn } from '../AdminListingsService';
import * as businessLifecycleService from '../business/BusinessLifecycleService';
import * as businessUtils from '../business/BusinessUtils';
import { findBusinessForAdmin, cascadeExpireBusinessListings, approveAdminBusiness, rejectAdminBusiness, expireAdminBusiness } from './business';
import { normalizeLocation } from '../location/LocationNormalizer';
import logger from '../../utils/logger';
import { dispatchTemplatedNotification } from '../NotificationService';

export { approveAdminBusiness, rejectAdminBusiness, expireAdminBusiness };

export const suspendAdminBusiness = async (id: string, reason: string, actorId: string, logFn: AdminLogFn) => {
    const finalReason = reason || 'Suspended by admin';
    const { mutateStatus } = await import('../lifecycle/StatusMutationService');
    const { BUSINESS_STATUS } = await import('@esparex/shared');
    const business = await mutateStatus({ domain: 'business', entityId: id, toStatus: BUSINESS_STATUS.SUSPENDED, actor: { type: ACTOR_TYPE.ADMIN, id: actorId }, reason: finalReason, patch: { rejectionReason: finalReason } });
    if (!business) throw new AppError('Business not found', 404);
    await logFn('SUSPEND_BUSINESS', 'Business', id, { reason: finalReason });
    return business;
};

export const updateAdminBusinessFields = async (id: string, rawBody: Record<string, unknown>, actorId: string, logFn: AdminLogFn) => {
    const allowedFields = ['name', 'description', 'mobile', 'email', 'website', 'gstNumber', 'registrationNumber', 'location', 'businessTypes'];
    const patch: Record<string, unknown> = {};
    for (const field of allowedFields) { if (Object.prototype.hasOwnProperty.call(rawBody, field)) patch[field] = rawBody[field]; }
    if (Object.keys(patch).length === 0) throw new AppError('No valid fields provided for update', 400);
    const existingBusiness = await findBusinessForAdmin(id);
    if (!existingBusiness) throw new AppError('Business not found', 404);
    if (patch.location && typeof patch.location === 'object' && !Array.isArray(patch.location)) {
        const incoming = patch.location as Record<string, unknown>;
        const bizDoc = existingBusiness as any;
        const current = bizDoc.location;
        const normalized = await normalizeLocation({ locationId: incoming.locationId || bizDoc.locationId, city: incoming.city || current?.city, state: incoming.state || current?.state, country: incoming.country || current?.country || 'India', display: incoming.display || incoming.address, coordinates: incoming.coordinates, address: incoming.address, pincode: incoming.pincode || current?.pincode });
        const resolved = businessUtils.buildBusinessLocationPayload({ currentLocation: current, incomingLocation: incoming, normalizedLocation: normalized, fallbackLocationId: bizDoc.locationId });
        patch.location = resolved.location;
        if (resolved.locationId) patch.locationId = resolved.locationId;
    }
    const business = await Business.findByIdAndUpdate(id, { $set: patch }, { new: true, runValidators: true }).populate('userId');
    if (!business) throw new AppError('Business not found', 404);
    await logFn('UPDATE_BUSINESS', 'Business', id, { patch });
    return business;
};

export const renewAdminBusiness = async (id: string, actorId: string, logFn: AdminLogFn) => {
    const business = await businessLifecycleService.renewBusiness(id, { type: ACTOR_TYPE.ADMIN, id: actorId }) as any;
    if (!business) throw new AppError('Business not found', 404);
    await logFn('RENEW_BUSINESS', 'Business', id, { expiresAt: business.expiresAt });
    await dispatchTemplatedNotification(business.userId.toString(), 'BUSINESS_STATUS', 'BUSINESS_RENEWED', { name: business.name, expiresAt: business.expiresAt?.toLocaleDateString() }, { businessId: id, status: 'live' });
    return business;
};

export const deleteAdminBusiness = async (id: string, actorId: string, logFn: AdminLogFn) => {
    const business = await findBusinessForAdmin(id);
    if (!business) throw new AppError('Business not found', 404);
    const businessName = business.name; const userId = business.userId.toString();
    const actor = { type: ACTOR_TYPE.ADMIN, id: actorId };
    const cc = await cascadeExpireBusinessListings(business._id, actor, 'Cascaded from business deletion');
    const deleted = await businessLifecycleService.softDeleteBusiness(id);
    if (!deleted) throw new AppError('Business not found', 404);
    await logFn('DELETE_BUSINESS', 'Business', id, { businessName, cascadedListings: cc });
    await dispatchTemplatedNotification(userId, 'BUSINESS_STATUS', 'BUSINESS_REMOVED', { name: businessName }, { businessId: id, status: 'deleted' });
    return true;
};

const execBulk = async (ids: string[], actionName: string, fn: (id: string) => Promise<unknown>): Promise<number> => {
    if (!Array.isArray(ids) || !ids.length) return 0;
    let c = 0;
    for (const id of ids) { try { await fn(id); c++; } catch (err) { logger.error(`Bulk ${actionName} failed for business ${id}:`, err); } }
    return c;
};

export const adminBulkApproveBusinesses = async (ids: string[], actorId: string, logFn: AdminLogFn) => execBulk(ids, 'approve', (id) => approveAdminBusiness(id, actorId, logFn));
export const adminBulkRejectBusinesses = async (ids: string[], reason: string, actorId: string, logFn: AdminLogFn) => execBulk(ids, 'reject', (id) => rejectAdminBusiness(id, reason, actorId, logFn));
export const adminBulkDeactivateBusinesses = async (ids: string[], actorId: string, logFn: AdminLogFn) => execBulk(ids, 'deactivate', (id) => suspendAdminBusiness(id, 'Deactivated by admin', actorId, logFn));
export const adminBulkExpireBusinesses = async (ids: string[], actorId: string, logFn: AdminLogFn) => execBulk(ids, 'expire', (id) => expireAdminBusiness(id, actorId, logFn));
export const adminBulkRenewBusinesses = async (ids: string[], actorId: string, logFn: AdminLogFn) => execBulk(ids, 'renew', (id) => renewAdminBusiness(id, actorId, logFn));

export const adminBulkResendBusinessWarnings = async (ids: string[], actorId: string, logFn: AdminLogFn) => {
    if (!Array.isArray(ids) || ids.length === 0) throw new AppError('A non-empty list of business IDs is required', 400);
    const results: Array<{ id: string; success: boolean; message?: string }> = [];
    for (const id of ids) {
        try {
            const biz = await Business.findById(id);
            if (!biz) throw new AppError('Business not found', 404);
            await dispatchTemplatedNotification(biz.userId.toString(), 'BUSINESS_STATUS', 'BUSINESS_EXPIRY_WARNING_3D', { name: biz.name, date: biz.expiresAt?.toLocaleDateString() || 'N/A' }, { businessId: biz._id.toString() });
            biz.expiryWarningSentAt = new Date(); biz.expiryWarningCount = (biz.expiryWarningCount || 0) + 1; biz.lastExpiryWarningChannel = 'in-app'; await biz.save();
            await logFn('expiry_warning_resent', 'ExpiryWarning', id, { entityType: 'Business', adminId: actorId });
            results.push({ id, success: true });
        } catch (error) { results.push({ id, success: false, message: error instanceof Error ? error.message : String(error) }); }
    }
    return { processedCount: ids.length, successCount: results.filter(r => r.success).length, errorCount: results.filter(r => !r.success).length, results };
};

import { AppError } from '../../utils/AppError';
import { dispatchTemplatedNotification } from '../NotificationService';
import Ad from '../../models/Ad';
import type { AdminLogFn } from './types';
import {
    adminApproveListing, adminRejectListing, adminDeactivateListing,
    adminExpireListing, adminExtendListing,
} from './mutations';
import { validateListingId } from './helpers';

const executeAdminListingsBulkOperation = async <T>(
    ids: string[],
    actionFn: (id: string) => Promise<T>,
    includeResults: boolean = true
) => {
    if (!Array.isArray(ids) || ids.length === 0) throw new AppError('A non-empty list of listing IDs is required', 400);
    const results: Array<{ id: string; success: boolean; message?: string; statusCode?: number; listing?: unknown }> = [];
    for (const id of ids) {
        try {
            const updated = await actionFn(id);
            results.push({ id, success: true, listing: (updated as any)?.listing || updated });
        } catch (error) {
            results.push({ id, success: false, message: error instanceof Error ? error.message : String(error), statusCode: (error as any).statusCode || 500 });
        }
    }
    const response: any = { processedCount: ids.length, successCount: results.filter(r => r.success).length, errorCount: results.filter(r => !r.success).length };
    if (includeResults) response.results = results;
    return response;
};

export const adminBulkApproveListings = async (ids: string[], actorId: string, logFn: AdminLogFn) =>
    executeAdminListingsBulkOperation(ids, id => adminApproveListing(id, actorId, logFn), true);

export const adminBulkRejectListings = async (ids: string[], actorId: string, rejectionReason: string, logFn: AdminLogFn) => {
    if (!rejectionReason || !rejectionReason.trim()) throw new AppError('Rejection reason is required for bulk rejection', 400);
    return executeAdminListingsBulkOperation(ids, id => adminRejectListing(id, actorId, rejectionReason, logFn), true);
};

export const adminBulkDeactivateListings = async (ids: string[], actorId: string, logFn: AdminLogFn) =>
    executeAdminListingsBulkOperation(ids, id => adminDeactivateListing(id, actorId, logFn), false);

export const adminBulkExpireListings = async (ids: string[], actorId: string, logFn: AdminLogFn) =>
    executeAdminListingsBulkOperation(ids, id => adminExpireListing(id, actorId, logFn), false);

export const adminBulkExtendListings = async (ids: string[], actorId: string, logFn: AdminLogFn) =>
    executeAdminListingsBulkOperation(ids, id => adminExtendListing(id, actorId, logFn), false);

export const adminBulkResendListingWarnings = async (ids: string[], actorId: string, logFn: AdminLogFn) =>
    executeAdminListingsBulkOperation(ids, async (id) => {
        validateListingId(id);
        const ad = await Ad.findById(id);
        if (!ad) throw new AppError('Listing not found', 404);
        await dispatchTemplatedNotification(ad.sellerId.toString(), 'SYSTEM', 'LISTING_EXPIRY_WARNING_3D', { title: ad.title, date: ad.expiresAt?.toLocaleDateString() || 'N/A' }, { adId: ad._id.toString() });
        ad.expiryWarningSentAt = new Date();
        ad.expiryWarningCount = (ad.expiryWarningCount || 0) + 1;
        ad.lastExpiryWarningChannel = 'in-app';
        await ad.save();
        await logFn('expiry_warning_resent', 'ExpiryWarning', id, { entityType: 'Ad', adminId: actorId });
        return null;
    }, true);

export const adminBulkResendSpotlightWarnings = async (ids: string[], actorId: string, logFn: AdminLogFn) =>
    executeAdminListingsBulkOperation(ids, async (id) => {
        validateListingId(id);
        const ad = await Ad.findById(id);
        if (!ad) throw new AppError('Listing not found', 404);
        if (!ad.isSpotlight) throw new AppError('Listing is not in spotlight', 400);
        await dispatchTemplatedNotification(ad.sellerId.toString(), 'SYSTEM', 'SPOTLIGHT_EXPIRY_WARNING_3D', { title: ad.title, date: ad.spotlightExpiresAt?.toLocaleDateString() || 'N/A' }, { adId: ad._id.toString(), type: 'spotlight' });
        ad.spotlightWarningSentAt = new Date();
        ad.spotlightWarningCount = (ad.spotlightWarningCount || 0) + 1;
        await ad.save();
        await logFn('expiry_warning_resent', 'SpotlightPromotion', id, { type: 'spotlight', adminId: actorId });
        return null;
    }, true);

