export const resolveOrCreateBrand = async (request: ICatalogRequest, session: ClientSession): Promise<{ entityId: Types.ObjectId; createdCanonicalEntity: boolean }> => {
    const requestCanonicalName = resolveRequestCanonicalName(request);
    let existingBrand = await Brand.findOne({
        canonicalName: requestCanonicalName, ...NON_DELETED_QUERY,
        approvalStatus: { $in: [CATALOG_APPROVAL_STATUS.APPROVED, CATALOG_APPROVAL_STATUS.PENDING] },
    }).session(session);
    if (existingBrand) {
        await ensureEntityActiveAndTrusted(existingBrand, request, session, { createdCanonicalEntity: false });
        return { entityId: existingBrand._id as Types.ObjectId, createdCanonicalEntity: false };
    }
    try {
        const created = await Brand.create([{
            name: request.requestedName, displayName: request.requestedName, canonicalName: requestCanonicalName,
            slug: buildCatalogSlug(request.requestedName, 'brand'), categoryIds: [request.categoryId],
            isActive: true, approvalStatus: CATALOG_APPROVAL_STATUS.APPROVED, status: CATALOG_STATUS.ACTIVE,
            suggestedBy: request.requestedBy,
            marketplaceTrust: buildApprovalTrustMetadata({ requestCount: request.requestCount, createdCanonicalEntity: true }),
        }], { session });
        return { entityId: created[0]._id as Types.ObjectId, createdCanonicalEntity: true };
    } catch (error: any) {
        if (error.code !== 11000) throw error;
        existingBrand = await Brand.findOne({ canonicalName: requestCanonicalName, ...NON_DELETED_QUERY, approvalStatus: { $in: [CATALOG_APPROVAL_STATUS.APPROVED, CATALOG_APPROVAL_STATUS.PENDING] } }).session(session);
        if (!existingBrand) throw error;
        await ensureEntityActiveAndTrusted(existingBrand, request, session, { createdCanonicalEntity: false });
        return { entityId: existingBrand._id as Types.ObjectId, createdCanonicalEntity: false };
    }
};

export const resolveOrCreateModel = async (request: ICatalogRequest, session: ClientSession): Promise<{ entityId: Types.ObjectId; createdCanonicalEntity: boolean }> => {
    if (!request.parentBrandId) throw new AppError('Model requests require a parentBrandId.', 400, 'CATALOG_REQUEST_PARENT_BRAND_REQUIRED');
    const requestCanonicalName = resolveRequestCanonicalName(request);
    let existingModel = await CatalogModel.findOne({
        brandId: request.parentBrandId, canonicalName: requestCanonicalName, ...NON_DELETED_QUERY,
        approvalStatus: { $in: [CATALOG_APPROVAL_STATUS.APPROVED, CATALOG_APPROVAL_STATUS.PENDING] },
    }).session(session);
    if (existingModel) {
        await ensureEntityActiveAndTrusted(existingModel, request, session, { createdCanonicalEntity: false });
        return { entityId: existingModel._id as Types.ObjectId, createdCanonicalEntity: false };
    }
    try {
        const created = await CatalogModel.create([{
            name: request.requestedName, displayName: request.requestedName, canonicalName: requestCanonicalName,
            slug: buildCatalogSlug(request.requestedName, 'model'), brandId: request.parentBrandId,
            categoryIds: [request.categoryId], isActive: true, approvalStatus: CATALOG_APPROVAL_STATUS.APPROVED,
            status: CATALOG_STATUS.ACTIVE, suggestedBy: request.requestedBy,
            marketplaceTrust: buildApprovalTrustMetadata({ requestCount: request.requestCount, createdCanonicalEntity: true }),
        }], { session });
        return { entityId: created[0]._id as Types.ObjectId, createdCanonicalEntity: true };
    } catch (error: any) {
        if (error.code !== 11000) throw error;
        existingModel = await CatalogModel.findOne({ brandId: request.parentBrandId, canonicalName: requestCanonicalName, ...NON_DELETED_QUERY, approvalStatus: { $in: [CATALOG_APPROVAL_STATUS.APPROVED, CATALOG_APPROVAL_STATUS.PENDING] } }).session(session);
        if (!existingModel) throw error;
        await ensureEntityActiveAndTrusted(existingModel, request, session, { createdCanonicalEntity: false });
        return { entityId: existingModel._id as Types.ObjectId, createdCanonicalEntity: false };
    }
};

export const resolveDuplicateEntity = async (request: ICatalogRequest, duplicateOfEntityId: Types.ObjectId, session: ClientSession): Promise<Types.ObjectId> => {
    if (request.requestType === 'brand') {
        const brand = await Brand.findOne({ _id: duplicateOfEntityId, ...NON_DELETED_QUERY }).session(session);
        if (!brand) throw new AppError('Duplicate target brand was not found.', 404, 'DUPLICATE_ENTITY_NOT_FOUND');
        await ensureEntityActiveAndTrusted(brand, request, session, { duplicateResolution: true });
        return brand._id as Types.ObjectId;
    }
    const model = await CatalogModel.findOne({ _id: duplicateOfEntityId, ...NON_DELETED_QUERY }).session(session);
    if (!model) throw new AppError('Duplicate target model was not found.', 404, 'DUPLICATE_ENTITY_NOT_FOUND');
    if (request.parentBrandId && String(model.brandId) !== String(request.parentBrandId)) throw new AppError('Duplicate model must belong to the requested parent brand.', 400, 'DUPLICATE_ENTITY_BRAND_MISMATCH');
    await ensureEntityActiveAndTrusted(model, request, session, { duplicateResolution: true });
    return model._id as Types.ObjectId;
};

import type { Document, Model } from 'mongoose';
import logger from '../../utils/logger';
import { escapeRegExp } from '../../utils/stringUtils';
import type { AtlasCatalogSearchResult, SeoCrawlDecision } from './types';
import {
    normalizeCatalogSearchText,
    compact,
} from './transliteration';
import { telemetry } from './telemetry';
import { getTrustSignals } from './scoring';

const MAX_SEARCH_VARIANTS = 5;
const MAX_ATLAS_SHOULD_CLAUSES = 36;
const MIN_SEO_INDEX_QUALITY = 0.52;
const MAX_SEO_CRAWL_DEPTH = 4;

export function buildSearchVariants(search: string): string[] {
    const normalized = normalizeCatalogSearchText(search);
    const collapsed = compact(normalized);
    const variants: string[] = [];
    const pushVariant = (value: string) => {
        const normalizedValue = normalizeCatalogSearchText(value);
        if (normalizedValue.length < 2) return;
        if (!variants.includes(normalizedValue)) variants.push(normalizedValue);
    };

    pushVariant(search.trim());
    if (normalized) pushVariant(normalized);
    if (collapsed && collapsed !== normalized && collapsed.length >= 4) pushVariant(collapsed);

    if (normalized.length >= 4) {
        pushVariant(normalized.replace(/\biphne\b/g, 'iphone'));
        pushVariant(normalized.replace(/\bsamung\b/g, 'samsung'));
    }
    if (normalized.length >= 6) {
        pushVariant(normalized.replace(/dh/g, 'd'));
        pushVariant(normalized.replace(/dy/g, 'di'));
    }

    return variants.slice(0, MAX_SEARCH_VARIANTS);
}

export function buildRegexSearchClauses(search: string, searchFields: string[]): Record<string, unknown>[] {
    const variants = buildSearchVariants(search);
    const clauses: Record<string, unknown>[] = [];
    for (const variant of variants) {
        const safeSearch = escapeRegExp(variant);
        for (const field of searchFields) {
            clauses.push({ [field]: { $regex: safeSearch, $options: 'i' } });
        }
    }
    return clauses;
}

export async function tryAtlasCatalogSearch(params: {
    model: Model<Document>;
    query: Record<string, unknown>;
    search: string;
    searchFields: string[];
    skip: number;
    limit: number;
    indexName?: string;
}): Promise<AtlasCatalogSearchResult | null> {
    const variants = buildSearchVariants(params.search);
    if (variants.length === 0) return null;
    const queryCost = variants.length * params.searchFields.length;
    telemetry.queryCostUnits += queryCost;
    if (queryCost > MAX_ATLAS_SHOULD_CLAUSES) { telemetry.atlasFallbacks++; return null; }
    telemetry.atlasAttempts++;

    try {
        const should = variants.flatMap((query) => params.searchFields.map((path) => ({
            text: {
                query,
                path,
                fuzzy: { maxEdits: query.length > 7 ? 2 : 1, prefixLength: Math.min(3, Math.max(1, query.length - 2)) },
                score: { boost: { value: path === 'canonicalName' ? 12 : path === 'slug' ? 10 : path === 'displayName' || path === 'name' ? 7 : 3 } },
            },
        }))).slice(0, MAX_ATLAS_SHOULD_CLAUSES);

        const filterClauses: Record<string, any>[] = [];
        const mustNotClauses: Record<string, any>[] = [];
        const MAPPED_ATLAS_FIELDS = new Set(['isActive', 'isDeleted', 'approvalStatus', 'categoryIds', 'brandId', 'parentModelId', 'variantOfModelId', 'type']);

        for (const [key, rawVal] of Object.entries(params.query)) {
            let targetPath = key;
            if (key === 'categoryId') targetPath = 'categoryIds';
            if (key === 'variantModelId') targetPath = 'variantOfModelId';
            if (!MAPPED_ATLAS_FIELDS.has(targetPath)) continue;

            if (rawVal && typeof rawVal === 'object' && !Array.isArray(rawVal) && !(rawVal instanceof Date)) {
                const keys = Object.keys(rawVal);
                if (keys.length === 1) {
                    const op = keys[0];
                    const opVal = (rawVal as Record<string, any>)[op];
                    if (op === '$ne') {
                        mustNotClauses.push({ equals: { path: targetPath, value: typeof opVal === 'object' && opVal ? String(opVal) : opVal } });
                    } else if (op === '$in' && Array.isArray(opVal)) {
                        filterClauses.push({ in: { path: targetPath, value: opVal.map((v: any) => typeof v === 'object' && v ? String(v) : v) } });
                    } else if (op === '$nin' && Array.isArray(opVal)) {
                        mustNotClauses.push({ in: { path: targetPath, value: opVal.map((v: any) => typeof v === 'object' && v ? String(v) : v) } });
                    }
                }
            } else if (Array.isArray(rawVal)) {
                filterClauses.push({ in: { path: targetPath, value: rawVal.map((v: any) => typeof v === 'object' && v ? String(v) : v) } });
            } else {
                filterClauses.push({ equals: { path: targetPath, value: typeof rawVal === 'object' && rawVal ? String(rawVal) : rawVal } });
            }
        }

        const compound: Record<string, any> = { should, minimumShouldMatch: 1 };
        if (filterClauses.length > 0) compound.filter = filterClauses;
        if (mustNotClauses.length > 0) compound.mustNot = mustNotClauses;

        const atlasStartedAt = Date.now();
        const rows = await params.model.aggregate([
            { $search: { index: params.indexName || process.env.ATLAS_CATALOG_SEARCH_INDEX || 'catalog_search', compound } },
            { $match: params.query },
            { $skip: params.skip },
            { $limit: params.limit },
            { $project: { _id: 1, score: { $meta: 'searchScore' } } },
        ]).option({ maxTimeMS: Number(process.env.ATLAS_CATALOG_SEARCH_TIMEOUT_MS || 1200) });
        telemetry.atlasLatencyMs += Date.now() - atlasStartedAt;

        const scores = new Map<string, number>();
        const ids = rows.map((row) => { const id = String(row._id); scores.set(id, Number(row.score ?? 0)); return id; });
        return { ids, scores };
    } catch (error) {
        telemetry.atlasFallbacks++;
        logger.warn('[CatalogSearch] Atlas Search unavailable; using governed regex fallback', {
            modelName: params.model.modelName,
            error: error instanceof Error ? error.message : String(error),
        });
        return null;
    }
}

export function buildSeoCanonicalPath(item: Record<string, unknown>): string | null {
    const segments = [item.categorySlug, item.brandSlug, item.parentSlug, item.slug]
        .map((segment) => normalizeCatalogSearchText(segment as string | undefined).replace(/\s+/g, '-'))
        .filter(Boolean);
    if (segments.length === 0) return null;
    return `/${segments.join('/')}`;
}

export function evaluateSeoCrawlDecision(item: Record<string, unknown>): SeoCrawlDecision {
    const canonicalPath = buildSeoCanonicalPath(item);
    const trust = getTrustSignals(item);
    const segments = canonicalPath ? canonicalPath.split('/').filter(Boolean) : [];
    const crawlDepth = segments.length;
    const reasons: string[] = [];
    const canonicalName = normalizeCatalogSearchText(item.canonicalName as string | undefined);
    const displayName = normalizeCatalogSearchText((item.displayName ?? item.name) as string | undefined);
    const descriptionLength = String(item.description ?? '').trim().length;
    const hasLineage = Boolean(item.categorySlug || item.brandSlug || item.parentSlug || item.modelId || item.brandId);
    const duplicateConfidence = trust.duplicateConfidenceScore ?? 0.5;
    let qualityScore = clamp01(trust.seoQualityScore, 0.6);

    if (!canonicalPath) { reasons.push('missing_canonical_path'); qualityScore -= 0.3; }
    if (crawlDepth > Math.min(MAX_SEO_CRAWL_DEPTH, trust.crawlDepthLimit ?? MAX_SEO_CRAWL_DEPTH)) { reasons.push('crawl_depth_exceeded'); telemetry.crawlBudgetSuppressions++; qualityScore -= 0.25; }
    if (!canonicalName || canonicalName === displayName && descriptionLength < 80) { reasons.push('thin_content'); telemetry.seoThinPageSuppressions++; qualityScore -= 0.2; }
    if (!hasLineage) { reasons.push('weak_lineage'); qualityScore -= 0.15; }
    if (duplicateConfidence > 0.72) { reasons.push('duplicate_seo_risk'); qualityScore -= 0.25; }
    if (trust.indexable === false) { reasons.push('explicit_noindex'); qualityScore = 0; }

    const finalQuality = clamp01(qualityScore, 0.6);
    telemetry.crawlQualityTotal += finalQuality;
    return {
        indexable: finalQuality >= MIN_SEO_INDEX_QUALITY && !reasons.includes('crawl_depth_exceeded') && !reasons.includes('explicit_noindex'),
        canonicalPath, qualityScore: finalQuality, crawlDepth, reasons,
    };
}

const clamp01 = (value: unknown, fallback = 0.5): number => {
    const numeric = Number(value);
    if (!Number.isFinite(numeric)) return fallback;
    return Math.min(1, Math.max(0, numeric));
};

export { MAX_SEARCH_VARIANTS, MAX_ATLAS_SHOULD_CLAUSES, MIN_SEO_INDEX_QUALITY, MAX_SEO_CRAWL_DEPTH };

/**
 * CatalogCategoryService
 * DB operations for Category management.
 * Also owns the multi-model entity count query used by the admin dashboard.
 */

import mongoose, { type Model as MongooseModel } from 'mongoose';
import Category from '../../models/Category';
import Brand from '../../models/Brand';
import CatalogModel from '../../models/Model';
import SparePart from '../../models/SparePart';
import ServiceType from '../../models/ServiceType';
import ScreenSize from '../../models/ScreenSize';
import logger from '../../utils/logger';

// Re-export the Category model so controllers can pass it to generic handler
// utilities (handlePaginatedContent, handleCatalogToggleStatus) without importing
// from models/ directly.
export { default as CategoryModel } from '../../models/Category';

// ─── Catalog-wide counts ──────────────────────────────────────────────────────

const CATALOG_COUNT_MAX_TIME_MS = 1500;
const CATALOG_COUNT_ESTIMATE_MAX_TIME_MS = 1000;

async function countCatalogCollectionSafely(
    model: MongooseModel<unknown>,
    filter: Record<string, unknown>,
    hint?: Record<string, 1 | -1>
): Promise<number> {
    const modelName = model.modelName || 'Unknown';
    const countOptions: Record<string, unknown> = {
        maxTimeMS: CATALOG_COUNT_MAX_TIME_MS,
        ...(hint ? { hint } : {})
    };
    try {
        return await model.collection.countDocuments(filter, countOptions);
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        const isHintError = Boolean(hint) && /hint|index/i.test(message);
        if (isHintError) {
            try {
                return await model.collection.countDocuments(filter, { maxTimeMS: CATALOG_COUNT_MAX_TIME_MS });
            } catch (retryError) {
                logger.warn('[CatalogCounts] countDocuments retry without hint failed; using estimate', {
                    model: modelName,
                    error: retryError instanceof Error ? retryError.message : String(retryError)
                });
            }
        } else {
            logger.warn('[CatalogCounts] countDocuments failed; using estimate', { model: modelName, error: message });
        }
        return model.collection.estimatedDocumentCount({ maxTimeMS: CATALOG_COUNT_ESTIMATE_MAX_TIME_MS });
    }
}

export async function getCatalogEntityCounts() {
    const nonDeletedFilter = { isDeleted: { $ne: true } };
    const [categories, brands, models, spareParts, serviceTypes, screenSizes] = await Promise.all([
        countCatalogCollectionSafely(Category, nonDeletedFilter, { isDeleted: 1 }),
        countCatalogCollectionSafely(Brand, nonDeletedFilter, { isDeleted: 1 }),
        countCatalogCollectionSafely(CatalogModel, nonDeletedFilter, { isDeleted: 1 }),
        countCatalogCollectionSafely(SparePart, nonDeletedFilter, { isDeleted: 1 }),
        countCatalogCollectionSafely(ServiceType, nonDeletedFilter, { isDeleted: 1 }),
        countCatalogCollectionSafely(ScreenSize, nonDeletedFilter, { isDeleted: 1 })
    ]);
    return { categories, brands, models, spareParts, serviceTypes, screenSizes };
}

// ─── Category queries ─────────────────────────────────────────────────────────

export const findCategoryById = async (id: string | undefined, extraQuery: Record<string, unknown> = {}) => {
    if (!id) return null;
    return Category.findOne({ _id: id, ...extraQuery });
};

export const categoryParentExists = async (parentId: string | undefined) => {
    if (!parentId) return false;
    return Category.exists({ _id: parentId });
};

export const updateCategorySchemaById = async (id: string | undefined, filters: unknown[]) => {
    if (!id) return null;
    return Category.findByIdAndUpdate(id, { filters }, { new: true, runValidators: true });
};

import { Category, Brand } from '../../domains/catalog';

// @todo ARCH-118: Transitional types until all consumers are migrated to strict domain models.
export type CategoryResult = Category & Record<string, unknown>;
export type BrandResult = Brand & Record<string, unknown>;


import logger from '../../utils/logger';
import { isDuplicateKeyError } from '../../utils/errorHelpers';
import { AppError } from '../../utils/AppError';
import { 
    CatalogUnitOfWorkPort,
    TransactionContext,
    CatalogCachePort,
    CategoryRepositoryPort, 
    BrandRepositoryPort, 
    ModelRepositoryPort, 
    SparePartRepositoryPort,
    ScreenSizeRepositoryPort
} from '../../domains/catalog';

// isDuplicateKeyError imported from errorHelpers (SSOT)

const toUniqueCategoryIds = (
    categoryIds: readonly string[] | undefined,
    deletedCategoryId: string
): string[] => {
    if (!Array.isArray(categoryIds) || categoryIds.length === 0) return [];
    const deduped = new Set<string>();
    for (const categoryId of categoryIds) {
        const id = String(categoryId);
        if (id === deletedCategoryId) continue;
        deduped.add(id);
    }
    return Array.from(deduped);
};

/**
 * CatalogOrchestrator
 * 
 * The Single Source of Truth (SSOT) for catalog domain orchestration.
 * Consolidates CRUD operations, cache management, and hierarchy integrity.
 */
export class CatalogOrchestratorImpl {
    constructor(
        private readonly unitOfWork: CatalogUnitOfWorkPort,
        private readonly cacheService: CatalogCachePort,
        private readonly categoryRepository: CategoryRepositoryPort,
        private readonly brandRepository: BrandRepositoryPort,
        private readonly modelRepository: ModelRepositoryPort,
        private readonly sparePartRepository: SparePartRepositoryPort,
        private readonly screenSizeRepository: ScreenSizeRepositoryPort
    ) {}
    /**
     * Invalidate catalog caches, optionally scoped by category or brand
     */
    async invalidateCatalogCache(opts?: { categoryIds?: any[], brandIds?: any[] }) {
        const cleanOpts = opts ? {
            categoryIds: opts.categoryIds ? opts.categoryIds.map(id => String(id)) : undefined,
            brandIds: opts.brandIds ? opts.brandIds.map(id => String(id)) : undefined
        } : undefined;
        await this.cacheService.invalidateCatalogCache(cleanOpts);
    }

    /**
     * Cascade Category soft-delete to Brands, Models, and deactivation of Parts
     */
    async cascadeCategoryDelete(categoryId: string, session?: TransactionContext) {
        const txSession = session || null;
        const brandIdsToDelete: string[] = [];

        // 1) Brands: detach deleted category when other categories exist; soft-delete only true orphans.
        const linkedBrands = await this.brandRepository.findByCategory(categoryId, txSession);

        for (const brand of linkedBrands) {
            const remainingCategoryIds = toUniqueCategoryIds(brand.categoryIds, categoryId);
            if (remainingCategoryIds.length === 0) {
                brandIdsToDelete.push(brand.id);
                continue;
            }

            try {
                await this.brandRepository.updateCategoryIds(brand.id, remainingCategoryIds, txSession);
            } catch (error) {
                // Keep uniqueness intact; if remap collides, safely archive this duplicate branch.
                if (isDuplicateKeyError(error)) {
                    brandIdsToDelete.push(brand.id);
                    continue;
                }
                throw error;
            }
        }

        if (brandIdsToDelete.length > 0) {
            await this.brandRepository.softDeleteMany(brandIdsToDelete, txSession);
        }

        // 2) Models: never delete by brand sweep unless brand is actually archived.
        //    Prefer detaching deleted category; soft-delete only if model becomes orphaned.
        const affectedModels = await this.modelRepository.findByCategoryOrBrands(categoryId, brandIdsToDelete, txSession);

        const modelIdsToDelete: string[] = [];
        const deletedBrandIdSet = new Set(brandIdsToDelete);

        for (const model of affectedModels) {
            if (model.brandId && deletedBrandIdSet.has(model.brandId)) {
                modelIdsToDelete.push(model.id);
                continue;
            }

            const remainingCategoryIds = toUniqueCategoryIds(model.categoryIds, categoryId);
            
            if (remainingCategoryIds.length === 0) {
                modelIdsToDelete.push(model.id);
                continue;
            }

            await this.modelRepository.updateCategoryIds(model.id, remainingCategoryIds, txSession);
        }

        if (modelIdsToDelete.length > 0) {
            await this.modelRepository.softDeleteMany(modelIdsToDelete, txSession);
        }

        // 3) SpareParts: detach category when possible; soft-delete only if no category remains
        //    or if parent brand is archived by this cascade.
        const affectedSpareParts = await this.sparePartRepository.findByCategoryOrBrands(categoryId, brandIdsToDelete, txSession);

        const sparePartIdsToDelete: string[] = [];
        for (const sparePart of affectedSpareParts) {
            if (sparePart.brandId && deletedBrandIdSet.has(sparePart.brandId)) {
                sparePartIdsToDelete.push(sparePart.id);
                continue;
            }

            const remainingCategoryIds = toUniqueCategoryIds(sparePart.categoryIds, categoryId);
            if (remainingCategoryIds.length === 0) {
                sparePartIdsToDelete.push(sparePart.id);
                continue;
            }

            await this.sparePartRepository.updateCategoryIds(sparePart.id, remainingCategoryIds, txSession);
        }

        if (sparePartIdsToDelete.length > 0) {
            await this.sparePartRepository.softDeleteMany(sparePartIdsToDelete, txSession);
        }

        // 4) ScreenSizes: singular category link; keep cascading delete.
        await this.screenSizeRepository.softDeleteByCriteria(
            { categoryId, brandIds: brandIdsToDelete },
            txSession
        );

        await this.invalidateCatalogCache({ categoryIds: [categoryId], brandIds: brandIdsToDelete });
        logger.info('Cascaded category delete completed', {
            categoryId,
            brandsArchived: brandIdsToDelete.length,
            modelsArchived: modelIdsToDelete.length,
            sparePartsArchived: sparePartIdsToDelete.length,
        });
    }

    /**
     * Cascade Brand soft-delete to Models and SpareParts
     */
    async cascadeBrandDelete(brandId: string, session?: TransactionContext) {
        const txSession = session || null;

        // Find all models associated with this brand
        const models = await this.modelRepository.findByBrandId(brandId, txSession);
        const modelIds = models.map((m) => m.id);

        // Soft-delete those Models
        const deletedModels = await this.modelRepository.softDeleteByBrandId(brandId, txSession);

        let deletedSpareParts = 0;
        // Soft-delete SpareParts linked to those models
        if (modelIds.length > 0) {
            const count1 = await this.sparePartRepository.softDeleteByModelIds(modelIds, txSession);
            deletedSpareParts += count1;
        }

        // Soft-delete SpareParts linked to the brand directly
        const count2 = await this.sparePartRepository.softDeleteByBrandId(brandId, txSession);
        deletedSpareParts += count2;

        await this.invalidateCatalogCache({ brandIds: [brandId] });
        logger.info(`Cascaded soft-delete for brand: ${brandId}`);

        return {
            deletedModels,
            deletedSpareParts
        };
    }

    /**
     * Create Category with cache invalidation
     */
    async createCategory(data: any): Promise<CategoryResult> {
        const result = await this.categoryRepository.create(data);
        await this.invalidateCatalogCache({ categoryIds: [result.id] });
        return result as CategoryResult;
    }

    /**
     * Update Category with cache invalidation
     */
    async updateCategory(id: string, data: any): Promise<CategoryResult | null> {
        const result = await this.categoryRepository.update(id, data);
        if (result) await this.invalidateCatalogCache({ categoryIds: [id] });
        return result as CategoryResult;
    }


    /**
     * Resolve all CategoryIDs from a BrandID
     */
    async resolveCategoryIdsFromBrand(brandId: string): Promise<string[]> {
        const brand = await this.brandRepository.findById(brandId);
        if (!brand || !brand.categoryIds) return [];
        return brand.categoryIds.map(id => String(id));
    }

    /**
     * Resolve a deterministic primary CategoryID from a BrandID.
     */
    async resolvePrimaryCategoryIdFromBrand(brandId: string): Promise<string | null> {
        const ids = await this.resolveCategoryIdsFromBrand(brandId);
        return ids.length > 0 ? (ids[0] ?? null) : null;
    }

    /**
     * Detach SpareParts from a specific Model
     */
    async detachSparePartsFromModel(modelId: string, session?: TransactionContext) {
        await this.sparePartRepository.clearModelReferences(modelId, session);
        
        logger.info(`Detached spare parts from model: ${modelId}`);
    }

    async deleteCategoryOrchestrated(categoryId: string): Promise<CategoryResult> {
        return this.unitOfWork.executeTransaction(async (txSession) => {
            const category = await this.categoryRepository.findById(categoryId, txSession);

            if (!category) {
                throw new AppError('Category not found', 404, 'CATEGORY_NOT_FOUND');
            }

            await this.categoryRepository.softDelete(categoryId, txSession);
            await this.cascadeCategoryDelete(categoryId, txSession);

            return await this.categoryRepository.findById(categoryId, txSession) as CategoryResult;
        });
    }

    async deleteBrandOrchestrated(brandId: string) {
        const existingBrand = await this.brandRepository.findById(brandId, true);
        if (!existingBrand || existingBrand.isDeleted) {
            return { brandId, deletedModels: 0, deletedSpareParts: 0, alreadyDeleted: true };
        }

        const { checkBrandDependencies } = require('../../services/catalog/CatalogBrandModelService');
        const deps = await checkBrandDependencies(brandId);
        if (deps.count > 0) {
            throw new AppError('Brand cannot be deleted because dependencies exist', 409, 'DEPENDENCIES_EXIST', deps.details);
        }

        return this.unitOfWork.executeTransaction(async (txSession) => {
            const brand = txSession 
                ? await this.brandRepository.softDelete(brandId, txSession)
                : await this.brandRepository.softDelete(brandId);

            if (!brand) return { deletedModels: 0, deletedSpareParts: 0, brand: null };
            const cascadeRes = await this.cascadeBrandDelete(brandId, txSession ?? undefined);
            return { brandId, deletedModels: cascadeRes.deletedModels, deletedSpareParts: cascadeRes.deletedSpareParts, alreadyDeleted: false };
        });
    }
}

let serviceInstance: CatalogOrchestratorImpl | null = null;

export function initializeCatalogOrchestrator(instance: CatalogOrchestratorImpl) {
    serviceInstance = instance;
}

function getServiceInstance(): CatalogOrchestratorImpl {
    if (!serviceInstance) {
        const { MongoCatalogUnitOfWorkAdapter } = require('../../adapters/outbound/database/catalog/MongoCatalogUnitOfWorkAdapter');
        const { RedisCatalogCacheAdapter } = require('../../adapters/outbound/database/catalog/RedisCatalogCacheAdapter');
        const { MongoCategoryRepositoryAdapter } = require('../../adapters/outbound/database/catalog/MongoCategoryRepositoryAdapter');
        const { MongoBrandRepositoryAdapter } = require('../../adapters/outbound/database/catalog/MongoBrandRepositoryAdapter');
