import { chatRepository } from '../../composition/chat';
import { isListingChatClosed } from '../ChatAvailabilityService';
import logger from '../../utils/logger';
import { NOTIFICATION_TYPE } from '@esparex/shared';
import type { IChatAttachment } from '../../models/ChatMessage';
import {
    PAGE_SIZE_MESSAGES,
    sanitizeText,
    detectBadWords,
    computeRiskScore,
    maskSensitiveData,
    buildConversationPreview
} from './ChatUtils';

export async function getMessages(
    conversationId: string,
    userId: string,
    before?: string,
    after?: string
) {
    return await chatRepository.findMessages(conversationId, userId, before, after);
}

export async function sendMessage(
    conversationId: string,
    senderId: string,
    rawText: string,
    attachments: IChatAttachment[] = []
) {
    const conv = await chatRepository.findConversationById(conversationId);
    if (!conv) throw Object.assign(new Error('Conversation not found'), { status: 404 });
    const listing = await chatRepository.getAdChatInfo(String(conv.adId));
    const derivedClosed = isListingChatClosed(listing);

    if (conv.isAdClosed !== derivedClosed) {
        await chatRepository.updateConversationAdClosedStatus(conversationId, derivedClosed);
    }

    const buyerStr = String(conv.buyerId);
    const sellerStr = String(conv.sellerId);

    if (senderId !== buyerStr && senderId !== sellerStr) {
        throw Object.assign(new Error('Forbidden'), { status: 403 });
    }
    if (conv.isBlocked) throw Object.assign(new Error('This chat has been blocked'), { status: 403, code: 'CHAT_BLOCKED' });
    if (derivedClosed) throw Object.assign(new Error('This ad is closed — chat is read-only'), { status: 403, code: 'CHAT_CLOSED' });

    const receiverId = senderId === buyerStr ? sellerStr : buyerStr;

    const sanitized = sanitizeText(rawText);
    const badWordDetected = detectBadWords(sanitized);
    const riskScore = computeRiskScore(sanitized);
    const storedText = maskSensitiveData(sanitized);

    const msg = await chatRepository.createMessage({
        conversationId,
        senderId,
        receiverId,
        text: storedText,
        attachments,
        riskScore,
        badWordDetected,
    });

    const unreadField = receiverId === buyerStr ? 'unreadBuyer' : 'unreadSeller';
    const preview = buildConversationPreview(storedText, attachments);
    
    await chatRepository.updateConversationPreview(
        conversationId,
        unreadField,
        senderId,
        preview,
        msg.createdAt
    );

    // 📣 NOTIFY RECEIVER (Push + In-App)
    void (async () => {
        try {
            const { dispatchTemplatedNotification } = await import('../NotificationService');
            const UserModel = (await import('@esparex/core/models/User')).default;
            const senderSnippet = await UserModel.findById(senderId).select('name').lean();
            
            await dispatchTemplatedNotification(
                receiverId,
                NOTIFICATION_TYPE.CHAT,
                'NEW_CHAT_MESSAGE',
                { 
                    senderName: (senderSnippet as { name?: string })?.name || 'User',
                    text: storedText.length > 50 ? `${storedText.substring(0, 47)}...` : storedText
                },
                { conversationId, type: 'chat_message' }
            );
        } catch (err) {
            logger.error('Failed to dispatch chat notification', { error: err });
        }
    })();

    if (riskScore >= 0.8) {
        await chatRepository.createSystemMessage({
            conversationId,
            senderId,
            receiverId,
            text: '⚠️ This message was flagged for review by our safety system.',
        });
    }

    return msg;
}

export async function markRead(conversationId: string, userId: string) {
    const conv = await chatRepository.findConversationById(conversationId);
    if (!conv) throw Object.assign(new Error('Conversation not found'), { status: 404 });

    const buyerStr = String(conv.buyerId);
    const sellerStr = String(conv.sellerId);
    if (userId !== buyerStr && userId !== sellerStr) {
        throw Object.assign(new Error('Forbidden'), { status: 403 });
    }

    await chatRepository.markMessagesRead(conversationId, userId);

    const unreadField = userId === buyerStr ? 'unreadBuyer' : 'unreadSeller';
    await chatRepository.resetUnreadCount(conversationId, unreadField);
}

import mongoose from 'mongoose';
import { env } from '../../config/env';
import Boost from '../../models/Boost';
import Category from '../../models/Category';
import { getListingRepository } from '../../composition/listings';
import type { ListingFilter, Listing } from '../../domains/listings/ports/ListingRepositoryPort';
import { buildPublicAdFilter } from '../../utils/FeedVisibilityGuard';
import { normalizeAdImagesForResponse } from '../adQuery/AdQueryHelpers';
import { normalizeGeoInput } from '../../utils/mongoGeoUtils';
import type { HomeFeedResponse } from "@esparex/shared";
import logger from '../../utils/logger';
import { FeedDecisionEngine } from '../FeedDecisionEngine';
import { HomeFeedRequest, ParsedHomeFeedCursor } from './FeedCursorService';
import { LISTING_TYPE } from '@esparex/shared';
import { toObjectId } from '../../utils/idUtils';
import { 
    filterBeforeCursor, 
    mergeRankedFeed, 
    extractAdId, 
    extractObjectIdHex 
} from './FeedRankerService';

interface FeedFacetResult {
    spotlight: Record<string, unknown>[];
    boosted: Record<string, unknown>[];
    organic: Record<string, unknown>[];
}

export const buildHomeFeed = async (
    input: HomeFeedRequest,
    limit: number,
    cursor: ParsedHomeFeedCursor | null
): Promise<HomeFeedResponse> => {
    const startedAt = Date.now();
    
    // 1. Resolve Match Criteria
    const baseFilter: ListingFilter = {
        listingType: LISTING_TYPE.AD,
    };

    if (typeof input.locationId === 'string' && mongoose.Types.ObjectId.isValid(input.locationId)) {
        baseFilter.locationId = input.locationId;
    } else if (typeof input.location === 'string' && input.location.trim().length > 0) {
        const safeLoc = input.location.trim().replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        if (input.level === 'state') {
            baseFilter.locationState = { $regex: `^${safeLoc}$`, $options: 'i' };
        } else if (input.level === 'city' || !input.level) {
            baseFilter.locationCity = { $regex: `^${safeLoc}$`, $options: 'i' };
        }
    }

    let resolvedCategoryId: string | undefined = undefined;
    if (typeof input.categoryId === 'string' && input.categoryId.trim().length > 0) {
        resolvedCategoryId = input.categoryId.trim();
    } else if (typeof input.category === 'string' && input.category.trim().length > 0) {
        const lookup = input.category.trim();
        const found = await Category.findOne({
            $or: [
                { slug: lookup.toLowerCase() },
                { name: { $regex: `^${lookup.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}$`, $options: 'i' } }
            ]
        }).select('_id').lean<{ _id: mongoose.Types.ObjectId } | null>();
        if (found) {
            resolvedCategoryId = found._id.toString();
        }
    }

    if (resolvedCategoryId) {
        baseFilter.categoryId = resolvedCategoryId;
    }

    const visibilityFilter = buildPublicAdFilter() as unknown as Partial<ListingFilter>;
    Object.assign(baseFilter, visibilityFilter);

    if (cursor) {
        baseFilter.cursorCreatedAt = cursor.createdAt;
        if (cursor.id) baseFilter.cursorId = cursor.id;
    }

    if (env.FEED_DEBUG) {
        logger.debug(`[FeedDebug] Final Match Filter`, { baseFilter });
    }

    // 2. Fetch Active Boosts (Fast Indexed Query)
    const now = new Date();
    const boostCandidates = await Boost.find({
        entityType: 'ad',
        isActive: true,
        startsAt: { $lte: now },
        endsAt: { $gt: now }
    })
        .select('entityId')
        .sort({ createdAt: -1 })
        .limit(200) // Safety cap
        .lean<Array<{ entityId?: mongoose.Types.ObjectId }>>();

    const boostedIds = boostCandidates
        .map((entry) => entry.entityId)
        .filter((id): id is mongoose.Types.ObjectId => id instanceof mongoose.Types.ObjectId);

    const { lat, lng, hasGeo } = normalizeGeoInput(input.lat, input.lng);
    const normalizedLevel = typeof input.level === 'string' ? input.level.toLowerCase() : undefined;
    const shouldUseGeo = hasGeo && normalizedLevel !== 'state' && normalizedLevel !== 'country';
    const safeRadius = shouldUseGeo 
        ? Math.min(Math.max(Number(input.radiusKm) || 50, 1), 500) 
        : 0;
    
    // 3. Unified Fetch via ListingRepositoryPort
    const spotlightFilter: ListingFilter = {
        ...baseFilter,
        isSpotlight: true,
        spotlightExpiresAt: { $gt: now }
    };
    
    const nonSpotlightFilter: ListingFilter = {
        ...baseFilter,
        $or: [
            { isSpotlight: { $ne: true } },
            { spotlightExpiresAt: { $exists: false } },
            { spotlightExpiresAt: null },
            { spotlightExpiresAt: { $lte: now } }
        ]
    };

    const boostedFilter: ListingFilter = {
        ...nonSpotlightFilter,
        ids: boostedIds.map(String)
    };

    const organicFilter: ListingFilter = {
        ...nonSpotlightFilter,
        idsNotIn: boostedIds.map(String)
    };

    const sortOption: Record<string, 1 | -1> = { createdAt: -1, _id: -1 };
    
    const fetch = async (filter: ListingFilter): Promise<readonly Listing[]> => {
        if (shouldUseGeo && lat !== undefined && lng !== undefined) {
            return getListingRepository().findWithinRadius(lng, lat, safeRadius, filter, sortOption, limit * 2);
        }
        return getListingRepository().findWithLimit(filter, sortOption, limit * 2);
    };

    const [spotlightListings, boostedListings, organicListings] = await Promise.all([
        fetch(spotlightFilter),
        fetch(boostedFilter),
        fetch(organicFilter)
    ]);

    const toFeedAd = (l: Listing, overrides: { isSpotlight: boolean, isBoosted: boolean }) => ({
        ...l,
        _id: l.id,
        ...overrides
    });

    const spotlightAds = filterBeforeCursor(
        spotlightListings.map(l => toFeedAd(l, { isSpotlight: true, isBoosted: false })),
        cursor
    );
    const boostedAds = filterBeforeCursor(
        boostedListings.map(l => toFeedAd(l, { isSpotlight: false, isBoosted: true })),
        cursor
    );
    const organicAds = filterBeforeCursor(
        organicListings.map(l => toFeedAd(l, { isSpotlight: false, isBoosted: false })),
        cursor
    );

    // 4. Merge results
    const merged = mergeRankedFeed(spotlightAds as Record<string, unknown>[], boostedAds as Record<string, unknown>[], organicAds as Record<string, unknown>[], limit);

    // 5. Fallback Logic
    let isFallbackResult = false;
    const isStrictLocation = Boolean(input.locationId || input.location || shouldUseGeo);

    if (!cursor && merged.ads.length < 4 && isStrictLocation) {
        isFallbackResult = true;
        const seenIds = new Set(merged.ads.map(extractAdId).filter(Boolean));

        const engineResult = await FeedDecisionEngine.getFallbackFeed(
            {
                locationId: input.locationId,
                city: typeof input.location === 'string' ? input.location.trim() : undefined,
                state: input.level === 'state' && typeof input.location === 'string' ? input.location.trim() : undefined,
                lat: shouldUseGeo ? input.lat : undefined,
                lng: shouldUseGeo ? input.lng : undefined,
            },
            Array.from(seenIds),
            limit - merged.ads.length,
            input.categoryId
        );

        const sortedBucket = engineResult.ads;
        for (const ad of sortedBucket) {
            if (merged.ads.length >= limit) break;
            const id = extractAdId(ad);
            if (!id || seenIds.has(id)) continue;
            seenIds.add(id);
            merged.ads.push(ad);
        }
    }

    const lastAd = merged.ads[merged.ads.length - 1];
    const lastAdCursor = lastAd
        ? {
            createdAt: new Date(String(lastAd.createdAt ?? '')).toISOString(),
            id: extractObjectIdHex(lastAd) || String(extractAdId(lastAd))
        }
        : null;

    logger.debug('Home feed build timings', { 
        durationMs: Date.now() - startedAt,
        adsCount: merged.ads.length,
        isFallback: isFallbackResult
    });

    return {
        ads: merged.ads.map(ad => normalizeAdImagesForResponse(ad as Record<string, unknown>)) as HomeFeedResponse['ads'],
        nextCursor: merged.hasRemaining ? lastAdCursor : null,
        hasMore: merged.hasRemaining && merged.ads.length > 0,
        isFallback: isFallbackResult
    };
};

import { getListingRepository } from '../../composition/listings';
import { LISTING_STATUS } from '@esparex/shared';
import { ACTOR_TYPE } from '@esparex/shared';
import { mutateStatusesBulk } from './StatusMutationService';
import { lifecycleEvents } from '../../events';
import logger from '../../utils/logger';

export type ListingExpirySweepResult = {
    expiredCount: number;
    touchedCount: number;
    listingIds: string[];
};

export class ListingExpiryService {
    static async runSweep(now: Date = new Date()): Promise<ListingExpirySweepResult> {
        const expiringListings = await getListingRepository().find({
            status: LISTING_STATUS.LIVE,
            expiresAt: { $lte: now } as any,
            isDeleted: false as any,
        });

        if (expiringListings.length === 0) {
            return {
                expiredCount: 0,
                touchedCount: 0,
                listingIds: [],
            };
        }

        const listingIds = expiringListings
            .map((doc) => doc.id)
            .filter((id) => id.length > 0);

        await getListingRepository().updateMany(
            { ids: listingIds },
            {
                isSpotlight: false,
                isChatLocked: true,
            }
        );

        const expiredCount = await mutateStatusesBulk(
            'ad',
            listingIds,
            LISTING_STATUS.EXPIRED,
            { type: ACTOR_TYPE.SYSTEM, id: 'listing_expiry_cron' },
            'Automated expiry'
        );

        await lifecycleEvents.dispatch('listing.expired.bulk', {
            count: expiredCount,
            listingIds,
            source: 'ListingExpiryService',
        });

        const { getListingsCache } = await import('../../composition/listings');
        await getListingsCache().invalidateAdFeedCaches();

        logger.info('[ListingExpiryService] Expiry sweep completed', {
            expiredCount,
            touchedCount: listingIds.length,
        });

        return {
            expiredCount,
            touchedCount: listingIds.length,
            listingIds,
        };
    }
}

import mongoose, { ClientSession } from 'mongoose';
import { 
    validateTransition as validateLifecycleTransition, 

    resolveLifecycleDomain,
    type ValidDomain 
} from './LifecycleGuard';
import { enforceLifecycleMutationPolicy } from './LifecyclePolicyGuard';
import StatusHistory from '../../models/StatusHistory';
import AdminMetrics from '../../models/AdminMetrics';
import logger from '../../utils/logger';
import { ActorMetadata, ACTOR_TYPE } from '@esparex/shared';
import { LISTING_STATUS } from '@esparex/shared';
import { lifecycleEvents } from '../../events';

// Import domain models
import Ad from '../../models/Ad';
import User from '../../models/User';
import Business from '../../models/Business';

export type { ValidDomain };

export interface MutationRequest {
    domain: ValidDomain;
    entityId: string | mongoose.Types.ObjectId;
    toStatus: string;
    actor: ActorMetadata;
    reason?: string;
    patch?: Record<string, unknown>; // Status-specific updates like soldAt, rejectionReason
    metadata?: Record<string, unknown>; // Audit metadata
    session?: unknown; // Optional external session
}


const toLower = (value: unknown): string =>
    typeof value === 'string' ? value.trim().toLowerCase() : '';

const isListingLifecycleDomain = (domain: ValidDomain): boolean =>
    domain === 'ad' || domain === 'service' || domain === 'spare_part_listing';

const isModerationDeactivationAction = (metadata?: Record<string, unknown>): boolean => {
    const action = toLower(metadata?.action);
    return action === 'moderation_deactivate' || action === 'moderation_soft_delete';
};

const canBypassInvalidTransition = (params: {
    error: unknown;
    actor: ActorMetadata;
    toStatus: string;
    resolvedDomain: ValidDomain;
    metadata?: Record<string, unknown>;
}): boolean => {
    const typedError = params.error as { code?: string };
    if (typedError.code !== 'INVALID_LIFECYCLE_TRANSITION') return false;
    if (params.actor.type !== ACTOR_TYPE.ADMIN) return false;
    if (!isListingLifecycleDomain(params.resolvedDomain)) return false;
    if (toLower(params.toStatus) !== LISTING_STATUS.DEACTIVATED) return false;
    return isModerationDeactivationAction(params.metadata);
};

interface IStatusable {
    status: string;
    statusChangedAt?: Date;
    statusReason?: string;
    moderationStatus?: string;
    listingType?: string;
    save: (options?: { session?: ClientSession }) => Promise<mongoose.Document>;
    toObject: () => Record<string, unknown>;
    [key: string]: unknown;
}

/**
 * 🛠️ Centralized Status Mutation Service
 * 
 * Enforces transaction-safe lifecycle transitions across all domains.
 * Integrates with:
 * 1. LifecycleGuard (Validation)
 * 2. StatusHistory (Unified Audit Trail)
 * 3. Metrics Telemetry (Observability)
 */
export const mutateStatus = async (request: MutationRequest): Promise<Record<string, unknown> | null> => {
    const { domain, entityId, toStatus, actor, reason, patch, metadata, session: externalSession } = request;
    const startTime = Date.now();

    let fromStatus = 'unknown';
    let resolvedListingType: string | undefined;

    try {
        let result: Record<string, unknown> | null = null;

        const executeOperations = async (activeSession: any) => {
            if (isListingLifecycleDomain(domain)) {
                return executeListingOperations(activeSession);
            }
            
            // 1. Resolve Model
            const Model = getModelForDomain(domain);
            const doc = await (Model as mongoose.Model<mongoose.Document>).findById(entityId).setOptions({ withDeleted: true }).session(activeSession) as (mongoose.Document & IStatusable) | null;
            
            if (!doc) {
                throw Object.assign(new Error(`Entity ${String(entityId)} not found in domain ${domain}`), { statusCode: 404 });
            }

            fromStatus = doc.status;
            const listingType = doc.listingType;
            resolvedListingType = listingType;

            // 2. Lifecycle Validation (Type-aware for unified ad model)
            const resolvedDomain = resolveLifecycleDomain(domain, listingType);
            try {
                validateLifecycleTransition(resolvedDomain, fromStatus, toStatus);
            } catch (error) {
                if (!canBypassInvalidTransition({
                    error,
                    actor,
                    toStatus,
                    resolvedDomain,
                    metadata,
                })) {
                    throw error;
                }

                logger.warn('Status Mutation BYPASS: allowing admin moderation deactivation outside strict transition map', {
                    domain,
                    resolvedDomain,
                    entityId: String(entityId),
                    fromStatus,
                    toStatus,
                    action: metadata?.action,
                    actorType: actor.type,
                    actorId: actor.id,
                });
            }
            enforceLifecycleMutationPolicy({
                domain: resolvedDomain,
                fromStatus,
                toStatus,
                actor,
                patch,
                metadata,
            });

            // 4. Update Document
            doc.status = toStatus;
            doc.statusChangedAt = new Date();
            if (reason) doc.statusReason = reason;

            // 🛡️ DATA INTEGRITY: Coerce stale/legacy moderationStatus values that are
            // not in the current enum. These exist in documents written before the enum
            // was tightened (e.g. "approved" was an old value, now split into
            // "auto_approved" / "manual_approved"). Mongoose validates the entire
            // document on .save(), so a single stale field blocks ALL mutations.
            const VALID_MODERATION_STATUSES = new Set([
                'auto_approved', 'held_for_review', 'manual_approved', 'rejected', 'community_hidden'
            ]);
            const currentModerationStatus = doc.moderationStatus;
            if (currentModerationStatus && !VALID_MODERATION_STATUSES.has(currentModerationStatus)) {
                logger.warn('StatusMutationService: coercing stale moderationStatus', {
                    entityId: String(entityId),
                    domain,
                    staleValue: currentModerationStatus,
                    coercedTo: 'manual_approved',
                });
                doc.moderationStatus = 'manual_approved';
            }

            // Apply status-specific patch (e.g., soldAt, rejectionReason, $push: { timeline })
            if (patch) {
                for (const [key, value] of Object.entries(patch)) {
                    if (key === '$push' && typeof value === 'object' && value !== null) {
                        for (const [pKey, pVal] of Object.entries(value as Record<string, unknown>)) {
                            const field = doc[pKey];
                            if (Array.isArray(field)) {
                                field.push(pVal);
                            }
                        }
                    } else {
                        doc[key] = value;
                    }
                }
            }
            
            await doc.save({ session: activeSession as any });

            // 5. Record Unified Status History
            await StatusHistory.create([{
                domain,
                entityId: (entityId instanceof mongoose.Types.ObjectId) ? entityId : new mongoose.Types.ObjectId(String(entityId)),
                fromStatus,
                toStatus,
                actorType: actor.type,
                actorId: (actor.id && mongoose.Types.ObjectId.isValid(actor.id)) ? new mongoose.Types.ObjectId(actor.id) : undefined,
                reason,
                metadata: {
                    ...metadata,
                    ip: actor.ip,
                    ua: actor.userAgent,
                    mutationService: 'v1'
                }
            }], { session: activeSession as any });

            return (typeof doc.toObject === 'function' ? doc.toObject() : doc) as Record<string, unknown>;
        };

        const executeListingOperations = async (activeSession: any) => {
            const { getListingRepository } = await import('../../composition/listings');
            const repo = getListingRepository();
            const listing = await repo.findOne({ ids: [entityId.toString()], isDeleted: { $in: [true, false] } as any, session: activeSession });
            
            if (!listing) {
                throw Object.assign(new Error(`Entity ${String(entityId)} not found in domain ${domain}`), { statusCode: 404 });
            }

            fromStatus = listing.status as string;
            resolvedListingType = listing.listingType as string;

            const resolvedDomain = resolveLifecycleDomain(domain, resolvedListingType);
            try {
                validateLifecycleTransition(resolvedDomain, fromStatus, toStatus);
            } catch (error) {
                if (!canBypassInvalidTransition({ error, actor, toStatus, resolvedDomain, metadata })) {
                    throw error;
                }
            }
            enforceLifecycleMutationPolicy({ domain: resolvedDomain, fromStatus, toStatus, actor, patch, metadata });

            const updateDoc: Record<string, unknown> = {
                status: toStatus,
                statusChangedAt: new Date(),
            };
            if (reason) updateDoc.statusReason = reason;

            const VALID_MODERATION_STATUSES = new Set(['auto_approved', 'held_for_review', 'manual_approved', 'rejected', 'community_hidden']);
            const currentModerationStatus = listing.moderationStatus;
            if (currentModerationStatus && !VALID_MODERATION_STATUSES.has(currentModerationStatus)) {
                updateDoc.moderationStatus = 'manual_approved';
            }

            if (patch) {
                for (const [key, value] of Object.entries(patch)) {
                    updateDoc[key] = value;
                }
            }

            const updated = await repo.updateOne(entityId.toString(), updateDoc as any, activeSession);

            await StatusHistory.create([{
                domain,
                entityId: (entityId instanceof mongoose.Types.ObjectId) ? entityId : new mongoose.Types.ObjectId(String(entityId)),
                fromStatus,
                toStatus,
                actorType: actor.type,
                actorId: (actor.id && mongoose.Types.ObjectId.isValid(actor.id)) ? new mongoose.Types.ObjectId(actor.id) : undefined,
                reason,
                metadata: {
                    ...metadata,
                    ip: actor.ip,
                    ua: actor.userAgent,
                    mutationService: 'v1'
                }
            }], { session: activeSession as any });

            return updated as any;
        };

        if (externalSession) {
            result = await executeOperations(externalSession);
        } else {
            const { getListingUnitOfWork } = await import('../../composition/listings');
            result = await getListingUnitOfWork().executeTransaction(async (session) => {
                return executeOperations(session);
            });
        }

        const duration = Date.now() - startTime;
        
        // 6. Record Real-time Telemetry (Success) - Always outside critical transaction
        setImmediate(() => {
            recordMutationMetric('success', domain, fromStatus, toStatus, actor.type).catch(err => {
                logger.error('Telemetry Error (Success Path):', err);
            });
        });

        logger.info(`Status Mutation SUCCESS: ${domain} ${String(entityId)} (${fromStatus} -> ${toStatus})`, {
            durationMs: duration,
            actorType: actor.type,
            actorId: actor.id
        });
        
        // 7. Dispatch Global Lifecycle Event (Decoupled side-effects)
        if (domain === 'ad') {
            // 🛡️ PRODUCTION HARDENING: Fire-and-forget cache invalidation
            // Cache bust runs independently — a Redis failure must NOT block
            // lifecycle event dispatch that downstream consumers depend on.
            import('@esparex/core/composition/listings').then(({ getListingsCache }) => {
                const listingsCache = getListingsCache();
                return Promise.all([
                    listingsCache.invalidatePublicAdCache(entityId.toString()),
                    listingsCache.invalidateAdFeedCaches()
                ]);
            }).catch((cacheErr) => {
                logger.error('Failed to bust cache during status mutation', { adId: entityId.toString(), cacheErr });
            });

            await lifecycleEvents.dispatch('ad.lifecycle.changed', {
                adId: entityId.toString(),
                fromStatus,
                toStatus,
                actorType: actor.type,
                actorId: actor.id,
                source: actor.type,
                reason
            });

            if (
                toStatus === 'rejected'
                && String(metadata?.action || '').trim().toLowerCase() === 'moderation_reject'
            ) {
                await lifecycleEvents.dispatch('listing.rejected', {
                    listingId: entityId.toString(),
                    listingType: resolvedListingType || 'ad',
                    rejectionReason: typeof (patch)?.rejectionReason === 'string'
                        ? String((patch).rejectionReason)
                        : undefined,
                    actorType: actor.type,
                    actorId: actor.id,
                });
            }

            if (
                toStatus === 'live'
                && String(metadata?.action || '').trim().toLowerCase() === 'moderation_approve'
            ) {
                const listingType =
                    typeof metadata?.listingType === 'string'
                        ? String(metadata.listingType)
                        : (
                            typeof (patch)?.listingType === 'string'
                                ? String((patch).listingType)
                                : undefined
                        );
                await lifecycleEvents.dispatch('listing.approved', {
                    listingId: entityId.toString(),
                    listingType: listingType || 'ad',
                    approvedAt: (
                        (patch)?.approvedAt instanceof Date
                            ? ((patch).approvedAt).toISOString()
                            : new Date().toISOString()
                    ),
                    actorType: actor.type,
                    actorId: actor.id,
                    source: String(metadata?.sourceRoute || metadata?.action || actor.type),
                });
            }
        }
        
        return result;
    } catch (error: unknown) {
        const duration = Date.now() - startTime;
        const err = error as { message?: string; code?: string };
        
        // Record Real-time Telemetry (Rejection/Failure)
        const isValidationFailure = err.code === 'INVALID_LIFECYCLE_TRANSITION' || err.code === 'LIFECYCLE_LOCKED';
        const metricStatus = isValidationFailure ? 'rejection' : 'failure';
        
        setImmediate(() => {
            recordMutationMetric(metricStatus as 'success' | 'rejection' | 'failure', domain, fromStatus, toStatus, actor.type).catch(err => {
                logger.error('Telemetry Error (Error Path):', err);
            });
        });
        
        logger.error(`Status Mutation FAILED: ${domain} ${String(entityId)} -> ${toStatus}`, {
            error: err.message,
            code: err.code,
            durationMs: duration,
            actorType: actor.type
        });
        
        throw error;
    }
};

/**
 * 🛠️ Bulk Status Mutation Service
 * Processes multiple entity transitions.
 * 
 * NOTE: For production safety and audit granularity, we process each mutation 
 * individually to ensure full LifecycleGuard validation and unique audit trails.
 */
export const mutateStatuses = async (requests: MutationRequest[]): Promise<(Record<string, unknown> | null)[]> => {
    const results: (Record<string, unknown> | null)[] = [];
    for (const request of requests) {
        results.push(await mutateStatus(request));
    }
    return results;
};

export const mutateStatusesBulk = async (
    domain: ValidDomain,
    entityIds: string[],
    toStatus: string,
    actor: MutationRequest['actor'],
    reason?: string
): Promise<number> => {
    if (!entityIds.length) return 0;
    
    const Model = getModelForDomain(domain);
    type BulkMutationDoc = { _id: mongoose.Types.ObjectId; listingType?: string };
    const docs = await (Model as mongoose.Model<mongoose.Document>).find({ _id: { $in: entityIds } })
        .select('_id status listingType')
        .lean<BulkMutationDoc[]>();
    if (!docs.length) return 0;

    await mutateStatuses(
        docs.map((doc) => ({
            domain,
            entityId: String(doc._id),
            toStatus,
            actor,
            reason,
            metadata: {
                action: 'bulk_mutation',
                sourceRoute: 'StatusMutationService.mutateStatusesBulk',
                listingType: doc.listingType,
            },
        }))
    );

    if (domain === 'ad' && toStatus === LISTING_STATUS.EXPIRED) {
        await lifecycleEvents.dispatch('ad.expired.bulk', { count: docs.length, source: 'cron_expireOutdatedAds' });
    }

    return docs.length;
};

/**
 * Domain-to-Model mapping SSOT
 */
function getModelForDomain(domain: ValidDomain) {
    switch (domain) {
        case 'ad': return Ad;
        case 'user': return User;
        case 'business': return Business;
        case 'service': return Ad;
        case 'spare_part_listing': return Ad;
        case 'catalog_part': throw new Error('Domain \'catalog_part\' uses CatalogStatus — route through admin catalog service, not statusMutationService');
        default: throw new Error(`Unsupported domain: ${domain as string}`);
    }
}


/**
 * Record mutation metrics for observability
 */
async function recordMutationMetric(
    status: 'success' | 'rejection' | 'failure',
    domain: string,
    from: string,
    to: string,
    actorType: string
) {
    try {
        // 1. Prometheus Telemetry (High-Resolution)
        if (status === 'success') {
            const { listingStatusTransitionsTotal } = await import('../../utils/metrics');
            listingStatusTransitionsTotal.inc({
                fromStatus: from,
                toStatus: to,
                actorType: actorType,
                listingType: domain,
            });
        }

        // 2. Database Metrics (Historical Trends)
        const date = new Date();
        date.setHours(0, 0, 0, 0);

        const update: Record<string, unknown> = {
            $inc: {
                [`payload.total`]: 1,
                [`payload.${status}`]: 1,
                [`payload.domains.${domain}`]: 1,
                [`payload.transitions.${from}_to_${to}`]: 1
            }
        };

        // AdminMetrics often resides on a separate restricted connection
        await AdminMetrics.findOneAndUpdate(
            { metricModule: 'status_mutations', aggregationDate: date },
            update,
            { upsert: true }
        );
    } catch (err) {
        // Telemetry failure should NEVER block the mutation transaction
        logger.error('Critical Telemetry Failure:', { error: String(err) });
    }
}

import { client, isConnected, cacheMetrics } from './config';
import logger from '../logger';
import { withTimeout } from '../resilience';
import { scanKeysByPattern } from './scan';
import {
    GOVERNED_CACHE_PATTERNS, REDIS_TTL_AUDIT_SAMPLE_LIMIT,
    REDIS_PROBE_TIMEOUT_MS, REDIS_HEALTH_PROBE_TTL_SECONDS,
    REDIS_MEMORY_PRESSURE_THRESHOLD, RECOMMENDED_REDIS_EVICTION_POLICY,
    CACHE_NAMESPACES, parseInfoNumberMetric, parseInfoStringMetric, getDefaultTtlForKey,
} from './constants';

let lastRedisConfigWarningSignature: string | null = null;

const getHitRateStatus = () => {
    const total = cacheMetrics.hits + cacheMetrics.misses;
    if (total === 0) return 'healthy';
    const rate = cacheMetrics.hits / total;
    if (rate < 0.5) return 'critical';
    if (rate < 0.7) return 'warning';
    return 'healthy';
};

const checkMemoryHealth = async () => {
    if (!isConnected) return;
    try {
        const info = await client.info('memory');
        const used = parseInfoNumberMetric(info, 'used_memory') ?? 0;
        const max = parseInfoNumberMetric(info, 'maxmemory') ?? 0;
        const maxMemoryPolicy = parseInfoStringMetric(info, 'maxmemory_policy') || 'unknown';
        if (max > 0) {
            (globalThis as any).__redisHighMemoryPressure = (used / max) > REDIS_MEMORY_PRESSURE_THRESHOLD;
        } else {
            (globalThis as any).__redisHighMemoryPressure = false;
        }
        if (process.env.NODE_ENV === 'production') {
            const warnings: string[] = [];
            if (max <= 0) warnings.push('maxmemory is not configured');
            if (maxMemoryPolicy !== RECOMMENDED_REDIS_EVICTION_POLICY) warnings.push(`maxmemory_policy is ${maxMemoryPolicy} (recommended: ${RECOMMENDED_REDIS_EVICTION_POLICY})`);
            const sig = warnings.join(' | ');
            if (sig && sig !== lastRedisConfigWarningSignature) { logger.warn(`[REDIS_CONFIG] ${sig}`); lastRedisConfigWarningSignature = sig; }
            if (!sig) lastRedisConfigWarningSignature = null;
        }
    } catch { /* silent */ }
};

setInterval(() => void checkMemoryHealth(), 300000).unref();

const buildProbeKey = (): string => `${CACHE_NAMESPACES.SYSTEM}:health:probe:${Date.now().toString(36)}:${Math.random().toString(36).slice(2, 8)}`;

export const getRedisHealthProbe = async (): Promise<{
    connected: boolean; pingOk: boolean; roundTripOk: boolean; latencyMs: number | null; error?: string;
}> => {
    const { reliabilityAlertsTotal } = await import('../metrics');
    const { emitReliabilityAlert } = await import('../reliabilityAlerts');

    if (!isConnected) {
        reliabilityAlertsTotal.labels('REDIS_DOWN', 'critical').inc();
        void emitReliabilityAlert({
            type: 'REDIS_DOWN', title: 'Redis is unavailable', severity: 'critical',
            summary: 'Redis client is disconnected', dedupeKey: 'redis_down',
            metadata: { redisMode: process.env.REDIS_MODE, connected: isConnected },
        });
        return { connected: false, pingOk: false, roundTripOk: false, latencyMs: null, error: 'Redis client is disconnected' };
    }

    const probeKey = buildProbeKey();
    const probeValue = Date.now().toString(36);
    const startedAt = Date.now();

    try {
        const pong = await withTimeout(client.ping(), REDIS_PROBE_TIMEOUT_MS, 'Redis ping probe');
        const pingOk = pong === 'PONG';
        await withTimeout(client.set(probeKey, probeValue, 'EX', REDIS_HEALTH_PROBE_TTL_SECONDS), REDIS_PROBE_TIMEOUT_MS, 'Redis probe set');
        const readBack = await withTimeout(client.get(probeKey), REDIS_PROBE_TIMEOUT_MS, 'Redis probe get');
        await withTimeout(client.del(probeKey), REDIS_PROBE_TIMEOUT_MS, 'Redis probe del');
        const roundTripOk = readBack === probeValue;
        if (!(pingOk && roundTripOk)) {
            reliabilityAlertsTotal.labels('REDIS_DEGRADED', 'high').inc();
            void emitReliabilityAlert({
                type: 'REDIS_DEGRADED', title: 'Redis health probe degraded', severity: 'high',
                summary: 'Redis ping or round-trip probe failed', dedupeKey: 'redis_degraded', metadata: { pingOk, roundTripOk },
            });
        }
        return { connected: true, pingOk, roundTripOk, latencyMs: Date.now() - startedAt };
    } catch (error: unknown) {
        cacheMetrics.errors++;
        reliabilityAlertsTotal.labels('REDIS_DOWN', 'critical').inc();
        void emitReliabilityAlert({
            type: 'REDIS_DOWN', title: 'Redis probe failed', severity: 'critical',
            summary: 'Redis health probe operation failed', dedupeKey: 'redis_probe_failure',
            metadata: { error: error instanceof Error ? error.message : String(error) },
        });
        return { connected: true, pingOk: false, roundTripOk: false, latencyMs: Date.now() - startedAt, error: error instanceof Error ? error.message : String(error) };
    }
};

const auditKeyTtl = async (key: string): Promise<{ ttl: number | null; autoFixed: boolean }> => {
    try {
        const ttl = await client.ttl(key);
        if (ttl === -1) {
            const fallbackTtl = getDefaultTtlForKey(key);
            if (fallbackTtl && fallbackTtl > 0) {
                const repaired = await client.expire(key, fallbackTtl);
                if (repaired === 1) return { ttl: fallbackTtl, autoFixed: true };
            }
        }
        return { ttl, autoFixed: false };
    } catch { cacheMetrics.errors++; return { ttl: null, autoFixed: false }; }
};

export const getCacheStats = async () => {
    let memoryUsedBytes = 0, totalKeys = 0, maxMemoryBytes = 0;
    let maxMemoryPolicy = 'unknown';
    let ttlAudit = { sampledKeys: 0, keysWithoutTtl: 0, keysAutoFixed: 0 };
    const redisHealth = await getRedisHealthProbe();

    if (isConnected) {
        try {
            const info = await client.info('memory');
            memoryUsedBytes = parseInfoNumberMetric(info, 'used_memory') ?? 0;
            maxMemoryBytes = parseInfoNumberMetric(info, 'maxmemory') ?? 0;
            maxMemoryPolicy = parseInfoStringMetric(info, 'maxmemory_policy') || 'unknown';
            totalKeys = await client.dbsize();
            await checkMemoryHealth();
            const sampled = new Set<string>();
            for (const pattern of GOVERNED_CACHE_PATTERNS) {
                const keys = await scanKeysByPattern(pattern, { count: 100, maxKeys: 50 });
                for (const key of keys) { sampled.add(key); if (sampled.size >= REDIS_TTL_AUDIT_SAMPLE_LIMIT) break; }
                if (sampled.size >= REDIS_TTL_AUDIT_SAMPLE_LIMIT) break;
            }
            const sampledKeys = Array.from(sampled);
            if (sampledKeys.length > 0) {
                let keysAutoFixed = 0;
                const results = await Promise.all(sampledKeys.map(key => auditKeyTtl(key)));
                for (const r of results) { if (r.autoFixed) keysAutoFixed += 1; }
                const ttlValues = results.map(r => r.ttl);
                ttlAudit = { sampledKeys: sampledKeys.length, keysWithoutTtl: ttlValues.filter(t => t === -1).length, keysAutoFixed };
            }
        } catch { /* ignore */ }
    }

    return {
        connected: isConnected,
        mode: process.env.REDIS_MODE,
        namespaces: CACHE_NAMESPACES,
        redisHealth,
        redisConfig: { maxMemoryBytes, maxMemoryPolicy, evictionPolicyRecommended: RECOMMENDED_REDIS_EVICTION_POLICY, isRecommendedPolicy: maxMemoryPolicy === RECOMMENDED_REDIS_EVICTION_POLICY },
        metrics: { ...cacheMetrics, memoryUsedMB: Number((memoryUsedBytes / (1024 * 1024)).toFixed(2)), totalKeys, ttlAudit, lastUpdated: new Date() },
        healthStatus: getHitRateStatus(),
        memoryPressureStatus: (globalThis as any).__redisHighMemoryPressure ? 'critical' : 'normal',
    };
};

setInterval(() => {
    if (isConnected) {
        const total = cacheMetrics.hits + cacheMetrics.misses;
        if (total > 0) {
            const rate = ((cacheMetrics.hits / total) * 100).toFixed(2);
            logger.info(`[REDIS_METRICS] Hit Rate: ${rate}% | Hits: ${cacheMetrics.hits} | Misses: ${cacheMetrics.misses}`);
        }
    }
}, 60000).unref();

import Ad from "../models/Ad";
import User from "../models/User";
import { locationRepository, locationAnalyticsRepository } from "../composition/location";
import { LISTING_STATUS } from '@esparex/shared';
import logger from '../utils/logger';
import { runWithDistributedJobLock } from '../utils/distributedJobLock';

export const runLocationAnalyticsJob = async () => {
    await runWithDistributedJobLock(
        'location_analytics_refresh',
        { ttlMs: 2 * 60 * 60 * 1000, failOpen: false },
        async () => {
            logger.info('Starting Location Analytics Worker...');
            try {
                await updateLocationStats();
                logger.info('Location Analytics Worker completed successfully.');
            } catch (error) {
                logger.error('Location Analytics Worker failed', { error });
            }
        }
    );
};

/**
 * Refreshes LocationAnalytics for all active locations via LocationAnalyticsRepositoryPort.
 * Computes adsCount, activeAdsCount, usersCount, searchCount, viewCount,
 * popularityScore, and isHotZone in a single consolidated write.
 */
export const updateLocationStats = async (triggeredBy: 'cron' | 'manual' = 'cron') => {
    logger.info('Updating location analytics...', { triggeredBy });

    let jobLog;
    try {
        const JobLogStart = (await import('@esparex/core/models/JobLog')).default;
        jobLog = await JobLogStart.create({
            jobName: 'refreshLocationStats',
            status: 'started',
            triggeredBy,
            startedAt: new Date()
        });
    } catch (e) {
        logger.error('Failed to create start JobLog', { error: e });
    }

    const startTime = Date.now();

    try {
        const locations = await locationRepository.findMany({ isActive: true });
        const locationIds = locations.map((loc: any) => loc._id);

        const [adCountsAgg, userCountsAgg, existingAnalyticsDocs] = await Promise.all([
            Ad.aggregate<{
                _id: unknown;
                adsCount: number;
                activeAdsCount: number;
            }>([
                { $match: { 'location.locationId': { $in: locationIds } } },
                {
                    $group: {
                        _id: '$location.locationId',
                        adsCount: { $sum: 1 },
                        activeAdsCount: {
                            $sum: { $cond: [{ $eq: ['$status', LISTING_STATUS.LIVE] }, 1, 0] }
                        }
                    }
                }
            ]),
            User.aggregate<{
                _id: unknown;
                usersCount: number;
            }>([
                { $match: { locationId: { $in: locationIds } } },
                {
                    $group: {
                        _id: '$locationId',
                        usersCount: { $sum: 1 }
                    }
                }
            ]),
            locationAnalyticsRepository.findAnalytics({ locationId: { $in: locationIds } })
        ]);

        const adCountByLocationId = new Map<string, { adsCount: number; activeAdsCount: number }>();
        const userCountByLocationId = new Map<string, number>();
        const analyticsByLocationId = new Map<string, { searchCount: number; viewCount: number }>();

        for (const item of adCountsAgg) {
            adCountByLocationId.set(String(item._id), {
                adsCount: Number(item.adsCount || 0),
                activeAdsCount: Number(item.activeAdsCount || 0)
            });
        }
        for (const item of userCountsAgg) {
            userCountByLocationId.set(String(item._id), Number(item.usersCount || 0));
        }
        for (const item of existingAnalyticsDocs) {
            analyticsByLocationId.set(String(item.locationId), {
                searchCount: Number((item as { searchCount?: number }).searchCount || 0),
                viewCount: Number((item as { viewCount?: number }).viewCount || 0)
            });
        }

        const analyticsBulkOps: any[] = [];

        for (const loc of locations) {
            const locationKey = String(loc._id);
            const adCounts = adCountByLocationId.get(locationKey);
            const adsCount = adCounts?.adsCount ?? 0;
            const activeAdsCount = adCounts?.activeAdsCount ?? 0;
            const usersCount = userCountByLocationId.get(locationKey) ?? 0;
            const existingAnalytics = analyticsByLocationId.get(locationKey);
            const searchCount = existingAnalytics?.searchCount ?? 0;
            const viewCount = existingAnalytics?.viewCount ?? 0;

            const popularityScore = Number(
                (adsCount * 0.4 + searchCount * 0.3 + viewCount * 0.3).toFixed(2)
            );
            const isHotZone = searchCount >= 100 || adsCount >= 50;

            analyticsBulkOps.push({
                updateOne: {
                    filter: { locationId: loc._id },
                    update: {
                        $set: {
                            locationId: loc._id,
                            adsCount,
                            activeAdsCount,
                            usersCount,
                            searchCount,
                            viewCount,
                            popularityScore,
                            isHotZone,
                            lastUpdated: new Date()
                        }
                    },
                    upsert: true
                }
            });
        }

        let updateCount = 0;
        if (analyticsBulkOps.length > 0) {
            const result = (await locationAnalyticsRepository.bulkWriteAnalytics(analyticsBulkOps)) as { modifiedCount: number; upsertedCount: number };
            updateCount = result.modifiedCount + result.upsertedCount;
            logger.info(`Updated analytics for ${analyticsBulkOps.length} locations.`, { updateCount });
        } else {
            logger.info('No location analytics to update.');
        }


        if (jobLog) {
            jobLog.status = 'success';
            jobLog.completedAt = new Date();
            jobLog.durationMs = Date.now() - startTime;
            jobLog.result = { processedLocations: locations.length, updatedAnalytics: updateCount };
            await jobLog.save();
        }

    } catch (err: unknown) {
        const errorMessage = err instanceof Error ? err.message : 'Unknown error';
        logger.error('Error updating location analytics:', { error: err });

        if (jobLog) {
            jobLog.status = 'failed';
            jobLog.completedAt = new Date();
            jobLog.durationMs = Date.now() - startTime;
            jobLog.error = errorMessage;
            await jobLog.save();
        }
        throw err;
    }
};

import { Worker } from 'bullmq';
import { redisConnection, shouldDisableQueueConnection } from '../queues/redisConnection';
import { NotificationDispatcher } from '../services/notification/NotificationDispatcher';
import { NotificationIntent } from '../domains/identity/domain/NotificationIntent';
import logger from '../utils/logger';
import { enqueueDeadLetter } from '../queues/deadLetterQueue';
import { queueWorkerBackoffStrategy } from '../queues/queueDefaults';
import { TraceContext } from '@esparex/shared';
import { clearReliabilityContext, setReliabilityContext } from '../utils/reliabilityContext';

/**
 * Notification Delivery Worker
 * Domain: notification
 * Queue:  notification.delivery.queue
 *
 * Responsibilities:
 *  1. Execute the final delivery of notifications (DB, WebSocket, FCM).
 *  2. Provide retry logic for failed push attempts.
 */
const createNoopWorker = <T>() => ({
    on: () => undefined,
    close: async () => undefined,
} as unknown as Worker<T>);

export const notificationDeliveryProcessor = async (job: any) => {
    const traceId = (job.data as { _trace?: { requestId?: string } } | undefined)?._trace?.requestId || `job-${String(job.id || 'unknown')}`;
    const traceUserId = (job.data as { _trace?: { userId?: string } } | undefined)?._trace?.userId;
    TraceContext.setCorrelationId(traceId);
    setReliabilityContext({
        traceId,
        userId: traceUserId,
        queueName: 'notification.delivery.queue',
        jobId: job.id ? String(job.id) : undefined,
        jobName: job.name,
        requestPath: `queue://notification.delivery.queue/${job.name}`,
        method: 'QUEUE',
    });
    const { intent, options } = job.data as {
        intent: ConstructorParameters<typeof NotificationIntent>[0];
        options: { shadowDispatch?: boolean }
    };

    logger.info(`[NotificationDeliveryWorker] Processing ${job.name} for User ${intent.userId}`, {
        jobId: job.id,
        type: intent.type
    });

    try {
        // Reconstruct the intent object to ensure all defaults are applied 
        // and any internal logic runs (though executeDispatch uses properties mostly).
        const notificationIntent = new NotificationIntent(intent);
        
        await NotificationDispatcher.executeDispatch(notificationIntent, options);
        
        logger.info(`[NotificationDeliveryWorker] Completed delivery for User ${intent.userId}`, {
            jobId: job.id
        });
    } catch (error) {
        logger.error(`[NotificationDeliveryWorker] Failed delivery for User ${intent.userId}`, {
            jobId: job.id,
            error: error instanceof Error ? error.message : String(error)
        });
        // Propagate error to BullMQ for retry (configured in adQueue.ts defaultJobOptions)
        throw error;
    } finally {
        TraceContext.clear();
        clearReliabilityContext();
    }
};

export const notificationDeliveryWorker = shouldDisableQueueConnection
    ? createNoopWorker()
    : new Worker(
        'notification.delivery.queue',
        notificationDeliveryProcessor,
        {
            connection: redisConnection,
            concurrency: 50, // High concurrency for network-bound tasks (FCM, WebSocket)
            settings: {
                backoffStrategy: (attemptsMade: number) => {
                    // Exponential: 5s → 10s → 20s → 40s → 80s
                    return queueWorkerBackoffStrategy(attemptsMade, 5_000, 600_000);
                }
            }
        }
    );

if (!shouldDisableQueueConnection) {
    notificationDeliveryWorker.on('failed', (job, err) => {
        if (job) {
            logger.error(`[NotificationDeliveryWorker] Delivery Job ${job.id} permanently failed`, {
                error: err.message,
                attempts: job.attemptsMade,
                attemptsConfigured: job.opts.attempts || 1,
            });
            void enqueueDeadLetter('notification.delivery.queue', job, err);
        }
    });

    notificationDeliveryWorker.on('completed', (job) => {
        logger.debug(`[NotificationDeliveryWorker] Delivery Job ${job.id} completed successfully`);
    });

    notificationDeliveryWorker.on('error', (err) => {
        logger.error('[NotificationDeliveryWorker] Worker runtime error', {
            error: err.message
        });
    });
}

#!/usr/bin/env node

const { execSync, spawnSync } = require("node:child_process");
const fs = require("node:fs");
const path = require("node:path");

const WORKSPACE_ROOTS = ["apps/admin", "apps/web", "backend/api", "core", "shared"];

function run(cmd) {
  return execSync(cmd, { stdio: ["ignore", "pipe", "pipe"], encoding: "utf8" }).trim();
}

function resolveBaseRef() {
  const ghBase = process.env.GITHUB_BASE_REF;
  if (ghBase) return `origin/${ghBase}`;
  return "origin/main";
}

function resolveMergeBase(baseRef) {
  try {
    return run(`git merge-base HEAD ${baseRef}`);
  } catch {
    try {
      return run("git rev-parse HEAD~1");
    } catch {
      return "";
    }
  }
}

function getChangedTsFiles(baseSha) {
  if (!baseSha) return [];
  const raw = run(`git diff --name-only --diff-filter=ACMR ${baseSha}...HEAD`);
  return raw
    .split("\n")
    .map((line) => line.trim())
    .filter(Boolean)
    .filter((file) => /\.(ts|tsx)$/.test(file))
    .filter((file) => WORKSPACE_ROOTS.some((root) => file.startsWith(`${root}/src/`)));
}

function groupByWorkspace(files) {
  const grouped = new Map();
  for (const file of files) {
    const root = WORKSPACE_ROOTS.find((r) => file.startsWith(`${r}/`));
    if (!root) continue;
    const rel = file.slice(root.length + 1);
    if (!grouped.has(root)) grouped.set(root, []);
    grouped.get(root).push(rel);
  }
  return grouped;
}

function lintWorkspaceChangedFiles(workspace, files) {
  if (!files.length) return 0;
  const args = [
    "eslint",
    ...files,
    "--format=json",
    "--rule",
    "unused-imports/no-unused-imports:error",
  ];
  const result = spawnSync("npx", args, {
    cwd: workspace,
    stdio: ["ignore", "pipe", "pipe"],
    shell: true,
    encoding: "utf8",
  });

  try {
    const output = JSON.parse(result.stdout.trim());
    let unusedImportCount = 0;
    for (const file of output) {
      const unusedInFile = file.messages.filter(m => m.ruleId === "unused-imports/no-unused-imports");
      if (unusedInFile.length > 0) {
        console.error(`❌ Unused imports in ${workspace}/${file.filePath}:`);
        unusedInFile.forEach(m => {
          console.error(`  Line ${m.line}: ${m.message}`);
        });
        unusedImportCount += unusedInFile.length;
      }
    }
    return unusedImportCount > 0 ? 1 : 0;
  } catch (err) {
    console.error(`ESLint error or parsing error in workspace ${workspace}:`, result.stderr || result.stdout);
    return 1;
  }
}

function main() {
  const baseRef = resolveBaseRef();
  const baseSha = resolveMergeBase(baseRef);

  if (!baseSha) {
    console.log("✅ Skipping unused import guard (git base could not be resolved).");
    return;
  }

  const changed = getChangedTsFiles(baseSha);

  if (changed.length === 0) {
    console.log("✅ No TypeScript changes detected for unused import guard.");
    return;
  }

  const grouped = groupByWorkspace(changed);
  let hasFailures = false;

  for (const [workspace, files] of grouped.entries()) {
    console.log(`Checking unused imports in changed files (${workspace})...`);
    // Final safety check: filter out files that may have been deleted/moved
    const existingFiles = files.filter(f => fs.existsSync(path.join(workspace, f)));
    if (existingFiles.length === 0) continue;

    const status = lintWorkspaceChangedFiles(workspace, existingFiles);
    if (status !== 0) {
      hasFailures = true;
    }
  }

  if (hasFailures) {
    console.error("❌ New unused imports detected in changed files.");
    process.exit(1);
  }

  console.log("✅ Unused import guard passed.");
}

main();

#!/usr/bin/env node

/**
 * Schema Migration Governance Check (Cross-Platform)
 * Ensures model changes are accompanied by migrations or changelog updates.
 */

const { execSync } = require('child_process');
const fs = require('fs');

if (process.env.SKIP_MIGRATION_GATE) {
    console.log("[governance] SKIP_MIGRATION_GATE is set; skipping schema migration guard.");
    process.exit(0);
}

function runGit(cmd) {
    try {
        return execSync(cmd, { encoding: 'utf8', stdio: ['pipe', 'pipe', 'ignore'] }).trim();
    } catch (e) {
        return '';
    }
}

// Parse args
let baseRef = '';
process.argv.forEach(val => {
    if (val.startsWith('--base=')) {
        baseRef = val.split('=')[1];
    }
});

function resolveBaseRef() {
    if (baseRef) return baseRef;

    const upstream = runGit('git rev-parse --abbrev-ref --symbolic-full-name @{upstream}');
    if (upstream) return upstream;

    const develop = runGit('git show-ref --verify --quiet refs/remotes/origin/develop');
    if (develop) return 'origin/develop';

    const main = runGit('git show-ref --verify --quiet refs/remotes/origin/main');
    if (main) return 'origin/main';

    return '';
}

let targetBaseRef = resolveBaseRef();
if (targetBaseRef && !runGit(`git rev-parse --verify --quiet ${targetBaseRef}`)) {
    console.log(`[governance] Base ref '${targetBaseRef}' was not found locally; falling back to HEAD~1.`);
    targetBaseRef = '';
}

let changedFilesRaw = '';
if (targetBaseRef) {
    console.log(`[governance] Schema migration gate diff base: ${targetBaseRef}`);
    changedFilesRaw = runGit(`git diff --name-only ${targetBaseRef}...HEAD`);
} else {
    console.log('[governance] Schema migration gate diff base: HEAD~1');
    changedFilesRaw = runGit('git diff --name-only HEAD~1..HEAD');
}

const untrackedFilesRaw = runGit('git ls-files --others --exclude-standard');

// Combine and normalize files list
const allFiles = Array.from(new Set([
    ...changedFilesRaw.split('\n'),
    ...untrackedFilesRaw.split('\n')
]))
    .map(f => f.trim().replace(/\\/g, '/'))
    .filter(f => f.length > 0);

if (allFiles.length === 0) {
    console.log("[governance] No changed files detected for schema migration gate.");
    process.exit(0);
}

// Schema and model file pattern matches
const schemaPatterns = [
    /^core\/src\/models\/.*\.(ts|js)$/,
    /^shared\/src\/schemas\/.*\.(ts|js)$/,
    /^shared\/src\/types\/catalogHierarchy\.ts$/,
    /^shared\/src\/enums\/taxonomyApprovalStatus\.ts$/,
    /^core\/src\/constants\/enums\/taxonomyApprovalStatus\.ts$/
];

const schemaChanges = allFiles.filter(file => 
    schemaPatterns.some(pattern => pattern.test(file))
);

if (schemaChanges.length === 0) {
    console.log("[governance] No core model changes detected; migration gate passed.");
    process.exit(0);
}

// Migration evidence pattern matches
const migrationPatterns = [
    /^backend\/user\/migrations\//
];

const hasMigrationEvidence = allFiles.some(file =>
    migrationPatterns.some(pattern => pattern.test(file))
);

if (hasMigrationEvidence) {
    console.log("[governance] Schema change detected with migration evidence.");
    process.exit(0);
}

console.error("❌ Schema migration governance violation.");
console.error("Changed schema/model files:");
schemaChanges.forEach(file => console.error(`  - ${file}`));
console.error("\nRequired with core model changes:");
console.error("  - Add/update a migration under backend/api/migrations/");
process.exit(1);

#!/usr/bin/env node
/**
 * generate-domain.ts
 * ------------------
 * Scaffolds a new bounded context under core/src/domains/<name>/.
 *
 * Usage:
 *   npm run generate:domain -- billing
 *   npm run generate:domain -- --name billing --owner billing-team --stability experimental
 *   npm run generate:domain -- --name billing --template event-sourced
 *
 * What it creates (minimal — no empty noise folders):
 *   core/src/domains/<name>/
 *   ├── application/          (empty dir held by .gitkeep)
 *   ├── domain/               (empty dir held by .gitkeep)
 *   ├── ports/                (empty dir held by .gitkeep)
 *   ├── __tests__/            (empty dir held by .gitkeep)
 *   ├── manifest.yaml         (populated from CLI flags)
 *   ├── index.ts              (empty barrel with guidance comments)
 *   └── README.md             (Purpose / Owner / Dependencies)
 *
 * Sub-folders like entities/, services/, policies/, events/ are NOT created
 * upfront. Teams add them when they are genuinely needed.
 *
 * The --template flag selects a template set under tooling/architecture/templates/.
 * Only "default" exists now; the structure supports future sets (event-sourced, crud).
 */

import * as path from 'node:path';
import * as fs from 'node:fs';
import { ensureDir, pathExists, writeFile } from './lib/filesystem';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface GeneratorOptions {
    name: string;
    owner: string;
    stability: 'experimental' | 'stable';
    template: string;
}

// ---------------------------------------------------------------------------
// Argument parsing
// ---------------------------------------------------------------------------

function parseArgs(argv: string[]): GeneratorOptions {
    const args = argv.slice(2); // strip node + script path

    // Positional shorthand: generate:domain billing
    const positional = args.find((a) => !a.startsWith('--'));

    function flag(name: string, fallback = ''): string {
        const idx = args.indexOf(`--${name}`);
        return idx !== -1 && args[idx + 1] ? args[idx + 1] : fallback;
    }

    const name = flag('name') || positional || '';
    if (!name) {
        console.error('❌  Missing domain name.');
        console.error('    Usage: npm run generate:domain -- <name>');
        console.error('           npm run generate:domain -- --name <name> --owner <owner> --stability experimental');
        process.exit(1);
    }

    const rawStability = flag('stability', 'experimental');
    if (rawStability !== 'experimental' && rawStability !== 'stable') {
        console.error(`❌  Invalid --stability "${rawStability}". Must be "experimental" or "stable".`);
        process.exit(1);
    }

    return {
        name: toKebabCase(name),
        owner: flag('owner', 'platform'),
        stability: rawStability as 'experimental' | 'stable',
        template: flag('template', 'default'),
    };
}

// ---------------------------------------------------------------------------
// String helpers
// ---------------------------------------------------------------------------

function toKebabCase(str: string): string {
    return str
        .replace(/([A-Z])/g, '-$1')
        .toLowerCase()
        .replace(/^-/, '')
        .replace(/[^a-z0-9-]/g, '-')
        .replace(/-+/g, '-');
}

function toPascalCase(str: string): string {
    return str
        .split(/[-_\s]+/)
        .map((w) => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
        .join('');
}

/** Replace {{placeholder}} tokens in a template string. */
function render(template: string, vars: Record<string, string>): string {
    return template.replace(/\{\{(\w+)\}\}/g, (_, key) => vars[key] ?? `{{${key}}}`);
}

// ---------------------------------------------------------------------------
// Template loader
// ---------------------------------------------------------------------------

function loadTemplate(templateSet: string, fileName: string): string {
    const templatePath = path.join(
        __dirname,
        'templates',
        templateSet,
        fileName
    );
    if (!fs.existsSync(templatePath)) {
        // Fall back to default template set if the custom set lacks this file.
        const fallback = path.join(__dirname, 'templates', 'default', fileName);
        if (!fs.existsSync(fallback)) {
            throw new Error(
                `Template "${fileName}" not found in set "${templateSet}" or "default".`
            );
        }
        return fs.readFileSync(fallback, 'utf-8');
    }
    return fs.readFileSync(templatePath, 'utf-8');
}

// ---------------------------------------------------------------------------
// Generator
// ---------------------------------------------------------------------------

const REPO_ROOT = path.resolve(__dirname, '..', '..');
const DOMAINS_ROOT = path.join(REPO_ROOT, 'core', 'src', 'domains');

function generate(opts: GeneratorOptions): void {
    const { name, owner, stability, template } = opts;
    const domainPath = path.join(DOMAINS_ROOT, name);

    // Guard: refuse to overwrite an existing domain.
    if (pathExists(domainPath)) {
        console.error(`❌  Domain "${name}" already exists at:\n    ${domainPath}`);
        console.error('    Delete it manually if you want to regenerate.');
        process.exit(1);
    }

    // Guard: validate template set exists.
    const templateDir = path.join(__dirname, 'templates', template);
    if (!fs.existsSync(templateDir)) {
        const available = fs
            .readdirSync(path.join(__dirname, 'templates'))
            .filter((f) => fs.statSync(path.join(__dirname, 'templates', f)).isDirectory());
        console.error(
            `❌  Template set "${template}" not found. Available: ${available.join(', ')}`
        );
        process.exit(1);
    }

    const vars: Record<string, string> = {
        id: name,
        Name: toPascalCase(name),
        owner,
        stability,
    };

    console.log(`\n🏗   Scaffolding domain: ${name}`);
    console.log(`    Template:   ${template}`);
    console.log(`    Owner:      ${owner}`);
    console.log(`    Stability:  ${stability}`);
    console.log(`    Path:       ${domainPath}\n`);

    // Create empty structural directories (held by .gitkeep).
    const dirs = ['application', 'domain', 'ports', '__tests__'];
    for (const dir of dirs) {
        const dirPath = path.join(domainPath, dir);
        ensureDir(dirPath);
        writeFile(path.join(dirPath, '.gitkeep'), '');
        console.log(`    ✓  ${dir}/.gitkeep`);
    }

    // Render and write the three mandatory root files.
    const files: Array<[string, string]> = [
        ['manifest.yaml', render(loadTemplate(template, 'manifest.yaml'), vars)],
        ['index.ts', render(loadTemplate(template, 'index.ts'), vars)],
        ['README.md', render(loadTemplate(template, 'README.md'), vars)],
    ];

    for (const [fileName, content] of files) {
        writeFile(path.join(domainPath, fileName), content);
        console.log(`    ✓  ${fileName}`);
    }

    console.log(`\n✅  Domain "${name}" scaffolded successfully.`);
    console.log('');
    console.log('    Next steps:');
    console.log(`    1.  Open core/src/domains/${name}/manifest.yaml`);
    console.log('        Update business_owner, criticality, and depends_on.');
    console.log(`    2.  Define your first port in core/src/domains/${name}/ports/`);
    console.log(`    3.  Export it from core/src/domains/${name}/index.ts`);
    console.log('    4.  Run: npm run verify:architecture');
    console.log('');
}

// ---------------------------------------------------------------------------
// Entry point
// ---------------------------------------------------------------------------

const opts = parseArgs(process.argv);
generate(opts);

#!/usr/bin/env node
/**
 * index.ts
 * --------
 * Master CLI orchestrator for the Esparex Architecture Platform.
 *
 * Pipeline:
 *   Verify → Registry → Metrics → Reports → Console Summary
 *
 * Usage:
 *   npm run architecture              # Full scan
 *   npm run architecture -- --changed # Incremental (AST checks only scan changed files)
 *
 * All generated artifacts are written under .tooling/ (git-ignored).
 */

import * as path from 'node:path';
import { runVerification } from './verify-architecture';
import { buildRegistry } from './registry';
import { collectMetrics, appendHistory, loadHistory } from './metrics';
import { buildReport, writeReports } from './report';
import { TOOLING_DIR } from './lib/constants';

// ---------------------------------------------------------------------------
// Entry point
// ---------------------------------------------------------------------------

async function main(): Promise<void> {
    const args = process.argv.slice(2);
    const isChanged = args.includes('--changed');

    const startMs = Date.now();

    console.log('\n🏗  Esparex Architecture Platform\n');
    if (isChanged) {
        console.log('   Mode: incremental (--changed)\n');
    }

    // 1. Verify — runs all check plugins, computes score
    process.stdout.write('   ① Verification … ');
    const { checkResults, score, summary, rules, domains, context } =
        await runVerification({ changed: isChanged, silent: true });
    console.log(`done  (score: ${score})`);

    // 2. Registry — scan manifests and count domain components
    process.stdout.write('   ② Registry … ');
    const registry = buildRegistry(domains, context.adaptersPath);
    console.log(`done  (${Object.keys(registry).length} domain(s))`);

    // 3. Metrics — compute extensible Metric[] array
    process.stdout.write('   ③ Metrics … ');
    const history = loadHistory();
    const metrics = collectMetrics(checkResults, registry, domains, history);
    console.log('done');

    // 4. Reports — build JSON/HTML and append history
    process.stdout.write('   ④ Reports … ');
    const report = buildReport(checkResults, metrics, registry, score, summary);
    writeReports(report, history);
    const updatedHistory = appendHistory(
        score,
        summary.totalViolations,
        domains.length,
        report.repositoryCommit
    );
    console.log('done');

    // 5. Console scorecard (printed after pipeline summary)
    const elapsedMs = Date.now() - startMs;
    console.log(`\n   Completed in ${(elapsedMs / 1000).toFixed(1)}s\n`);

    // Re-use the verify module's scorecard printer by importing it
    const { computeScore, buildSummary } = await import('./verify-architecture');

    // Scorecard
    const LINE = '─'.repeat(60);
    const C = {
        reset: '\x1b[0m',
        bold: '\x1b[1m',
        red: '\x1b[31m',
        green: '\x1b[32m',
        yellow: '\x1b[33m',
        cyan: '\x1b[36m',
        gray: '\x1b[90m',
    };
    const col = score >= 90 ? C.green : score >= 70 ? C.yellow : C.red;

    console.log(`${C.bold}${LINE}${C.reset}`);
    console.log(`  Architecture Score: ${col}${C.bold}${score} / 100${C.reset}  ${score >= 90 ? `${C.green}PASS${C.reset}` : `${C.red}FAIL${C.reset}`}`);
    console.log(`  Critical: ${summary.critical}  High: ${summary.high}  Medium: ${summary.medium}  Low: ${summary.low}`);
    console.log('');

    // Check results
    for (const r of checkResults) {
        const icon = r.passed ? `${C.green}✓${C.reset}` : `${C.red}✗${C.reset}`;
        const count = r.passed ? '' : `  ${C.gray}(${r.violations.length})${C.reset}`;
        console.log(`  ${icon}  ${r.name}${count}`);
    }

    // Top 5 issues
    const allViolations = checkResults
        .flatMap((r) => r.violations)
        .sort((a, b) => {
            const order = { critical: 0, high: 1, medium: 2, low: 3 };
            return order[a.severity] - order[b.severity];
        });

    if (allViolations.length > 0) {
        console.log(`\n  ${C.bold}Recommended Fixes:${C.reset}`);
        const icons = ['①', '②', '③', '④', '⑤'];
        allViolations.slice(0, 5).forEach((v, i) => {
            console.log(`  ${icons[i]}  ${v.message}`);
        });
    }

    // Metrics summary
    const domainMetric = metrics.find((m) => m.id === 'total_domains');
    const migratedMetric = metrics.find((m) => m.id === 'migrated_domains');
    const legacyMetric = metrics.find((m) => m.id === 'legacy_services');
    if (domainMetric || migratedMetric || legacyMetric) {
        console.log('');
        console.log(`  Domains: ${domainMetric?.value ?? '?'}  |  Migrated: ${migratedMetric?.value ?? '?'}  |  Legacy services: ${legacyMetric?.value ?? '?'}`);
    }

    // Trend
    if (updatedHistory.length >= 2) {
        const prev = updatedHistory[updatedHistory.length - 2];
        const curr = updatedHistory[updatedHistory.length - 1];
        const delta = curr.score - prev.score;
        const deltaStr = delta >= 0 ? `${C.green}+${delta}${C.reset}` : `${C.red}${delta}${C.reset}`;
        console.log(`  Trend: ${prev.score} → ${curr.score}  (${deltaStr} since ${prev.date})`);
    }

    console.log('');
    console.log(`  Reports: ${C.cyan}.tooling/reports/architecture-report.html${C.reset}`);
    console.log(`  Machine-readable: ${C.cyan}.tooling/check-summary.json${C.reset}`);
    console.log(`${C.bold}${LINE}${C.reset}\n`);

    // Exit with non-zero if failing
    process.exit(score >= 90 ? 0 : 1);
}

main().catch((err) => {
    console.error('\n❌  Architecture platform failed:', err);
    process.exit(2);
});

/**
 * metrics.ts
 * ----------
 * Computes the architecture Metric[] array from check results, the domain registry,
 * and direct filesystem inspection. Does NOT calculate; it just reads and counts.
 *
 * report.ts is responsible for rendering. metrics.ts only produces data.
 * All counts come from live inspection — never from hardcoded values.
 */

import * as path from 'node:path';
import * as fs from 'node:fs';
import { CheckResult, DomainInfo, HistoryEntry, Metric, Registry, Severity } from './types';
import { walkTypeScriptFiles, ensureDir, writeFile, readFile } from './lib/filesystem';
import { REPO_ROOT, DOMAINS_PATH, TOOLING_DIR } from './lib/constants';

// ---------------------------------------------------------------------------
// Filesystem counters
// ---------------------------------------------------------------------------

/** Count TypeScript files in the legacy flat services directory. */
function countLegacyServices(): number {
    const legacyDir = path.join(REPO_ROOT, 'core', 'src', 'services');
    if (!fs.existsSync(legacyDir)) return 0;
    return walkTypeScriptFiles(legacyDir)
        .filter((f) => !/\.(spec|test)\.tsx?$/.test(f.absolutePath))
        .length;
}

/** Count TypeScript files containing bridge/compat patterns. */
function countLegacyBridges(domains: DomainInfo[]): number {
    let count = 0;
    for (const domain of domains) {
        const files = walkTypeScriptFiles(domain.path);
        for (const file of files) {
            try {
                const content = fs.readFileSync(file.absolutePath, 'utf-8');
                // Look for explicit legacy bridge markers used in the codebase
                if (content.includes('@legacy-bridge') || content.includes('LegacyBridge')) {
                    count++;
                }
            } catch {
                // Skip unreadable files
            }
        }
    }
    return count;
}

// ---------------------------------------------------------------------------
// Trend computation
// ---------------------------------------------------------------------------

function computeTrend(
    currentValue: number,
    history: HistoryEntry[],
    field: keyof HistoryEntry
): Metric['trend'] {
    if (history.length < 2) return 'stable';
    const previous = Number(history[history.length - 2][field]);
    if (isNaN(previous)) return 'stable';
    if (currentValue > previous) return 'up';
    if (currentValue < previous) return 'down';
    return 'stable';
}

// ---------------------------------------------------------------------------
// Violation counters from check results
// ---------------------------------------------------------------------------

function countViolationsOfType(
    checkResults: CheckResult[],
    checkIds: string[]
): number {
    return checkResults
        .filter((r) => checkIds.includes(r.checkId))
        .reduce((acc, r) => acc + r.violations.length, 0);
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export function collectMetrics(
    checkResults: CheckResult[],
    registry: Registry,
    domains: DomainInfo[],
    history: HistoryEntry[]
): Metric[] {
    const domainIds = Object.keys(registry);
    const totalDomains = domainIds.length;
    const migratedDomains = domains.filter((d) => d.hasManifest).length;
    const legacyServices = countLegacyServices();
    const legacyBridges = countLegacyBridges(domains);

    const totalPorts = domainIds.reduce((acc, id) => acc + registry[id].ports, 0);
    const totalAdapters = domainIds.reduce((acc, id) => acc + registry[id].adapters, 0);
    const avgPorts = totalDomains > 0 ? +(totalPorts / totalDomains).toFixed(1) : 0;
    const avgAdapters = totalDomains > 0 ? +(totalAdapters / totalDomains).toFixed(1) : 0;

    const boundaryViolations = countViolationsOfType(checkResults, ['boundary_violation']);
    const circularDeps = countViolationsOfType(checkResults, ['circular_dependency']);
    const deepImports = countViolationsOfType(checkResults, ['deep_import_violation']);
    const missingManifests = checkResults
        .find((r) => r.checkId === 'missing_manifest')
        ?.violations.length ?? 0;

    function sev(value: number, thresholds: [number, Severity][]): Severity {
        for (const [threshold, severity] of thresholds) {
            if (value >= threshold) return severity;
        }
        return 'low';
    }

    const metrics: Metric[] = [
        {
            id: 'total_domains',
            name: 'Total Domains',
            value: totalDomains,
            severity: 'info' as unknown as Severity,
            trend: computeTrend(totalDomains, history, 'domains'),
        },
        {
            id: 'migrated_domains',
            name: 'Migrated Domains',
            value: `${migratedDomains} / ${totalDomains}`,
            severity: migratedDomains === totalDomains ? 'low' : 'medium',
        },
        {
            id: 'legacy_services',
            name: 'Legacy Services Remaining',
            value: legacyServices,
            severity: sev(legacyServices, [[50, 'high'], [20, 'medium'], [1, 'low']]),
        },
        {
            id: 'legacy_bridges',
            name: 'Legacy Compatibility Bridges',
            value: legacyBridges,
            severity: legacyBridges > 0 ? 'medium' : 'low',
        },
        {
            id: 'boundary_violations',
            name: 'Dependency Boundary Violations',
            value: boundaryViolations,
            severity: sev(boundaryViolations, [[1, 'critical']]),
            trend: computeTrend(boundaryViolations, history, 'violations'),
        },
        {
            id: 'circular_deps',
            name: 'Circular Dependencies',
            value: circularDeps,
            severity: circularDeps > 0 ? 'critical' : 'low',
        },
        {
            id: 'deep_imports',
            name: 'Deep Import Violations',
            value: deepImports,
            severity: sev(deepImports, [[5, 'high'], [1, 'medium']]),
        },
        {
            id: 'missing_manifests',
            name: 'Missing Manifests',
            value: missingManifests,
            severity: missingManifests > 0 ? 'high' : 'low',
        },
        {
            id: 'avg_ports_per_domain',
            name: 'Avg Ports per Domain',
            value: avgPorts,
            severity: avgPorts === 0 ? 'medium' : 'low',
        },
        {
            id: 'avg_adapters_per_domain',
            name: 'Avg Adapters per Domain',
            value: avgAdapters,
            severity: avgAdapters === 0 ? 'medium' : 'low',
        },
    ];

    return metrics;
}

// ---------------------------------------------------------------------------
// History management
// ---------------------------------------------------------------------------

export function loadHistory(): HistoryEntry[] {
    const histPath = path.join(TOOLING_DIR, 'history.json');
    const raw = readFile(histPath);
    if (!raw) return [];
    try {
        return JSON.parse(raw) as HistoryEntry[];
    } catch {
        return [];
    }
}

export function appendHistory(
    score: number,
    totalViolations: number,
    domains: number,
    commit: string
): HistoryEntry[] {
    const history = loadHistory();
    const today = new Date().toISOString().split('T')[0];

    // Replace today's entry if it already exists (idempotent re-runs)
    const filtered = history.filter((h) => h.date !== today);
    const entry: HistoryEntry = { date: today, commit, score, violations: totalViolations, domains };
    const updated = [...filtered, entry].slice(-90); // keep 90 days

    ensureDir(TOOLING_DIR);
    writeFile(path.join(TOOLING_DIR, 'history.json'), JSON.stringify(updated, null, 2));
    return updated;
}

/**
 * registry.ts
 * -----------
 * Scans all domain manifests and the adapters directory to produce a rich
 * per-domain registry.
 *
 * Writes output to .tooling/registry.json (git-ignored).
 * Exports buildRegistry() for consumption by the metrics and report pipelines.
 */

import * as path from 'node:path';
import * as fs from 'node:fs';
import { loadDomainManifest } from './lib/manifest';
import { walkTypeScriptFiles, ensureDir, writeFile } from './lib/filesystem';
import { DOMAINS_PATH, ADAPTERS_PATH, TOOLING_DIR } from './lib/constants';
import { Registry, RegistryEntry, DomainInfo } from './types';
import { discoverDomains } from './verify-architecture';

// ---------------------------------------------------------------------------
// Counting helpers
// ---------------------------------------------------------------------------

function countTsFiles(dir: string): number {
    if (!fs.existsSync(dir)) return 0;
    return walkTypeScriptFiles(dir)
        .filter((f) => !/\.(spec|test)\.tsx?$/.test(f.absolutePath))
        .length;
}

function countPortFiles(domainPath: string): number {
    return countTsFiles(path.join(domainPath, 'ports'));
}

function countAdapterFiles(domainId: string, adaptersPath: string): number {
    const adapterDir = path.join(adaptersPath, 'outbound', 'database', domainId);
    return countTsFiles(adapterDir);
}

function countSubDir(domainPath: string, layer: string, subDir: string): number {
    return countTsFiles(path.join(domainPath, layer, subDir));
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export function buildRegistry(domains: DomainInfo[], adaptersPath: string): Registry {
    const registry: Registry = {};

    // First pass: load all manifests
    const manifests = new Map(
        domains.map((d) => [d.id, loadDomainManifest(d.path)])
    );

    // Build dependents map
    const dependentsMap = new Map<string, string[]>(domains.map((d) => [d.id, []]));
    for (const [domainId, result] of manifests) {
        if (!result.ok) continue;
        for (const dep of result.manifest.depends_on) {
            if (dependentsMap.has(dep)) {
                dependentsMap.get(dep)!.push(domainId);
            }
        }
    }

    // Second pass: build entries
    for (const domain of domains) {
        const manifestResult = manifests.get(domain.id);

        const entry: RegistryEntry = {
            owner: 'unknown',
            stability: 'experimental',
            maturity: 'experimental',
            reference: false,
            dependencies: [],
            dependents: dependentsMap.get(domain.id) ?? [],
            ports: countPortFiles(domain.path),
            adapters: countAdapterFiles(domain.id, adaptersPath),
            entities: countSubDir(domain.path, 'domain', 'entities'),
            services: countSubDir(domain.path, 'domain', 'services'),
            policies: countSubDir(domain.path, 'domain', 'policies'),
            events: countSubDir(domain.path, 'domain', 'events'),
        };

        if (manifestResult?.ok) {
            const m = manifestResult.manifest;
            entry.owner = m.owner;
            entry.stability = m.stability;
            entry.maturity = m.maturity;
            entry.reference = m.reference ?? false;
            entry.dependencies = m.depends_on;
        }

        registry[domain.id] = entry;
    }

    return registry;
}

// ---------------------------------------------------------------------------
// CLI entry point
// ---------------------------------------------------------------------------

export async function generateRegistry(): Promise<Registry> {
    const domains = discoverDomains(DOMAINS_PATH);
    const registry = buildRegistry(domains, ADAPTERS_PATH);

    ensureDir(TOOLING_DIR);
    writeFile(
        path.join(TOOLING_DIR, 'registry.json'),
        JSON.stringify(registry, null, 2)
    );

    return registry;
}

if (require.main === module) {
    generateRegistry()
        .then((reg) => {
            const count = Object.keys(reg).length;
            console.log(`Registry generated: ${count} domain(s) → .tooling/registry.json`);
        })
        .catch((err) => {
            console.error('Registry generation failed:', err);
            process.exit(1);
        });
}

/**
 * report.ts
 * ---------
 * Pure renderer: receives pre-computed data and writes files to .tooling/reports/.
 * Does NOT calculate or verify anything. Pure I/O.
 *
 * Outputs:
 *   .tooling/reports/architecture-report.json
 *   .tooling/reports/architecture-report.html
 */

import * as path from 'node:path';
import { execSync } from 'node:child_process';
import { ArchitectureReport, HistoryEntry } from './types';
import { ensureDir, writeFile } from './lib/filesystem';
import { renderHtmlReport } from './lib/reporter';
import { TOOLING_DIR, REPO_ROOT } from './lib/constants';

const REPORTS_DIR = path.join(TOOLING_DIR, 'reports');
const TOOL_VERSION = '1.0.0';
const ARCH_VERSION = '1';

function getCommit(): string {
    try {
        return execSync('git rev-parse --short HEAD', {
            cwd: REPO_ROOT,
            encoding: 'utf-8',
        }).trim();
    } catch {
        return 'unknown';
    }
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export function buildReport(
    checkResults: ArchitectureReport['checkResults'],
    metrics: ArchitectureReport['metrics'],
    registry: ArchitectureReport['registry'],
    score: number,
    summary: ArchitectureReport['summary']
): ArchitectureReport {
    return {
        architectureVersion: ARCH_VERSION,
        toolVersion: TOOL_VERSION,
        repositoryCommit: getCommit(),
        generatedAt: new Date().toISOString(),
        score,
        passed: score >= 90,
        checkResults,
        metrics,
        registry,
        summary,
    };
}

export function writeReports(report: ArchitectureReport, history: HistoryEntry[]): void {
    ensureDir(REPORTS_DIR);

    // JSON report
    writeFile(
        path.join(REPORTS_DIR, 'architecture-report.json'),
        JSON.stringify(report, null, 2)
    );

    // HTML dashboard
    writeFile(
        path.join(REPORTS_DIR, 'architecture-report.html'),
        renderHtmlReport(report, history)
    );
}

// ---------------------------------------------------------------------------
// CLI entry point (for debugging)
// ---------------------------------------------------------------------------

if (require.main === module) {
    console.log('report.ts: run `npm run architecture` to generate the full report.');
}

#!/usr/bin/env node
/**
 * verify-architecture.ts
 * ----------------------
 * Architecture verification orchestrator.
 *
 * Dynamically loads all check plugins from tooling/architecture/checks/,
 * runs them in parallel, computes a 100-point score using weights from
 * architecture-rules.yaml, and prints a colour-coded scorecard to stdout.
 *
 * Also writes a machine-readable exit summary to .tooling/check-summary.json
 * for CI/CD consumption.
 *
 * Usage (direct):
 *   npm run verify:architecture
 *   npm run verify:architecture -- --changed
 *
 * Or from the orchestrator (index.ts):
 *   import { runVerification } from './verify-architecture'
 */

import * as path from 'node:path';
import * as fs from 'node:fs';
import yaml from 'js-yaml';
import {
    ArchitectureCheck,
    ArchitectureRules,
    CheckContext,
    CheckResult,
    DomainInfo,
    ScoreSummary,
    Severity,
} from './types';
import { findDomains, getDomainManifestPath, pathExists, ensureDir, writeFile } from './lib/filesystem';
import { REPO_ROOT, DOMAINS_PATH, ADAPTERS_PATH, TOOLING_DIR, RULES_PATH, CHECKS_DIR } from './lib/constants';
import { execSync } from 'node:child_process';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

export function loadRules(): ArchitectureRules {
    const raw = fs.readFileSync(RULES_PATH, 'utf-8');
    return yaml.load(raw) as ArchitectureRules;
}

export function discoverDomains(domainsPath: string): DomainInfo[] {
    return findDomains(domainsPath).map((p) => ({
        id: path.basename(p),
        path: p,
        hasManifest: pathExists(getDomainManifestPath(p)),
    }));
}

function getChangedFiles(repoRoot: string): string[] {
    try {
        const out = execSync('git diff --name-only HEAD', {
            cwd: repoRoot,
            encoding: 'utf-8',
        });
        return out.trim().split('\n').filter(Boolean);
    } catch {
        return [];
    }
}

function getSeverityForCheck(checkId: string, rules: ArchitectureRules): Severity {
    for (const [tier, ids] of Object.entries(rules.severity)) {
        if ((ids as string[]).includes(checkId)) return tier as Severity;
    }
    return 'medium';
}

export function computeScore(results: CheckResult[], rules: ArchitectureRules): number {
    let score = 100;
    for (const result of results) {
        if (result.passed) continue;
        const tier = getSeverityForCheck(result.checkId, rules);
        const weight = rules.score_weights?.[tier] ?? 5;
        score -= result.violations.length * weight;
    }
    return Math.max(0, score);
}

export function buildSummary(results: CheckResult[], rules: ArchitectureRules): ScoreSummary {
    const counts: ScoreSummary = { critical: 0, high: 0, medium: 0, low: 0, totalViolations: 0 };
    for (const result of results) {
        for (const v of result.violations) {
            counts[v.severity]++;
            counts.totalViolations++;
        }
    }
    // Also count by check severity tier (in case violations don't carry their own severity)
    for (const result of results) {
        if (result.passed) continue;
        const tier = getSeverityForCheck(result.checkId, rules);
        // violations already counted above
        void tier;
    }
    return counts;
}

// ---------------------------------------------------------------------------
// Dynamic check loader
// ---------------------------------------------------------------------------

async function loadChecks(): Promise<ArchitectureCheck[]> {
    if (!fs.existsSync(CHECKS_DIR)) return [];

    const files = fs
        .readdirSync(CHECKS_DIR)
        .filter((f) => f.endsWith('.ts') && !f.startsWith('_'));

    const checks: ArchitectureCheck[] = [];
    for (const file of files) {
        const absPath = path.join(CHECKS_DIR, file);
        // Use pathToFileURL so Windows absolute paths (C:\...) become valid file:// URLs
        const { pathToFileURL } = require('node:url');
        const mod = await import(pathToFileURL(absPath).href);
        const check: ArchitectureCheck = mod.default;
        if (check && typeof check.run === 'function') {
            checks.push(check);
        }
    }
    return checks;
}

// ---------------------------------------------------------------------------
// Console scorecard renderer
// ---------------------------------------------------------------------------

const C = {
    reset: '\x1b[0m',
    bold: '\x1b[1m',
    red: '\x1b[31m',
    green: '\x1b[32m',
    yellow: '\x1b[33m',
    cyan: '\x1b[36m',
    gray: '\x1b[90m',
    white: '\x1b[97m',
};

function scoreColor(score: number): string {
    if (score >= 90) return C.green;
    if (score >= 70) return C.yellow;
    return C.red;
}

function printScorecard(results: CheckResult[], score: number, rules: ArchitectureRules): void {
    const summary = buildSummary(results, rules);
    const passed = score >= 90;
    const LINE = '─'.repeat(60);

    console.log(`\n${C.bold}${LINE}${C.reset}`);
    console.log(`${C.bold}  Esparex Architecture Platform${C.reset}`);
    console.log(`${LINE}`);

    const scoreStr = `${scoreColor(score)}${C.bold}${score} / 100${C.reset}`;
    const passStr = passed
        ? `${C.green}${C.bold}  PASS${C.reset}`
        : `${C.red}${C.bold}  FAIL${C.reset}`;
    console.log(`\n  Architecture Score: ${scoreStr}${passStr}\n`);

    // Severity summary
    const sevLines = [
        ['critical', '❌', summary.critical, C.red],
        ['high', '⚠ ', summary.high, C.yellow],
        ['medium', 'ℹ ', summary.medium, C.cyan],
        ['low', '· ', summary.low, C.gray],
    ] as const;
    for (const [, icon, count, color] of sevLines) {
        console.log(`  ${color}${icon}  ${count}${C.reset}`);
    }

    // Per-check results
    console.log('');
    for (const result of results) {
        const icon = result.passed ? `${C.green}✓${C.reset}` : `${C.red}✗${C.reset}`;
        const detail = result.passed ? '' : `  ${C.gray}(${result.violations.length} violation${result.violations.length !== 1 ? 's' : ''})${C.reset}`;
        console.log(`  ${icon}  ${result.name}${detail}`);
        if (!result.passed) {
            const maxShown = 3;
            for (const v of result.violations.slice(0, maxShown)) {
                const loc = v.file ? ` ${C.gray}${v.file}${v.line ? ':' + v.line : ''}${C.reset}` : '';
                console.log(`       ${C.gray}→${C.reset}${loc} ${v.message}`);
            }
            if (result.violations.length > maxShown) {
                console.log(`       ${C.gray}  … and ${result.violations.length - maxShown} more${C.reset}`);
            }
        }
    }

    // Top fixes
    const allViolations = results.flatMap((r) => r.violations);
    const topIssues = allViolations
        .sort((a, b) => {
            const order: Record<Severity, number> = { critical: 0, high: 1, medium: 2, low: 3 };
            return order[a.severity] - order[b.severity];
        })
        .slice(0, 5);

    if (topIssues.length > 0) {
        console.log(`\n  ${C.bold}Top Issues:${C.reset}`);
        topIssues.forEach((v, i) => {
            const num = ['①', '②', '③', '④', '⑤'][i];
            console.log(`  ${num}  ${v.message}`);
        });
    }

    console.log(`\n${LINE}${C.reset}\n`);
}

// ---------------------------------------------------------------------------
// Exit code summary (machine-readable for CI)
// ---------------------------------------------------------------------------

function writeExitSummary(score: number, summary: ScoreSummary): void {
    ensureDir(TOOLING_DIR);
    const out = {
        passed: score >= 90,
        score,
        critical: summary.critical,
        high: summary.high,
        medium: summary.medium,
        low: summary.low,
    };
    writeFile(path.join(TOOLING_DIR, 'check-summary.json'), JSON.stringify(out, null, 2));
}

// ---------------------------------------------------------------------------
// Public API (used by index.ts orchestrator)
// ---------------------------------------------------------------------------

export interface VerificationResult {
    checkResults: CheckResult[];
    score: number;
    summary: ScoreSummary;
    rules: ArchitectureRules;
    domains: DomainInfo[];
    context: CheckContext;
}

export async function runVerification(opts: {
    changed?: boolean;
    silent?: boolean;
} = {}): Promise<VerificationResult> {
    const rules = loadRules();
    const domains = discoverDomains(DOMAINS_PATH);
    const changed = opts.changed ? getChangedFiles(REPO_ROOT) : undefined;

    const context: CheckContext = {
        repoRoot: REPO_ROOT,
        domainsPath: DOMAINS_PATH,
        adaptersPath: ADAPTERS_PATH,
        rules,
        domains,
        changed,
    };

    const checks = await loadChecks();
    const checkResults = await Promise.all(checks.map((c) => c.run(context)));

    const score = computeScore(checkResults, rules);
    const summary = buildSummary(checkResults, rules);

    writeExitSummary(score, summary);

    if (!opts.silent) {
        printScorecard(checkResults, score, rules);
    }

    return { checkResults, score, summary, rules, domains, context };
}

// ---------------------------------------------------------------------------
// Entry point (when run directly)
// ---------------------------------------------------------------------------

if (require.main === module) {
    const args = process.argv.slice(2);
    const isChanged = args.includes('--changed');

    runVerification({ changed: isChanged })
        .then(({ score }) => {
            process.exit(score >= 90 ? 0 : 1);
        })
        .catch((err) => {
            console.error('Architecture verification failed:', err);
            process.exit(2);
        });
}
